-- Poems batch 221
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('684320d9-54ad-4467-8f58-7fe00d959ec6','見趙章泉','姚鏞','宋','宋诗','song-poetry','','[]','秉芳獨向章泉老，四海兒童以字傳。',64,'全唐诗/poet.song.204000.json','["秉芳獨向章泉老，四海兒童以字傳。", "特詔難更高士服，好詩多入賈人船。", "行窩冷落熙寧後，放鶴風流景祐前。", "一代典刑能幾見，願從几杖閲耆年。"]'),
('88bbe33c-28f8-41ed-ba99-4eb6285c9cf8','見袁蒙齋','姚鏞','宋','宋诗','song-poetry','','[]','書說曾傳到剡中，不圖今見古人風。',64,'全唐诗/poet.song.204000.json','["書說曾傳到剡中，不圖今見古人風。", "間生伊洛二三子，安得龔黄十數公。", "仁性未嘗離日用，道心元自與人同。", "絜齋衣鉢慈湖學，願發精微一啟蒙。"]'),
('6d9a0eb7-1777-4d5f-b8b1-15ec98493845','懷雲泉頤山老','姚鏞','宋','宋诗','song-poetry','','[]','枯吟世慮輕，求道不求名。',48,'全唐诗/poet.song.204000.json','["枯吟世慮輕，求道不求名。", "病起春風過，閑居野草生。", "游山尋舊屐，煮藥試新鐺。", "別久空相憶，疏鍾隔水鳴。"]'),
('50d772fb-7040-44e5-b481-46a8c3132ad4','寄徑山敬溪翁','姚鏞','宋','宋诗','song-poetry','','[]','心遠人間世，燈傳國一禪。',48,'全唐诗/poet.song.204000.json','["心遠人間世，燈傳國一禪。", "靜中無劇暑，詩外總閑年。", "掛錫雲生樹，烹茶月落泉。", "幾時歸去得，再約剡溪船。"]'),
('c6785b03-f54d-411d-b855-0c6850849432','拜先君墓','姚鏞','宋','宋诗','song-poetry','','[]','次第瞻山看水流，夜臺中閟憶三秋。',64,'全唐诗/poet.song.204000.json','["次第瞻山看水流，夜臺中閟憶三秋。", "新松成行如人長，老鶴無言似我愁。", "僧奉晨昏惟茗供，兒悲霜露只蘋羞。", "結廬終歲關心事，怊悵鍾聲出暝樓。"]'),
('a8a23281-01aa-4bb1-8b7b-a4bf9bf8e835','送曄沖晦歸天竺','姚鏞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖山下多奇石，師去今遊乳竇峰。',32,'全唐诗/poet.song.204000.json','["西湖山下多奇石，師去今遊乳竇峰。", "遥想石臺登講罷，野猿歸洞鶴歸松。"]'),
('de538253-fbd2-48b5-8e1a-b17ad1bc979f','寓霅川','姚鏞','宋','宋诗','song-poetry','','[]','王戴溪頭小隠仙，漁翁引上霅溪船。',32,'全唐诗/poet.song.204000.json','["王戴溪頭小隠仙，漁翁引上霅溪船。", "幾回倦釣思歸去，又爲蘋花住一年。"]'),
('342d37ec-182a-45e2-9cba-3bbc8847a254','春夜曲','姚鏞','宋','宋诗','song-poetry','','[]','金魚鎖合蘭缸小，酒不支愁尋睡早。',64,'全唐诗/poet.song.204000.json','["金魚鎖合蘭缸小，酒不支愁尋睡早。", "梨花欲墮風更寒，燕子不歸春自老。", "流蘇護帳香雲結，三十六簧清吹咽。", "緘書欲寄湘水深，城烏啼落花西川。"]'),
('748a86c6-d552-409e-9ebd-e5e67c2d34cd','夜發漁浦','姚鏞','宋','宋诗','song-poetry','','[]','爲親從薄宦，不復計脩程。',48,'全唐诗/poet.song.204000.json','["爲親從薄宦，不復計脩程。", "斷浦迎潮別，孤帆带月行。", "秋來江柳變，夜久水煙生。", "前路猶淹泊，凄其賦遠征。"]'),
('b31397ac-549e-43a8-9582-7c3b372c2f9a','桐廬道中','姚鏞','宋','宋诗','song-poetry','','[]','兩岸山如簇，中流鎖翠微。',48,'全唐诗/poet.song.204000.json','["兩岸山如簇，中流鎖翠微。", "風帆逆水上，江鶴背人飛。", "野廟青楓樹，人家白板扉。", "嚴陵臺下過，不敢浣塵衣。"]'),
('5f5183f4-c124-4ac8-b54b-cd5884287a77','頭陀菴','姚鏞','宋','宋诗','song-poetry','','[]','衣緇髮可梳，雲外卓菴居。',48,'全唐诗/poet.song.204000.json','["衣緇髮可梳，雲外卓菴居。", "佛換新花供，幡拈古偈書。", "刪松容徑竹，種茗間園蔬。", "爲應諸方供，山房盡日虛。"]'),
('fef2b21b-0c01-4d5e-b519-e82cdf6f32b0','出山','姚鏞','宋','宋诗','song-poetry','','[]','雲陰漠漠雨瀟瀟，坐兀歸輿野興遥。',64,'全唐诗/poet.song.204000.json','["雲陰漠漠雨瀟瀟，坐兀歸輿野興遥。", "石磵水流苔路滑，竹籬秋去菊花焦。", "誰將束縕求山火，自立寒谿問板橋。", "官事奔奔何日了，倚松臨水羨漁樵。"]'),
('3a28ce59-29d8-4edc-b98f-0ffb9f5cb57b','題畫壁','姚鏞','宋','宋诗','song-poetry','','[]','兩山灌木带晴鴉，泯泯春流漾浦沙。',32,'全唐诗/poet.song.204000.json','["兩山灌木带晴鴉，泯泯春流漾浦沙。", "隔岸小舟呼不應，碧桃花外是誰家。"]'),
('f40ca568-f3d4-474c-b8aa-bb3031521347','寄范中洲','姚鏞','宋','宋诗','song-poetry','','[]','高隠就詩名，中洲雅趣成。',48,'全唐诗/poet.song.204000.json','["高隠就詩名，中洲雅趣成。", "几前脩竹浄，屋上落泉鳴。", "柘圃春風織，山田野火耕。", "滿山薇蕨老，客至足蔬萌。"]'),
('5aa47a8b-d3a7-4299-a0f1-2a46f8c20564','野廟','姚鏞','宋','宋诗','song-poetry','','[]','未知何王廟，歲月日已非。',48,'全唐诗/poet.song.204000.json','["未知何王廟，歲月日已非。", "熏爐松柏煤，畫壁苔蘚衣。", "門空牧豎戯，樹老山魈依。", "田家社酒香，紙窖生光輝。"]'),
('28a9660b-22a3-48c1-8fb1-f515f7e4b991','懷范正夫','姚鏞','宋','宋诗','song-poetry','','[]','愁霖滴禾黍，秋暮滯雲莊。',48,'全唐诗/poet.song.204000.json','["愁霖滴禾黍，秋暮滯雲莊。", "但慮輸井稅，不憂無積倉。", "竹雞啼野塹，饑鼠走山房。", "不飲論文酒，思君覺夜長。"]'),
('65814ad7-97ee-444c-b272-e0f87c0f8d53','宿護國寺觀晦翁先生題名  其一','姚鏞','宋','宋诗','song-poetry','','[]','滿樹椶花滿逕松，解鞍纔是暝樓鍾。',32,'全唐诗/poet.song.204000.json','["滿樹椶花滿逕松，解鞍纔是暝樓鍾。", "上方月白山雲靜，看見東南一兩峰。"]'),
('ce29bbfe-f3eb-4c17-be3e-f2a5b9030aad','宿護國寺觀晦翁先生題名  其二','姚鏞','宋','宋诗','song-poetry','','[]','看了題名看跋文，自憐不及晦翁門。',32,'全唐诗/poet.song.204000.json','["看了題名看跋文，自憐不及晦翁門。", "野僧惜打殘碑賣，時共山猿洗墨痕。"]'),
('d62e1d31-9b68-4b42-b9eb-edeccd8ab516','寄沖晦','姚鏞','宋','宋诗','song-poetry','','[]','欲答前春信，西飛雁不逢。',48,'全唐诗/poet.song.204000.json','["欲答前春信，西飛雁不逢。", "應隨丹竈鶴，同看白雲松。", "花雨繙經石，山鳴出定鐘。", "何時尋舊住，却說武夷峰。"]'),
('bb8b0612-8b1e-4480-a02d-2adb52d42ff8','訪中洲','姚鏞','宋','宋诗','song-poetry','','[]','踏雨來敲柳下門，荷香清透紫綃裙。',32,'全唐诗/poet.song.204000.json','["踏雨來敲柳下門，荷香清透紫綃裙。", "相逢未暇論奇字，先向水邊看白雲。"]'),
('ba33801f-4101-424a-81fe-db088c1c1517','賃宅','姚鏞','宋','宋诗','song-poetry','','[]','及春遊帝里，賃宅似吾家。',48,'全唐诗/poet.song.204000.json','["及春遊帝里，賃宅似吾家。", "雨霤生新草，風牀受落花。", "病多添老懶，慮澹遠紛華。", "時與幽人遇，燒香煮茗芽。"]'),
('567af4e3-6687-4abd-b310-1834a4649447','悼復石壁','姚鏞','宋','宋诗','song-poetry','','[]','一死雖如蛻，殺身真可哀。',48,'全唐诗/poet.song.204000.json','["一死雖如蛻，殺身真可哀。", "僧危能仗義，詩好更多才。", "鶴怨蘭亭月，雲消石壁苔。", "舊時同社友，寂寞載書來。"]'),
('eb9df35d-e500-4e63-a38c-5f0e9c39d59e','送僧','姚鏞','宋','宋诗','song-poetry','','[]','去結茅堂霅水邊，曉行持鉢落花天。',32,'全唐诗/poet.song.204000.json','["去結茅堂霅水邊，曉行持鉢落花天。", "得錢未用栽松本，先買溪南舊石田。"]'),
('f0224df4-1d08-4f72-85bd-5113ae9ea09e','王別駕訪天竺頤曄二師','姚鏞','宋','宋诗','song-poetry','','[]','寶香熏徹碧蓮臺，別駕尋僧日暮回。',64,'全唐诗/poet.song.204000.json','["寶香熏徹碧蓮臺，別駕尋僧日暮回。", "聽雨齋前驚樹長，浴雲池上看花開。", "青山久不逢坡老，玄鶴親曾識辨才。", "二老風流如昨日，百年詩石未蒼苔。"]'),
('13c530d4-47a9-4c5a-ab70-5fb2e95f771c','廬陵贈異孤峰','姚鏞','宋','宋诗','song-poetry','','[]','幾度雲間望鶴飛，相逢猶喜及秋期。',32,'全唐诗/poet.song.204000.json','["幾度雲間望鶴飛，相逢猶喜及秋期。", "明朝採藥青原洞，好掬寒泉供祖師。"]'),
('f68c6b93-e516-48d5-a26f-d0d0a6d8b86d','寄劉敏叔','姚鏞','宋','宋诗','song-poetry','','[]','一生貧樂鬢成絲，前輩風流及見之。',64,'全唐诗/poet.song.204000.json','["一生貧樂鬢成絲，前輩風流及見之。", "道外無營偏愛畫，靜中有趣只吟詩。", "雲生茅屋湖山近，秋滿荒園橘柚垂。", "見說地幽人罕到，自同妻子種江蘺。"]'),
('16155521-b404-4858-9c0c-ab2373e2a0e1','自青原回訪敏叔幾不相遇','姚鏞','宋','宋诗','song-poetry','','[]','曉汲三泉洗硯回，要看奇石立蒼苔。',64,'全唐诗/poet.song.204000.json','["曉汲三泉洗硯回，要看奇石立蒼苔。", "騎馿應爲尋詩出，放鶴還知有客來。", "一井清寒宜茗飲，千林黄落獨梅開。", "他時老圃如能學，只乞山中橘本栽。"]'),
('f856c859-d18d-4b39-8df5-1bcb46e15c82','寄趙東野時以帥檄撫定贛叛  其一','姚鏞','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','東野山人有晉風，歸來三徑自栽松。',64,'全唐诗/poet.song.204000.json','["東野山人有晉風，歸來三徑自栽松。", "錦囊句好閑中趣，鉛鼎丹成靜處功。", "無事杖藜隨野鶴，有時隠几看晴峰。", "長江近日風波惡，莫向深淵下釣筒。"]'),
('f7df1f71-57d5-4d40-b88c-ecde7a95a823','寄趙東野時以帥檄撫定贛叛  其二','姚鏞','宋','宋诗','song-poetry','','[]','清晨閑上鬰孤臺，鼓咽譙樓角更哀。',64,'全唐诗/poet.song.204000.json','["清晨閑上鬰孤臺，鼓咽譙樓角更哀。", "病葉滿山難獨掃，狂花一樹爲誰開。", "泉枯石井獅空吼，雨暗荒池鳳不來。", "欲向江東問仙老，海風吹浪駕舟回。"]'),
('39e9d276-ba09-4384-ad88-58ba71267f6f','送贛士謁前贛侯楊東山','姚鏞','宋','宋诗','song-poetry','','[]','凝香句滿空同石，靜向東山卧白雲。',64,'全唐诗/poet.song.204000.json','["凝香句滿空同石，靜向東山卧白雲。", "夫子自能明易學，衆人誰解識玄文。", "空江短棹浮詩卷，別岸飛花撲練裙。", "到得带園春已過，煮茶應共竹間分。"]'),
('ade7f19b-47cd-438d-b9aa-891234134b20','題東山贈何青霞詩後','姚鏞','宋','宋诗','song-poetry','','[]','青霞道士來相見，手閲東山詩一卷。',64,'全唐诗/poet.song.204000.json','["青霞道士來相見，手閲東山詩一卷。", "句裏明知山水心，筆端照見煙霞面。", "昨宵夢上寥陽殿，仙官敕作青霞傳。", "傳成不及卷中詩，罰讀靈歌三百遍。"]'),
('7c5128a0-a42e-4ab4-a141-6b1af78a0737','午興','姚鏞','宋','宋诗','song-poetry','','[]','心閑日日理黄庭，四體和柔勝藥靈。',32,'全唐诗/poet.song.204000.json','["心閑日日理黄庭，四體和柔勝藥靈。", "獨步小軒無一事，老槐陰裏鶴梳翎。"]'),
('81fe88b1-d685-4ef3-94fd-7268c8537557','秋風','姚鏞','宋','宋诗','song-poetry','','[]','顥氣薄衣襟，疎聲集暝林。',48,'全唐诗/poet.song.204000.json','["顥氣薄衣襟，疎聲集暝林。", "雁驚烟塞夢，鱸入故鄉心。", "靜落階前葉，清傳月下砧。", "更憐茅屋破，愁絕少陵吟。"]'),
('5c6f723f-6114-4882-b1c0-5ce1742f1e32','北高峰','姚鏞','宋','宋诗','song-poetry','','[]','閒處春光淡，逢僧共採蒿。',48,'全唐诗/poet.song.204000.json','["閒處春光淡，逢僧共採蒿。", "曲盤山磴險，直上塔峰高。", "風露侵衣冷，江湖送眼豪。", "近年無隠者，空負數株桃。"]'),
('210b8408-b795-4289-bd5c-b85c77a70f84','送僧孤峰','姚鏞','宋','宋诗','song-poetry','','[]','分得西林雲滿巢，瓣香端爲遠公燒。',32,'全唐诗/poet.song.204000.json','["分得西林雲滿巢，瓣香端爲遠公燒。", "阿兄不解陶潛飲，只倚山中水一瓢。"]'),
('e14da6e3-466b-4f18-9ebe-b656ac06e3d7','贈孤峰','姚鏞','宋','宋诗','song-poetry','','[]','拄杖尋幽古寺中，雲容淡淡雨濛濛。',32,'全唐诗/poet.song.204000.json','["拄杖尋幽古寺中，雲容淡淡雨濛濛。", "歸來一笑春多事，野杏山桃各自紅。"]'),
('55e0fa51-0254-434a-8b6d-ff18ebf6a6d9','憶孤峰','姚鏞','宋','宋诗','song-poetry','','[]','浮杯方渡湘江上，又逐孤雲到嶽前。',32,'全唐诗/poet.song.204000.json','["浮杯方渡湘江上，又逐孤雲到嶽前。", "七十二峰煙雨夜，與誰同話懶殘禪。"]'),
('77365079-29d0-4ce7-be1e-49a51d17c349','題孤峰房','姚鏞','宋','宋诗','song-poetry','','[]','雲木陰森天氣清，杜鵑啼了又啼鶑。',32,'全唐诗/poet.song.204000.json','["雲木陰森天氣清，杜鵑啼了又啼鶑。", "幽人午枕不成夢，憶得故山春樹生。"]'),
('81078878-270e-4c67-b4f7-33362204669e','龜松泉','姚鏞','宋','宋诗','song-poetry','','[]','未讓葛洪丹井靈，石根流水更清泠。',32,'全唐诗/poet.song.204000.json','["未讓葛洪丹井靈，石根流水更清泠。", "多年不見仙桃出，化作老松生茯苓。"]'),
('564cc4a0-6a60-4767-96d0-008248c2eb27','別毛滄洲','姚鏞','宋','宋诗','song-poetry','','[]','風雨三更夢，江湖萬里心。',24,'全唐诗/poet.song.204000.json','["風雨三更夢，江湖萬里心。", "青燈正愁絕，可惜不能琴。"]'),
('4bc0f0e0-e2a3-48d9-b461-fe81cad4f7ca','放船','姚鏞','宋','宋诗','song-poetry','','[]','數幅蒲帆破曉煙，一篙春水漲平川。',32,'全唐诗/poet.song.204000.json','["數幅蒲帆破曉煙，一篙春水漲平川。", "誰家池館多楊柳，時送飛花到客船。"]'),
('1d1532cb-30f7-4aad-913e-2cc890f7f20a','題衡岳','姚鏞','宋','宋诗','song-poetry','','[]','萬山環拱祝融尊，紫蓋前趨若駿奔。',64,'全唐诗/poet.song.204000.json','["萬山環拱祝融尊，紫蓋前趨若駿奔。", "火德中天扶日月，炎方一柱鎮乾坤。", "久無執贄來侯牧，空有穹碑立廟門。", "北望中原青一髮，淒其四岳正塵昏。"]'),
('b52eef9c-8b4c-4fe5-a781-df92ee6e657e','離衡','姚鏞','宋','宋诗','song-poetry','','[]','天恩下釋湘纍客，心事悠悠月滿船。',64,'全唐诗/poet.song.204000.json','["天恩下釋湘纍客，心事悠悠月滿船。", "種藥已收思病日，著書不就負殘年。", "雜花怪石分人去，老竹荒亭入畫傳。", "歸夢鑑湖三百里，白鷗相候亦欣然。"]'),
('bf7ec07a-fd44-41d7-ab0e-d398b7ed0240','法華寺','姚鏞','宋','宋诗','song-poetry','','[]','入門松逕幽，樹杪見鐘樓。',48,'全唐诗/poet.song.204000.json','["入門松逕幽，樹杪見鐘樓。", "客至犬迎吠，香消僧出游。", "水花迎晚照，風葉引凉秋。", "欲作居山計，吾盟在白鷗。"]'),
('d209f5d4-ac6b-40e7-a0ca-1039376c7642','出遊','姚鏞','宋','宋诗','song-poetry','','[]','春來日日風兼雨，今日晴明試杖藜。',32,'全唐诗/poet.song.204000.json','["春來日日風兼雨，今日晴明試杖藜。", "閉戶不知花信過，野桃開了到棠梨。"]'),
('6d1fbfeb-7aa9-42fe-9996-4e289b0dba24','羅憲北林預脩禊事','姚鏞','宋','宋诗','song-poetry','','[]','玉節先期泛禊川，携壺與客上樓船。',64,'全唐诗/poet.song.204000.json','["玉節先期泛禊川，携壺與客上樓船。", "江亭野寺山山好，梅子櫻桃樹樹圓。", "看竹靜行松下道，瀹茶寒汲石根泉。", "清遊盡日惟觴詠，不學蘭亭悅管絃。"]'),
('707164cc-470d-4e2b-8fba-33cf19907ddc','贈相者','姚鏞','宋','宋诗','song-poetry','','[]','眼白骨多屯，還能閲世人。',48,'全唐诗/poet.song.204000.json','["眼白骨多屯，還能閲世人。", "空靈三寸舌，不療一生貧。", "歲晚離騷國，天涯放逐臣。", "相過話人物，京洛尚風塵。"]'),
('9f4bf5a5-a9d3-4ef5-9736-ef2407642d7e','送上超古還徑山','姚鏞','宋','宋诗','song-poetry','','[]','相見忽秋初，言詩足起予。',48,'全唐诗/poet.song.204000.json','["相見忽秋初，言詩足起予。", "身雖披壞衲，手未釋群書。", "雙徑雲多潤，諸山木易疏。", "此心超萬古，禪誦特其餘。"]'),
('7e487d20-8d5b-404e-9b26-a0c3856ffb1f','壽樞使','姚鏞','宋','宋诗','song-poetry','','[]','崧岳重生再及申，望餘兩日正青春。',64,'全唐诗/poet.song.204000.json','["崧岳重生再及申，望餘兩日正青春。", "熊羆五十年前夢，龜鶴三千歲後身。", "故地寂無南牧馬，桂枝新有北歸人。", "黄封賜酒堪爲壽，願頌莊周上古椿。"]'),
('092483e0-d08d-4ad0-b130-f1af0c404ee4','句  其一','姚鏞','宋','宋诗','song-poetry','','[]','癡雲蔽嶽行人遠，淫雨摧花白髮生。',16,'全唐诗/poet.song.204000.json','["癡雲蔽嶽行人遠，淫雨摧花白髮生。"]'),
('3b84d29e-b51c-4bff-966a-d84a1d65056c','句  其二','姚鏞','宋','宋诗','song-poetry','','[]','萬里尋遷客，三年見此人。',12,'全唐诗/poet.song.204000.json','["萬里尋遷客，三年見此人。"]'),
('f343775a-d305-4d48-ae65-8c1bc7ec3a88','積雨嘆','張侃','宋','宋诗','song-poetry','','[]','去年南蘭陵，官河無流澌。',288,'全唐诗/poet.song.204000.json','["去年南蘭陵，官河無流澌。", "陰雲久不見，萬里行炎曦。", "太守爲民禱，百拜躬愈祗。", "忽然動凉飈，驟雨肆奔馳。", "旱苗有生意，下民免寒饑。", "感格在俄頃，嗟人自不爲。", "頌語我欲作，垂世同曹規。", "深恐旁觀者，憑藉立是非。", "反謂地勢隆，水散及四支。", "縱使雨入尺，立待只片時。", "今年芒種後，有雨細如絲。", "農家買五兆，寸波成漣漪。", "我耳曾聽得，把筆紀小詩。", "又傳練湖圯，澒洞南北迷。", "浸淫到旁邑，原隰不分畸。", "秋中月色皎，老晴頗相宜。", "深谷傳地籟，喬松難扶持。", "滂流盡三日，處處同一辭。", "化工有至理，淺眼休蠡窺。", "蝝蝝可憐生，短衣到鳬茈。", "冬寒與夏暑，平日何怨咨。", "一旦示災咎，反己深思惟。", "退寸望求尺，龠合規微貲。", "豐艱非逆料，人情恣生疑。"]'),
('a12303c0-7c56-40e1-80af-5a0672459dd5','秋後一日書所見者','張侃','宋','宋诗','song-poetry','','[]','秋深山轉清，雨定水自綠。',72,'全唐诗/poet.song.204000.json','["秋深山轉清，雨定水自綠。", "庭前牽牛花，粲粲悅人目。", "居官已年餘，竟日書吏牘。", "因閒窺化工，景象不一足。", "促織汝何爲，懶婦絲斷續。", "夜長清未眠，題詩燒短燭。"]'),
('18031822-2f69-48c4-8ac6-3d9460ee24a1','紅塔','張侃','宋','宋诗','song-poetry','','[]','出門看青山，天際晴雲合。',72,'全唐诗/poet.song.204000.json','["出門看青山，天際晴雲合。", "虬松植長塗，亭亭兩紅塔。", "誰知百年後，竟坐市塵雜。", "老僧隨世機，電眸閲伏臘。", "流水洗不盡，就下汙流納。", "北窗稍幽虛，清風滿眠榻。"]'),
('fd601d56-8aeb-4c7d-9cd3-1aae192fa264','觀海','張侃','宋','宋诗','song-poetry','','[]','孔聖道不行，乘桴浮于海。',96,'全唐诗/poet.song.204000.json','["孔聖道不行，乘桴浮于海。", "非子深寓言，誠欲警不逮。", "我生遊江湖，舟汎聽自在。", "有時月初生，滿天雲去靉。", "今朝到海邊，潮遲立可待。", "固知源脈長，下藏魚龍隊。", "想見景晴明，間亦露光彩。", "因爾觀自然，天地能主宰。"]'),
('7fdf8dbe-3cee-467a-9c73-e70376ad2f16','雨','張侃','宋','宋诗','song-poetry','','[]','今日天欲雨，農家名分龍。',96,'全唐诗/poet.song.204000.json','["今日天欲雨，農家名分龍。", "雨意或羞澀，霑潤限西東。", "入夏雨已多，頗覺支體慵。", "輕煙苒苒綠，夕照微微紅。", "不奈勃姑語，呼雨雲滿空。", "乍晴絲捲軸，復闇花無蹤。", "良辰偶孤負，土脈方豐融。", "屈指是新秋，細聽鄰杵舂。"]'),
('b1794658-aeca-4740-b66f-e7159ea79706','冬夜對月','張侃','宋','宋诗','song-poetry','','[]','秋來月漸清，老火猶未退。',96,'全唐诗/poet.song.204000.json','["秋來月漸清，老火猶未退。", "好風送新凉，雲深復昏晦。", "徐思此夜滿，豈不令人愛。", "暑氣薄前榮，蒸溽肯少貸。", "月色到芳池，緣此亦拘礙。", "今宵坐中庭，揮麈成獨對。", "霜華雜月色，頓然清病肺。", "何必泥中秋，此語吾永佩。"]'),
('ce55b25a-d1f3-4c9c-9ca7-266060f4269e','午步積谷山探梅才有一二蘂','張侃','宋','宋诗','song-poetry','','[]','爛雨才放晴，街頭泥三寸。',72,'全唐诗/poet.song.204000.json','["爛雨才放晴，街頭泥三寸。", "支筇積谷山，寒梅微弄粉。", "二十四番風，迎臘先一訊。", "青女素精明，竟不易號令。", "譬如蛻骨仙，色粧而意整。", "惟有吟詩翁，年年來管領。"]'),
('8c580708-c712-46f3-b6bf-ab35168feaba','發奔牛','張侃','宋','宋诗','song-poetry','','[]','紅添花滿溪，綠带草穿石。',72,'全唐诗/poet.song.204000.json','["紅添花滿溪，綠带草穿石。", "佳致在目前，遠近記經歷。", "雲疎雨漸收，篙長水倒激。", "平生一詩卷，未免寫胸臆。", "記得坡翁言，在郡六百日。", "出處雖不同，我性聊自適。"]'),
('f7e47fa9-c8dc-4cd8-a19f-1e1d15703b98','桃花鸂鶒','張侃','宋','宋诗','song-poetry','','[]','畫工天機高，腕有萬鈞力。',180,'全唐诗/poet.song.204000.json','["畫工天機高，腕有萬鈞力。", "把筆解寫生，妙處欠人識。", "地深煙自引，雲歛望不極。", "誰知只尺間，卷藏棲座側。", "桃枝糝淺紅，羞带燕支色。", "經時歎芳跗，數片墮晴碧。", "政緣景色饒，詎忍光陰擲。", "波心自在流，夕照苦見逼。", "雌蜂不受影，容此雙鸂鶒。", "睨目且裴回，暫收西去翼。", "籠寬終難馴，水滿好脩飾。", "旁人莫癡心，乘勢事箭弋。", "庶幾久相忘，飛浮欣得得。", "連旬暑送風，對此融胸臆。", "不必形似求，枉費半圭墨。"]'),
('6dc59dfd-7168-45f6-8c00-4c5ca8c46a7c','新河','張侃','宋','宋诗','song-poetry','','[]','侵晨發金臺，停午泊新河。',72,'全唐诗/poet.song.204000.json','["侵晨發金臺，停午泊新河。", "風定雨新霽，一段平青羅。", "遠烟搴新景，宿鷺行細莎。", "臨流洗塵心，此地今幾過。", "官事記蒲鞭，少駐聽漁歌。", "大哉濬汲功，萬古保不磨。"]'),
('37f96811-a6e7-4d0c-9b67-a68be0752d3e','晨起','張侃','宋','宋诗','song-poetry','','[]','青山與白水，足以娛人思。',228,'全唐诗/poet.song.204000.json','["青山與白水，足以娛人思。", "麗花與佳禽，足以令人悲。", "因思世上事，感觸特一時。", "拘拘守定見，年少紛白絲。", "朝來北窗邊，天清雲不飛。", "桂樹充綠潤，其色光陸離。", "靜坐息萬慮，手携淵明詩。", "飲酒得真趣，神氣常自怡。", "我飲僅涓滴，螺杯謾爾持。", "後山草木深，有禽擇所栖。", "婆餠爲誰焦，姑惡爲誰咨。", "騷翁繹楚語，解說累千辭。", "萬物雖異性，天地同一機。", "時至乃飛鳴，人訛反生疑。", "禽語空啾唧，有怨難窮推。", "好生毛羽者，細聽强誑欺。", "遂使本然質，由是深有虧。", "清風到階庭，處處禽語奇。", "勿問聲如何，天地何曾私。"]'),
('83d3b980-679d-494d-9fb4-72aa09ed76e5','杜門','張侃','宋','宋诗','song-poetry','','[]','初官金臺邊，日長頗閒暇。',120,'全唐诗/poet.song.204000.json','["初官金臺邊，日長頗閒暇。", "細賡飲酒詩，喜無俗子駕。", "雲輕月緩梳，竹少花相亞。", "官塘頗塵囂，數間名傳舍。", "吾身聊自適，閲世如啖蔗。", "春初汎舟回，晴谿山影射。", "蒼苔護魚池，粉牆旁花架。", "東風知人情，游絲從空下。", "歷覽佳有餘，頃刻在所化。", "杜門觀我心，陶冶有鮑謝。"]'),
('dec00d2f-5fc7-41d7-a45b-57ef041eef8a','府治闢鎮越堂得坡翁詩石於草棘間','張侃','宋','宋诗','song-poetry','','[]','功名蚊成雷，文華珠媚川。',48,'全唐诗/poet.song.204000.json','["功名蚊成雷，文華珠媚川。", "作意每中輟，要當付自然。", "誰知蠅頭表，不似詩句傳。", "鑑湖生光彩，坡翁真謫仙。"]'),
('780b46fd-94d8-45a4-bfd9-e19cc0e06baf','記野人語','張侃','宋','宋诗','song-poetry','','[]','野人延我坐，古木陰四垂。',48,'全唐诗/poet.song.204000.json','["野人延我坐，古木陰四垂。", "未語涕先集，昔盛今全衰。", "我聞野人語，斯事古有之。", "但要存心地，何須問墓師。"]'),
('427e5a1e-ad2c-41f4-83ce-172e034fc909','歸來五首  其一','張侃','宋','宋诗','song-poetry','','[]','小圃近吾廬，呼奴掃階曲。',48,'全唐诗/poet.song.204000.json','["小圃近吾廬，呼奴掃階曲。", "梅株晚放花，谿水新圍玉。", "聲名不厭低，出處今已熟。", "倚杖看城山，飛來兩鴝鵒。"]'),
('415db701-925b-4b35-afe5-3ca042ae3c58','歸來五首  其二','張侃','宋','宋诗','song-poetry','','[]','西關景色妍，歸來春未盡。',48,'全唐诗/poet.song.204000.json','["西關景色妍，歸來春未盡。", "岸淺柳生陰，風緩花成陣。", "懽娛垂白親，免得望家訊。", "乳燕立簾鈎，別久還相認。"]'),
('bed2cb6b-5f2f-4f5c-89b6-c70abefe6e4a','歸來五首  其三','張侃','宋','宋诗','song-poetry','','[]','薔薇在其西，老桂在其東。',48,'全唐诗/poet.song.204000.json','["薔薇在其西，老桂在其東。", "先後不同時，生毓歸元功。", "幽艷占淑景，清香待秋風。", "有句莫漫與，騷然固長窮。"]'),
('039a1f7c-99ce-42f5-b305-cf082d6d52d0','歸來五首  其四','張侃','宋','宋诗','song-poetry','','[]','爽氣滿清晨，秀色藏山骨。',48,'全唐诗/poet.song.204000.json','["爽氣滿清晨，秀色藏山骨。", "結亭苕水旁，斷手建巳月。", "古語敬書紳，高譚休拄笏。", "柴扉喜常關，從今避請謁。"]'),
('fc7a08cb-6ae2-4331-8a33-39b20f418429','歸來五首  其五','張侃','宋','宋诗','song-poetry','','[]','酴醿數尺長，伐木成小架。',48,'全唐诗/poet.song.204000.json','["酴醿數尺長，伐木成小架。", "玉色映晚春，濃陰接初夏。", "濁醪任淺深，細草堪枕藉。", "興來信步行，浮雲出山罅。"]'),
('113c9a4c-ed39-414b-8d92-6c1d9e982021','書目所見者五首  其一','張侃','宋','宋诗','song-poetry','','[]','我家屏圍圖，畫作江天雪。',48,'全唐诗/poet.song.204000.json','["我家屏圍圖，畫作江天雪。", "雪晴行漁舟，蒲帆繫檣絕。", "猶記爲兒時，劍立從頭說。", "今日親見之，甚欲伴清潔。"]'),
('90e97b1b-25ab-47e1-a501-af56a8acdb94','書目所見者五首  其二','張侃','宋','宋诗','song-poetry','','[]','淺灘潮未到，小舟不得動。',48,'全唐诗/poet.song.204000.json','["淺灘潮未到，小舟不得動。", "當時一羽輕，今成千鈞重。", "老翁倚篙竿，生寒肩勢竦。", "勸翁且歸家，潮來勝乘槎。"]'),
('6e94f044-2d61-4415-a385-06dc841084b4','書目所見者五首  其三','張侃','宋','宋诗','song-poetry','','[]','盟鷗何處來，聲和春喜近。',48,'全唐诗/poet.song.204000.json','["盟鷗何處來，聲和春喜近。", "賓鴻可憐生，呼羣摩霧隠。", "鷗鴻本何心，世人無義襟。", "責彼不責己，嗟嗟非獨今。"]'),
('230b68c1-73e2-46b7-bcb2-5ff864f4d8ac','書目所見者五首  其四','張侃','宋','宋诗','song-poetry','','[]','羣山恰四圍，江潮游其中。',48,'全唐诗/poet.song.204000.json','["羣山恰四圍，江潮游其中。", "潮低不成山，豈是阨於風。", "舟行山漸遠，潮勢同瓴建。", "抑之可使高，又作望崖反。"]'),
('d204aad3-3ee0-4c0d-8dd6-4700a0efcd24','書目所見者五首  其五','張侃','宋','宋诗','song-poetry','','[]','小民海濱居，煎水活妻孥。',48,'全唐诗/poet.song.204000.json','["小民海濱居，煎水活妻孥。", "指海充府庫，何曾計有無。", "鹽成有喜色，摘蔬供午食。", "君子勞於心，我儂勞於力。"]'),
('67862723-c29e-45c4-ad7f-651f2a3b2fa2','朱陳嫁娶圖','張侃','宋','宋诗','song-poetry','','[]','生男願封侯，嫁女在比隣。',144,'全唐诗/poet.song.204000.json','["生男願封侯，嫁女在比隣。", "此是古人言，最知天理真。", "世遠人亦僞，嫁娶來城闉。", "歲序罕聚首，浩渺不計春。", "當其出門時，錯落車百輪。", "笙簫填孔道，珠翠委泥塵。", "堂開牡丹屏，盤橫水精鱗。", "徒取眼前富，未問身後貧。", "女嬌鮮禮法，薄夫貽所親。", "民家女及嫁，擇對走踆踆。", "一旦有其家，昕昏如主賓。", "誰圖朱陳村，宜爲堯舜民。"]'),
('01ad881f-6b19-47d3-af50-74aeae954259','嘉定壬午春晚園官送杞菊因取陸天隨蘇東坡張南軒三賦誦之感事賦詩','張侃','宋','宋诗','song-poetry','','[]','我志甘澹薄，不爲物所遷。',96,'全唐诗/poet.song.204000.json','["我志甘澹薄，不爲物所遷。", "園官送杞菊，秀色滿目前。", "生育秉至性，陰陽順中權。", "可憐黄口兒，匕筯照腥羶。", "縱得一餉戲，旁觀成脅肩。", "杞菊付中厨，試著薑鹽煎。", "至哉天下味，妙處祕不傳。", "三賢留雋語，首當師之焉。"]'),
('ca1bf9ea-7a9b-44cb-b177-fc9647a7a256','秋日閒居十首  其一','張侃','宋','宋诗','song-poetry','','[]','歸來清凈居，懶蹋紅紫陌。',96,'全唐诗/poet.song.204000.json','["歸來清凈居，懶蹋紅紫陌。", "有堂新翼然，遠景疑界畫。", "暑氣礙秋容，似覺眼界窄。", "墨雲吹雨絲，頃刻入地尺。", "水勢沄沄來，岸流已拍拍。", "老楊溼根翠，穉菱汙花白。", "東港與西塍，了不見舊迹。", "陰陽反掌間，底事作災阨。"]'),
('5d1d1cac-a424-4598-a827-228a4a810f84','秋日閒居十首  其二','張侃','宋','宋诗','song-poetry','','[]','名花逢深春，各自逞嬌怪。',96,'全唐诗/poet.song.204000.json','["名花逢深春，各自逞嬌怪。", "薔薇繞籬根，園丁采去賣。", "瑣細不知名，結束擔頭挂。", "細細隨輕風，時時與破壞。", "詩人浪自吟，放言竟成躗。", "紅紫一夕空，又見韶華邁。", "亭亭珊瑚枝，懶入名花派。", "每見天秋凉，依竹堪入畫。"]'),
('9314f7c6-428e-4e54-9c05-644909572d80','秋日閒居十首  其三','張侃','宋','宋诗','song-poetry','','[]','我志甘鋤園，汲水敢言倦。',96,'全唐诗/poet.song.204000.json','["我志甘鋤園，汲水敢言倦。", "擬種百尺松，終宵風雨戰。", "土脈分瘠肥，秉性有後先。", "蔚然三寸長，荆棘從旁罥。", "待得成清陰，方爲世人羨。", "畫手知姓誰，拂拭好東絹。", "寫此歲寒姿，爽氣滿庭院。", "不記少小時，插株泥樣賤。"]'),
('2d6c940c-ced5-41db-8598-93eea05a756b','秋日閒居十首  其四','張侃','宋','宋诗','song-poetry','','[]','秋崖一段清，秋水暗生池。',96,'全唐诗/poet.song.204000.json','["秋崖一段清，秋水暗生池。", "眼力所盡處，不特宋玉悲。", "化工爾許巧，閒花糝枯枝。", "凉生細細吐，月緩重重垂。", "但恨古之人，未能鑄好辭。", "從叟悲秋語，如石不可移。", "獨愛白樂天，酌酒細吟詩。", "漸喜無人聽，格外只自知。"]'),
('75b62c0c-9525-41c3-9dc7-d0e107c19a26','秋日閒居十首  其五','張侃','宋','宋诗','song-poetry','','[]','西關近邑郛，閒地素來廣。',96,'全唐诗/poet.song.204000.json','["西關近邑郛，閒地素來廣。", "規度三五弓，栽花屹相向。", "第一覓竹本，宗生要易暀。", "晚色翠四圍，依約見秋嶂。", "老雞先司晨，除柵試一放。", "峨冠汙枯草，鮮明莫能狀。", "厨人出新巧，收勳到盆盎。", "持送文園翁，小字書佳况。"]'),
('4d46f94c-3c4c-4875-8a4d-acba95d6d684','秋日閒居十首  其六','張侃','宋','宋诗','song-poetry','','[]','江南多澤國，別派亦成湖。',96,'全唐诗/poet.song.204000.json','["江南多澤國，別派亦成湖。", "渺渺明佳景，紛紛展畫圖。", "層穹邈無際，浮翠前峰孤。", "欲喚扁舟去，筆牀茶竈俱。", "東邊嶼深幽，穉蘆不記株。", "花輕相上下，隨風掠酒盂。", "湖中開一鏡，中有雙野鳬。", "可憐知者少，此趣未嘗無。"]'),
('31f404ae-94ac-4108-8c0a-d998687a6ddd','秋日閒居十首  其七','張侃','宋','宋诗','song-poetry','','[]','人情易愛憎，品花語最嚴。',96,'全唐诗/poet.song.204000.json','["人情易愛憎，品花語最嚴。", "遮護富貴花，排日掛牙籤。", "驕態不自持，霏微花上霑。", "虛名竟何益，餘事付寶奩。", "花開有遲速，稟氣等洪纖。", "到眼俱可翫，何曾形棄嫌。", "幽幽牽牛開，碧色照疎欄。", "勿云此花陋，所取緣傷廉。"]'),
('0d64e670-6645-450b-a1e0-a0392ff9248d','秋日閒居十首  其八','張侃','宋','宋诗','song-poetry','','[]','迎秋花事稀，蝶翅依沙晚。',96,'全唐诗/poet.song.204000.json','["迎秋花事稀，蝶翅依沙晚。", "籬落繞紅園，暗遣佳名損。", "立名豈願醜，一定不容返。", "寧避市塵喧，甘作山林遯。", "柔枝綴鳳兒，欄外成錦幰。", "婉婉風味殊，苒苒煙光遠。", "治世鳳朝陽，吾道何須偃。", "毋學接輿狂，終日空思忖。"]'),
('c3d4737b-4ea4-48de-9368-e92b92129dee','秋日閒居十首  其九','張侃','宋','宋诗','song-poetry','','[]','蘭以深而香，避世非吾忍。',96,'全唐诗/poet.song.204000.json','["蘭以深而香，避世非吾忍。", "移根植堂下，遂使世人囅。", "誰知秋華拆，未許流聲盡。", "即之色漸溫，佩之芳愈敏。", "因觀太古音，試理幽蘭引。", "幽蘭本香草，名隨四時泯。", "奈何楚子孫，些只徒自窘。", "一枝三四葉，與人作標準。"]'),
('6364b9da-9ce2-4357-b48a-6db073dac033','秋日閒居十首  其一○','張侃','宋','宋诗','song-poetry','','[]','小園雖偪仄，堂成春告殘。',96,'全唐诗/poet.song.204000.json','["小園雖偪仄，堂成春告殘。", "羣山當目前，翠色煙中繁。", "隔隄多垂楊，紛紛風前翻。", "畦夫爲予言，宜插秋牡丹。", "既無傾城艷，亦可酒筵看。", "根株雖脆弱，千葉攢中單。", "夕陽媚晴水，紅濕回輕瀾。", "休從殷七七，染法成欺暪。"]'),
('a38d5aa2-2f05-4a2d-ac8a-69dd52f260ee','五雲門外湖田','張侃','宋','宋诗','song-poetry','','[]','越中官賦重，有田即追呼。',120,'全唐诗/poet.song.204000.json','["越中官賦重，有田即追呼。", "小民生計薄，何以存妻孥。", "前賢念民切，潴水啟鑑湖。", "自此歲常登，不計大有書。", "湖堙水漸涸，往往事耕鋤。", "禾根雖浸水，天秋翠平鋪。", "后王主生育，詎肯餒一夫。", "盡說湖田好，大勝行商車。", "商車利縱博，巨濤與險涂。", "湖田若不熟，明年豈全無。"]'),
('4577605c-7752-4599-9d40-7f966363fc1d','娥江市','張侃','宋','宋诗','song-poetry','','[]','前回渡娥江，夜半呼舟行。',48,'全唐诗/poet.song.204000.json','["前回渡娥江，夜半呼舟行。", "今回渡娥江，風迎晚潮平。", "人心險於潮，潮頭平於路。", "娥心無古今，潮隨漁篙渡。"]'),
('6374ea02-df99-480d-858e-03da46d92142','千秋觀拜賀知章像','張侃','宋','宋诗','song-poetry','','[]','天清雲捲幔，風定水開奩。',48,'全唐诗/poet.song.204000.json','["天清雲捲幔，風定水開奩。", "既知鑑湖闊，所取胡乃廉。", "一曲期自足，千年名字馥。", "我來拜遺像，端可激頹俗。"]'),
('a657d627-1e54-4ebc-9c36-dbc14f86b6f5','遊石筍','張侃','宋','宋诗','song-poetry','','[]','偶成石筍遊，山色浸雲表。',48,'全唐诗/poet.song.204000.json','["偶成石筍遊，山色浸雲表。", "兩輪天地闊，一覽江湖小。", "渴飲金沙泉，饑餐翠松苗。", "鄴公何許人，遥想好風標。"]'),
('46b15697-2d7f-448e-afb9-7bfce01e1d64','郊外','張侃','宋','宋诗','song-poetry','','[]','縣市已蕭疎，何况在西郊。',96,'全唐诗/poet.song.204000.json','["縣市已蕭疎，何况在西郊。", "浮雲不成山，濁雨平淺坳。", "紛紛占生殖，蓋頭一把茅。", "釣魚尋竹枝，明火采松梢。", "翻成水墨畫，極意竟難描。", "移時反官舍，遊僧初解包。", "潜思目所寓，肯把聲名拋。", "試問耳聾許，終勝掉頭巢。"]'),
('c70fdd34-5a1c-4a08-8ffe-c0241ee40241','閒意','張侃','宋','宋诗','song-poetry','','[]','秋來纔幾日，得雨洗暑氣。',96,'全唐诗/poet.song.204000.json','["秋來纔幾日，得雨洗暑氣。", "庭前容人行，瑣細開野卉。", "似覺氣象殊，鄙薄牡丹貴。", "不是怨春風，政緣出處異。", "柔得千年存，剛則片時易。", "彈指秋又深，靜處覷萬彙。", "胡床倚竹根，清入詩人胃。", "好風緩緩來，側耳聽絡緯。"]'),
('9e95420f-2409-499f-90e2-4d5ed7135c4b','樊將軍廟在上陌樊宅土人相傳是將軍故居史本傳云沛人也五十年前因題數語今輒附此','張侃','宋','宋诗','song-poetry','','[]','將軍生沛邑，樊宅在吳墟。',48,'全唐诗/poet.song.204000.json','["將軍生沛邑，樊宅在吳墟。", "既沒其先語，决知非此居。", "排門忠尚在，浮甲事尤虛。", "却恐同姓者，相傳佚本初。"]'),
('6dceaafe-3a54-4630-90d3-1c47e84b81f6','古澗閒適','張侃','宋','宋诗','song-poetry','','[]','雨來磵水碧，磵遠山勢斜。',48,'全唐诗/poet.song.204000.json','["雨來磵水碧，磵遠山勢斜。", "磵邊隨意坐，瑣細覓開花。", "野蝶深有情，翾翾依沙晚。", "以渠流水心，醒我觀花眼。"]'),
('7ad427b2-87af-4736-bec1-60e8825b3903','示韋中實六首  其一','張侃','宋','宋诗','song-poetry','','[]','鶴隠乍來時，年方三十七。',72,'全唐诗/poet.song.204000.json','["鶴隠乍來時，年方三十七。", "忽忽十七年，終始如一日。", "卜居在邑西，近我讀書室。", "閒來劇笑談，友情似膠漆。", "筆端備六體，紙上春蛇逸。", "兩鬢吹秋絲，吟詩紀經歷。"]'),
('42d96fed-aee5-4eb5-bc58-10e7c4561eab','示韋中實六首  其二','張侃','宋','宋诗','song-poetry','','[]','去年金臺歸，今年三十六。',72,'全唐诗/poet.song.204000.json','["去年金臺歸，今年三十六。", "守拙伴林鳩，折箭存飛鵠。", "小園接屋東，有堂依水綠。", "浮雲前山來，蕭放忘拘束。", "雲已久無心，細看猶未足。", "起來一杯酒，從此覓歸宿。"]'),
('0c62e54d-a60d-4ce9-bb4f-752bbe84260e','示韋中實六首  其三','張侃','宋','宋诗','song-poetry','','[]','我與鶴隠交，一紀又踰五。',72,'全唐诗/poet.song.204000.json','["我與鶴隠交，一紀又踰五。", "燕飛知春秋，雞鳴便風雨。", "惟君勝蘇端，許我似杜甫。", "忘情更忘言，握手見肺腑。", "君或醉時歌，不問歌差誤。", "醒後頗快人，續續寫詩句。"]'),
('d4d169f3-d22c-4802-b960-f244e17fe2ab','示韋中實六首  其四','張侃','宋','宋诗','song-poetry','','[]','向來未服役，君室日清閒。',72,'全唐诗/poet.song.204000.json','["向來未服役，君室日清閒。", "侵曉披衣見，中宵曳杖還。", "溪梅粲玉萼，幾度開笑顔。", "邇來君累重，旬月旅長安。", "葛屨蹋塵沙，春在湖山間。", "忙裏買小艇，何妨卧看山。"]'),
('6d681cb4-385b-41c2-941d-5f1ded59bdf8','示韋中實六首  其五','張侃','宋','宋诗','song-poetry','','[]','一春隨意行，濟勝欣有遇。',72,'全唐诗/poet.song.204000.json','["一春隨意行，濟勝欣有遇。", "不愁風薄人，但愁雨深阻。", "亂山煙中藏，勃姑聲轉嗉。", "春無三日晴，前人句已寓。", "惜許好花枝，爛熳少人顧。", "君久不在家，花思依柳絮。"]'),
('9dc65305-64a2-4f5a-8f9b-1bacb77bacc6','示韋中實六首  其六','張侃','宋','宋诗','song-poetry','','[]','微官當力勤，後月已戒路。',72,'全唐诗/poet.song.204000.json','["微官當力勤，後月已戒路。", "思君且話言，處處放閒步。", "花前借鶑吟，卷中笑魚蠹。", "民家老樹根，小憩覓幽趣。", "更後四十年，同君尋舊寓。", "斯事姑置之，尺書寄飛羽。"]'),
('e469e555-0fb9-41f1-9572-39467e99e39b','示高愷叔','張侃','宋','宋诗','song-poetry','','[]','天秋桂子香，我舟從西來。',72,'全唐诗/poet.song.204000.json','["天秋桂子香，我舟從西來。", "愛君丰度好，面上無塵埃。", "相逢各草草，未暇開情抱。", "贈君以一言，功名薄穹昊。", "新春雪初晴，記水三四程。", "徘徊梅花樹，邀我了詩情。"]'),
('81eb5983-5974-4e3d-96e1-32d7dc838b73','題李伯時馬','張侃','宋','宋诗','song-poetry','','[]','近代李伯時，能畫天廄馬。',96,'全唐诗/poet.song.204000.json','["近代李伯時，能畫天廄馬。", "畫本出心匠，不在韓幹下。", "真骨獨當御，汗血沫凝赭。", "爲渠生光輝，神妙非力假。", "平日熟意態，繪事頗閒暇。", "誰知贋易真，萬馬悉喑啞。", "色带碧雲騢，和鸞亦雅雅。", "一筆竟不予，此意識者寡。"]'),
('4df440c2-d930-4e06-b172-adc6b6b0ec5c','三高祠','張侃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','武侯出師表，子陵釣魚磯。',288,'全唐诗/poet.song.204000.json','["武侯出師表，子陵釣魚磯。", "達則濟天下，窮則歛所施。", "凄凉數間屋，荒草碧離離。", "功名挂人口，毀譽復隨之。", "檥舟三高堂，快讀石湖碑。", "不有君子生，何以立國基。", "夫君守定見，遯野身自肥。", "儻不爲時用，猶當師仲尼。", "血指恐及己，旁觀付盛衰。", "汎湖誠僞計，思鱸設虛辭。", "區區務力作，反蒙樵人譏。", "松江水不窮，那能洗瑕疵。", "石湖擬小山，三招何逶迤。", "字字春秋筆，史氏當憑依。", "武林有西湖，湖上水仙祠。", "君復隠孤山，清名敵伯夷。", "死無封禪書，小詩揚京師。", "坡翁刺是邦，寒泉薦江蘺。", "在郡六百日，遂踵居易規。", "終焉配水仙，事定分是非。", "邦人思坡翁，要和甘棠時。", "遂肖三賢像，相與祝其尸。", "三賢得其操，三高得其微。", "篙師催我行，日落江水湄。"]'),
('37571dfa-9696-44f9-99c5-7f06f1eb6b5f','惠山','張侃','宋','宋诗','song-poetry','','[]','勝槩棄道旁，翠色空蕭爽。',72,'全唐诗/poet.song.204000.json','["勝槩棄道旁，翠色空蕭爽。", "泉經古澗流，鳥趁枯藤上。", "俗眼眩浮華，紅妝圍翠幌。", "入山恐太深，更肯契心賞。", "山靈亦退聽，佳名慮標榜。", "斷綆汲寒深，隨人墮世網。"]'),
('3dc93d08-fe44-40af-aa15-e25efc514a0d','煎茶','張侃','宋','宋诗','song-poetry','','[]','結廬枕石隙，其下通泉脈。',96,'全唐诗/poet.song.204000.json','["結廬枕石隙，其下通泉脈。", "新開數尺泉，涌然如乳白。", "道人北山來，閒話到終夕。", "徐云茶已芽，氣味及高格。", "絳囊映綠色，未嘗齒流液。", "汲泉滿歙缻，篝火勿遽迫。", "須臾蟹眼生，茶新手緩擲。", "薑鹽宜屏除，祇能添水厄。"]'),
('ef71b4f6-46cd-470a-9807-21ea0c51ba41','東西家','張侃','宋','宋诗','song-poetry','','[]','東家機杼鳴，西家舂杵急。',72,'全唐诗/poet.song.204000.json','["東家機杼鳴，西家舂杵急。", "西家荷艷鮮，東家竹翠濕。", "小小了生涯，四壁從渠立。", "昨朝雨傾盆，雞柵又新葺。", "柘葉延凉陰，父母妻兒集。", "村南沽酒歸，佳饌有魚入。"]'),
('25fc175e-6dd3-41e0-be7d-3b5be0c1a1db','對鏡辭','張侃','宋','宋诗','song-poetry','','[]','古人對鏡辭，率是年紀老。',144,'全唐诗/poet.song.204000.json','["古人對鏡辭，率是年紀老。", "出言反成悲，未免耿成抱。", "間有少年人，對鏡默祈禱。", "第一早功名，第二多壽考。", "第三欲富貴，滿屋貯珠寶。", "此心機械生，此身晨夕惱。", "用一每藏九，終焉乖至道。", "目爲守錢虜，名字亦可保。", "不見王夷甫，舉去忘稽考。", "我今對鏡別，有酒便爲好。", "欲醉未醉間，浩歌出晴昊。", "荷花解人心，風前互傾倒。"]'),
('a7c7492f-30ba-4c5b-8a4c-703ebfee35e6','秋夜','張侃','宋','宋诗','song-poetry','','[]','秋深氣轉清，夜閒更正永。',48,'全唐诗/poet.song.204000.json','["秋深氣轉清，夜閒更正永。", "庭前菊半花，天外雲收景。", "試呼麴生來，綠色照瓦皿。", "悠然兩相忘，何必問形影。"]'),
('6913b364-6a56-4c1c-a963-70d23a4615b5','十月二十四夜雪霰用蘇文忠和趙虢令韻','張侃','宋','宋诗','song-poetry','','[]','營居在西關，鍊句誰能和。',192,'全唐诗/poet.song.204000.json','["營居在西關，鍊句誰能和。", "水深舟已行，雨驟雲無奈。", "殘花蝶倦棲，弱柳鳥驚墮。", "橋杆挂稻頭，小定事舂簸。", "带濕芒盡除，易破粒漸瑳。", "世路久羊腸，人情隨蟻磨。", "每祈天雨寶，非是心好貨。", "力行毋自畫，浮言空相挫。", "因閒到農家，暫憩同客坐。", "別港野鳬歸，斷籬瘠牛卧。", "老翁語殷勤，今歲多坎坷。", "望晴眼力枯，護田衣袂涴。", "政恐官稅虧，不顧茅屋破。", "老翁勿預愁，太守兼勸課。", "丘明紀大饑，孟子憫人餓。", "瑞花舞綏綏，來秋真可賀。"]'),
('1a40dfca-e6a3-4bb3-8fe1-c82c61d88161','戊辰春二月雪呂君國秀曾賦七字句予和云試來月下逢僊子何似風前聘宓妃乙酉春二月一日雪再吟二首  其一','張侃','宋','宋诗','song-poetry','','[]','去年正月尾，雲片綴雨絲。',48,'全唐诗/poet.song.204000.json','["去年正月尾，雲片綴雨絲。", "今年二月頭，雪花一尺圍。", "豐登有定數，元化孰可窺。", "呼奴粲燈篝，細誦辛卯詩。"]'),
('8a94c88f-bee7-46ca-a03c-981e95f5d6f4','戊辰春二月雪呂君國秀曾賦七字句予和云試來月下逢僊子何似風前聘宓妃乙酉春二月一日雪再吟二首  其二','張侃','宋','宋诗','song-poetry','','[]','呂君年八十，曾賦春雪詩。',48,'全唐诗/poet.song.204000.json','["呂君年八十，曾賦春雪詩。", "平生慕韓愈，大書萬玉妃。", "我時年甫冠，辛苦鑄好辭。", "功業只爾耳，歲序空推移。"]'),
('1e819626-479b-450c-b8ce-6cc0252d1da7','孤山','張侃','宋','宋诗','song-poetry','','[]','先生聲名高，引人同吾道。',48,'全唐诗/poet.song.204000.json','["先生聲名高，引人同吾道。", "來訪孤山師，草木富華藻。", "有泉出山罅，碧色巧縈抱。", "甚欲酌此清，仰天應笑倒。"]'),
('ddeb9df6-b3f2-4f2a-87e5-a970d3804a50','寫古五首  其一','張侃','宋','宋诗','song-poetry','','[]','事行人所難，塗人未深信。',48,'全唐诗/poet.song.204000.json','["事行人所難，塗人未深信。", "吾身一時高，佳名萬古振。", "堂前頗幽虛，老竹添翠潤。", "世俗日澆訛，風流今已盡。"]'),
('4c6cb42d-a0df-4e36-9c30-7b619bb73f42','寫古五首  其二','張侃','宋','宋诗','song-poetry','','[]','文章如元氣，又如水赴川。',48,'全唐诗/poet.song.204000.json','["文章如元氣，又如水赴川。", "宿習務洗去，仲涂當日賢。", "扶持正統在，後學承其傳。", "衆目不可掩，璣衡麗青天。"]'),
('dde8d7ba-7cce-430e-b343-fd83fe5b6034','寫古五首  其三','張侃','宋','宋诗','song-poetry','','[]','束带立朝廷，平日有定力。',48,'全唐诗/poet.song.204000.json','["束带立朝廷，平日有定力。", "挺挺道鄉公，面上無佞色。", "諫書與天通，那暇顧荆棘。", "墓祭記學宮，賢哉太守職。"]'),
('28679210-f459-4523-a516-09a20261d725','寫古五首  其四','張侃','宋','宋诗','song-poetry','','[]','人心具天性，嗜好各不同。',48,'全唐诗/poet.song.204000.json','["人心具天性，嗜好各不同。", "荒凉陸子祠，寒泉引碧筩。", "名者身之累，千載存遺蹤。", "獨有吟詩人，時來繫短篷。"]'),
('e3720172-9858-4dff-b393-0fe0b4bb8edc','寫古五首  其五','張侃','宋','宋诗','song-poetry','','[]','希聲少年日，勁風盤青蒼。',48,'全唐诗/poet.song.204000.json','["希聲少年日，勁風盤青蒼。", "與世既不偶，投老頤山旁。", "蓺花靜天理，濬泉發新芳。", "斯事古亦有，君子戒反常。"]'),
('43aaa924-dc2d-4206-af39-d9085f8b3cac','清寒','張侃','宋','宋诗','song-poetry','','[]','臞叟久不出，短帽半離披。',192,'全唐诗/poet.song.204000.json','["臞叟久不出，短帽半離披。", "天公有新事，剪雪玉參差。", "仰瞻銀海眩，須臾肆寒威。", "試呼緘口翁，時復一中之。", "初如薝蔔飄，終似白練馳。", "陰氣無所泄，乘風舞綏綏。", "山明失紫翠，手板休拄頤。", "磎流有層冰，艇子寸步移。", "寒禽集深條，可憐翅翎垂。", "擁爐回陽春，始覺溫四肢。", "我生僅再見，老農重嗟咨。", "錦里杜子美，姑溪周紫芝。", "文章江漢流，初不事支辭。", "遺編可推究，古豈異今時。", "無此雪與寒，何翅五吟詩。", "宜瑞不患寡，寫檄誅雲師。"]'),
('cbf82c89-cc44-4ea1-8633-096b3aec473d','書事  其一','張侃','宋','宋诗','song-poetry','','[]','細雨饑寒色，忽被北風吹。',48,'全唐诗/poet.song.204000.json','["細雨饑寒色，忽被北風吹。", "楊柳絲不長，免得成別離。", "西家杼錦繡，東家粥文辭。", "天地本無巧，人世嗟何爲。"]'),
('a896176c-fb94-49af-8bca-194c718b343d','書事  其二','張侃','宋','宋诗','song-poetry','','[]','今年氣候遲，五月寒尚在。',120,'全唐诗/poet.song.204000.json','["今年氣候遲，五月寒尚在。", "花柳已稀疎，軒窗頗瀟灑。", "提携一書篋，轉盼十五載。", "自拂蛛蝥去，文字生光彩。", "名起致人嫌，俗冗令我凂。", "袖手細旁觀，小大立可待。", "樵夫唱竹枝，漁人歌欵乃。", "清適付儻來，浪語免後悔。", "吾家儒代耕，官卑謹勤怠。", "入夜傾碧香，聊用澆磊塊。"]'),
('73f1f1f8-efc3-4715-9e2f-275233dd6b91','歲時書事  其一','張侃','宋','宋诗','song-poetry','','[]','官居盡日閒，隨意自消遣。',96,'全唐诗/poet.song.204000.json','["官居盡日閒，隨意自消遣。", "出門河水清，風定回長練。", "煙林入畫圖，脫葉霜新絢。", "景色爲人妍，一歲知幾變。", "因思天地間，是處堪留戀。", "指隨襟袖寒，地氣近淮甸。", "歸來吹青燈，峨冠看經傳。", "今人聊復爾，古人不可見。"]'),
('61c1c756-b288-46bc-bbdf-8afa2af1189e','歲時書事  其二','張侃','宋','宋诗','song-poetry','','[]','牆東古楊樹，秋來已憔悴。',60,'全唐诗/poet.song.204000.json','["牆東古楊樹，秋來已憔悴。", "非無歲寒心，政以枝條脆。", "陽春敷新榮，生育不擇地。", "依依楊柳枝，風前舞嬌翠。", "嬌翠雖至柔，中有生生意。"]'),
('badffba1-9359-497e-8cc2-200025b4df34','歲時書事  其三','張侃','宋','宋诗','song-poetry','','[]','夜長何漫漫，誰爲勞者辭。',132,'全唐诗/poet.song.204000.json','["夜長何漫漫，誰爲勞者辭。", "致身清明朝，誰爲感遇詩。", "古來賢達士，氣志不肯卑。", "曳裾非素習，不過祈人知。", "一言偶相契，遂踵蕭何規。", "嗚呼今不然，車馬日以馳。", "朱門極富貴，長途多寒饑。", "立身榮辱中，每見無不爲。", "平生毅然節，反爲今所虧。", "赧顔度朝夕，同隊如小兒。", "結茅枕吳羌，清名萬代垂。"]'),
('38c24ee5-dc2f-4399-9aac-7ec457500100','歲時書事  其四','張侃','宋','宋诗','song-poetry','','[]','束髮能綴文，未解知其奧。',72,'全唐诗/poet.song.204000.json','["束髮能綴文，未解知其奧。", "脩綆汲淵源，所得是潢潦。", "年來三折肱，逢人漫稱好。", "古意愈簡淡，新說恣顛倒。", "如何十日曝，只望陰雨膏。", "閉門覷天功，時至學自到。"]'),
('40dc3a4d-c473-4e50-bdb5-fe3c67f62b6d','歲時書事  其五','張侃','宋','宋诗','song-poetry','','[]','霜色白皚皚，與雪竟無間。',156,'全唐诗/poet.song.204000.json','["霜色白皚皚，與雪竟無間。", "不獨齊國人，凌晨歌甕飯。", "古瓦燦奇葩，纖微分六瓣。", "雲寒曉不開，雝雝有孤鴈。", "猶記前十年，躡舄青螺綰。", "舒徐酌細泉，委折登危棧。", "獨恨來倉卒，野服未易辦。", "去年買小舟，歛板作微宦。", "荒凉屋數椽，門外多車輚。", "旋呼市居人，觕葺如縫綻。", "寂坐冬夜深，霜風吹兩骭。", "舊書不敢廢，官事不敢慢。", "達哉漆園翁，出處任鵬鷃。"]'),
('df6b1c66-f4ab-41e5-b18e-df416b9f8387','歲時書事  其六','張侃','宋','宋诗','song-poetry','','[]','朝來瑞花飛，簷前成箇箇。',96,'全唐诗/poet.song.204000.json','["朝來瑞花飛，簷前成箇箇。", "老農村中居，沽酒自相賀。", "不願擔石儲，但願免饑餓。", "連年田有秋，牆東添石磑。", "春來亦有花，竹外江梅破。", "倡桃與妖李，臨風自嬌惰。", "上天新賜瑞，莫測花機大。", "毫端已先知，浩歌續楚些。"]'),
('8c42b523-bffd-4cd3-b687-dd25c1e8316c','歲時書事  其七','張侃','宋','宋诗','song-poetry','','[]','冬雪已飛舞，冬月愈明皎。',72,'全唐诗/poet.song.204000.json','["冬雪已飛舞，冬月愈明皎。", "午夜靜人籟，一目天未了。", "荒村木杈枒，上有烏鵲繞。", "胡床擁破裘，呼奴取青醥。", "良夜天下同，妙處識者少。", "何必與人言，壯志出塵表。"]'),
('78918704-0bff-429d-9dc8-8168f1e123fa','歲時書事  其八','張侃','宋','宋诗','song-poetry','','[]','前朝到牐南，冰開春意動。',96,'全唐诗/poet.song.204000.json','["前朝到牐南，冰開春意動。", "寒風先觱發，日色尚曈矓。", "老翁禮頗恭，側立手先拱。", "殷勤謝官儂，筠籠野果重。", "顧我守官下，仁惠愧劉寵。", "其位偪而卑，惟知短檄捧。", "舉袖謝老翁，毋以斯言恐。", "我見誠暖姝，我才甘散冗。"]'),
('57677ee9-7dea-4e65-9832-b1f56b4e4703','歲時書事  其九','張侃','宋','宋诗','song-poetry','','[]','心官素坦夷，幼荷父兄詔。',132,'全唐诗/poet.song.204000.json','["心官素坦夷，幼荷父兄詔。", "口誦太古篇，煙村雜漁釣。", "誰知賢者樂，竟坐旁人譙。", "偶有百鍊銅，鑄作架上照。", "形模雖不同，小大亦相肖。", "一爲世所移，作事非素料。", "酒中有妙理，勿學淵明笑。", "淵明曠蕩人，行藏同荷篠。", "天外有奇趣，勿學孫登嘯。", "孫登隠逸輩，施爲異常調。", "萬事付自然，吾方詣至妙。"]'),
('1bf2c450-50f5-4381-bcc7-680101939c11','歲時書事  其一○','張侃','宋','宋诗','song-poetry','','[]','歲晚星回天，雪晴雨收脚。',72,'全唐诗/poet.song.204000.json','["歲晚星回天，雪晴雨收脚。", "畦丁昨夜來，老竹如新斮。", "我本一書生，紙上守糟粕。", "治圃非素長，方欲求其略。", "吁嗟天下人，方以鄰爲壑。", "人心自爾殊，化工無厚薄。"]'),
('28bde89e-9ad5-435a-842e-062ec9b8f90f','歲時書事  其一一','張侃','宋','宋诗','song-poetry','','[]','羣花極妖麗，不似梅花清。',48,'全唐诗/poet.song.204000.json','["羣花極妖麗，不似梅花清。", "孤標年年在，吟意年年生。", "香清到詩骨，可翫不可名。", "安得李杜輩，美酒爲之傾。"]'),
('6733433a-3fc2-4839-abfa-814ecd38237f','食圓用建昌使君叔父韻','張侃','宋','宋诗','song-poetry','','[]','荆楚遺風在，瑣碎陳佳筵。',168,'全唐诗/poet.song.204000.json','["荆楚遺風在，瑣碎陳佳筵。", "猶憶總丱時，兀坐空自憐。", "老妻劑秫粉，夜永燈花偏。", "瀲盌蔗漿穠，晴雲繞目前。", "翻匙玉比潔，膠齒珠相駢。", "我髮日種種，流光自年年。", "門無送酒人，誰能中聖賢。", "因試囊中術，妙處有機權。", "由來寓于手，不在刀削圓。", "汎觀天地間，幾者物之先。", "大阮精詩學，詠物巧回旋。", "虛名付儻來，默守終日乾。", "吳生泥於方，所見何拘攣。", "三復叔兮什，華池水潤咽。"]'),
('0c5f2a62-6f03-48dc-b26f-7d827ef1f59e','池荷','張侃','宋','宋诗','song-poetry','','[]','水淺荷亭亭，風過半欹側。',96,'全唐诗/poet.song.204000.json','["水淺荷亭亭，風過半欹側。", "入水元不濡，須臾見本色。", "偶然成珠璣，至妙人孰測。", "乍散起微波，再圓聊作劇。", "瀾雨未舒晴，浮雲時擁墨。", "小池瀰舊痕，一旦寓新飾。", "荷平綠水深，翠滿真堪惜。", "切勿濺成珠，漾去靜如拭。"]'),
('da9b10f9-1f6d-4835-b647-593508798fcf','楓橋','張侃','宋','宋诗','song-poetry','','[]','牆邊紫燕留，柳外紅日晚。',72,'全唐诗/poet.song.204000.json','["牆邊紫燕留，柳外紅日晚。", "川明山影動，風緩波聲遠。", "吾道付悠悠，世塵空衮衮。", "精廬傍官河，時有舟車返。", "古賢用志苦，吟詩一字穩。", "乃知半夜鐘，絕勝木蘭飯。"]'),
('c20f0d2a-a773-4f76-83f4-0e7db5adbff7','薄薄酒三首  其一','張侃','宋','宋诗','song-poetry','','[]','薄薄酒，解愁顔。',180,'全唐诗/poet.song.204000.json','["薄薄酒，解愁顔。", "醜醜婦，勝居鰥。", "但有粗繒大布包裹了，爭羨危冠華服傴僂趨朝班。", "就令真封定遠侯，何如生入玉門關。", "蘇秦富貴却輸負郭二頃，管叔兄弟恨不茅屋三間。", "張公厚葬保首領，嵇康養生誅市闤。", "亡羊未易較臧穀，爭地適足誇觸蠻。", "錦衣未暖沐猴敗，仙舟無耗鮑魚還。", "狂謀正使鬼笑，薄命豈坐天慳。", "不須乞鏡湖三百里，不須買蓮峰一半山。", "窮達憂樂付與三萬六千日，但恐一生辛苦不若一生閒。"]'),
('964185e1-bb65-426f-9fac-5f188a7ff0bc','薄薄酒三首  其二','張侃','宋','宋诗','song-poetry','','[]','薄薄酒，免厚味。',184,'全唐诗/poet.song.204000.json','["薄薄酒，免厚味。", "醜醜婦，得長年。", "淵明飲酒聊小醉，醉後清風北窗眠。", "季倫百萬買嬌麗，一朝禍至空棄捐。", "因思達者得其趣，那用情愛汩心淵。", "門栽五柳池種蓮，瓶無斗粟囊無錢。", "浮雲富貴不須問，在世得失付自然。", "君看曳玉垂金趨魏闕，何如躡舄散策吳羌邊。", "君看奇珍異味食方丈，何如糲飯野蔌在目前。", "古來知此亦自少，或出或處隨吾權。", "入秋雨過暑光薄，桂子將綻添清妍。", "抱甕獨醉有深樂，不用抽釵喚李娟。"]'),
('30d07198-5e38-42f8-be85-911aa392fcbc','薄薄酒三首  其三','張侃','宋','宋诗','song-poetry','','[]','薄薄酒，無餘味。',98,'全唐诗/poet.song.204000.json','["薄薄酒，無餘味。", "醜醜婦，有餘妍。", "君看行樂且隨分，不用美酒麗女驕目前。", "紛紛萬事如雲過，塞翁祈福圖免禍。", "屈指富貴能幾人，大笑書生守寒餓。", "書生作計亦不癡，開尊對花吟好詩。", "醜婦買魚赤脚煮，醉後狂歌發真趣。"]'),
('6cf3d0fb-c4f7-4e87-9a79-66b2169f2c7c','家園有梅一株依附籬落潘聖功喜其有古意戲占云早是江南春訊動枝頭己著兩三花癸酉歲梅不生花己卯秋尾聖功云亡愴然有感見于篇什','張侃','宋','宋诗','song-poetry','','[]','雪意垂垂雲滿天，梅花一枝放清妍。',144,'全唐诗/poet.song.204000.json','["雪意垂垂雲滿天，梅花一枝放清妍。", "與君蹋雪看不足，歸來吹鐙傳詩篇。", "此詩只許梅壓倒，句中染香疑登仙。", "梅兮再四乞避舍，杳渺初不到靈堅。", "我恐么鳳暗作祟，嶺梅碧落侍班聯。", "空留佳語塗耳目，歲月冉冉知幾遷。", "况君姓氏占仙籍，隨分了却塵世緣。", "想今共梅成莫逆，投壺一笑三千年。", "江南春訊誰領略，杖頭那用挂酒錢。"]'),
('f76497d4-136e-44ee-baf6-cfffe1ce2007','千葉支子','張侃','宋','宋诗','song-poetry','','[]','園林綠暗花事稀，蜂愁蝶怨依夕暉。',128,'全唐诗/poet.song.204000.json','["園林綠暗花事稀，蜂愁蝶怨依夕暉。", "天工續續施巧手，眼邊無日不芳菲。", "須知萬物都是假，苦泥實相第二機。", "支花附石水清泚，端莊自是蕭然姿。", "來從鹿苑塵頓洗，暫登螢窗聊發揮。", "芳苞攢葉毋乃密，清香徐徐風作圍。", "我方寂坐息百慮，對此不覺板拄頤。", "荒山草木能嫵媚，從今細尋莫相違。"]'),
('cc2400ae-b5e0-42cc-bc46-959af08a973b','園丁報秀野對岸芙蓉盛開','張侃','宋','宋诗','song-poetry','','[]','我家分占清溪曲，溪曲新添數椽屋。',224,'全唐诗/poet.song.204000.json','["我家分占清溪曲，溪曲新添數椽屋。", "屋前花竹占清妍，更植芙蓉伴黄菊。", "植時止是三寸栽，雨打雪埋地氣回。", "深培淺壅那費力，想見錦繡沿溪開。", "向來爲渠轉一語，欲絆秋光堅不住。", "于今秋光雖勝前，花開却恨隔江浦。", "畦丁知我酷愛花，風吹芳訊到官衙。", "淡紅深粉足嬌態，高高下下依日斜。", "人生行樂何須定，蹉見此花頭次盛。", "蜂脾添蜜採偏多，蝶婢尋香屢來聘。", "因報畦丁輕削根，趁時亂插不厭繁。", "今年開遍明年續，要使長蒙天地恩。", "主人做官在虞水，亦有芙蓉滿閒地。", "看花翻憶植花時，酌酒一杯誰寄似。"]'),
('a1a2346a-1be9-4c48-bf91-345121b3d845','野航池邊古梅二首  其一','張侃','宋','宋诗','song-poetry','','[]','池邊梅花種幾時，枝柯古怪苔紋圍。',64,'全唐诗/poet.song.204000.json','["池邊梅花種幾時，枝柯古怪苔紋圍。", "可憐守分不入宜，開時却有天然姿。", "因看冬夜月初上，景象森然最難狀。", "梅枝寫影已清奇，不用畫師作圖障。"]'),
('92d931e0-16a1-4d01-80b3-e5ead16dc322','野航池邊古梅二首  其二','張侃','宋','宋诗','song-poetry','','[]','凡花雖艷艷在眼，梅花带清清入骨。',64,'全唐诗/poet.song.204000.json','["凡花雖艷艷在眼，梅花带清清入骨。", "時人喜艷不喜清，綺言麗語寓輕忽。", "池邊之梅格又高，霜月次第上林皋。", "平生愛梅被梅惱，梅亦憐吾非年少。"]'),
('adc42ca3-ba71-45fa-ab16-e8a8c33b46b0','對梅傚楊誠齋體','張侃','宋','宋诗','song-poetry','','[]','前年看梅清溪邊，萬花依枝占芳妍。',128,'全唐诗/poet.song.204000.json','["前年看梅清溪邊，萬花依枝占芳妍。", "去年看梅金臺下，一枝傍竹秀而野。", "今年梅花勝舊年，急呼麴生來座前。", "折花飲酒到夜半，羌管休吹且頻看。", "旁人笑我心太癡，花開花落由天時。", "如何苦作十日計，慳風妬雨誰得知。", "我雖不言見已慣，倚著茅簾聽過鴈。", "明年梅開在清溪，不妨訪梅西山西。"]'),
('35ae615f-5b52-427f-b57a-2ea99fa51add','連日雨','張侃','宋','宋诗','song-poetry','','[]','夭桃倡杏羞蕋紅，東風未傳第二訊。',64,'全唐诗/poet.song.204000.json','["夭桃倡杏羞蕋紅，東風未傳第二訊。", "忽吹山頭雲擁墨，細聽簷牙雨成陣。", "公堂閴寂春晝長，病夫兀坐湘竹牀。", "童子添火深炷香，萬念不生兩相忘。"]'),
('d7091ee0-b472-4d23-bc98-1ed0e058fd92','久雨','張侃','宋','宋诗','song-poetry','','[]','浮雲四散雨意濃，小池水滿不可容。',64,'全唐诗/poet.song.204000.json','["浮雲四散雨意濃，小池水滿不可容。", "前度久晴今久雨，綠牋端欲問太空。", "太空高兮渺無路，風力翦絲得小住。", "農家一飽庶有期，笑殺春深脫布袴。"]'),
('5f0f188a-0be9-4239-9893-d8f8c224d44f','連日雨意未止','張侃','宋','宋诗','song-poetry','','[]','前日雨聲無一滴，官河不堪行小舟。',96,'全唐诗/poet.song.204000.json','["前日雨聲無一滴，官河不堪行小舟。", "只因連夜雲送雨，軒窗處處留清幽。", "人心不同分好惡，陰晴無準言妄吐。", "杜陵曾賦貧交行，豈是今人不如古。", "古人今人莫預愁，皇天念民耕西疇。", "翻手覆手言俄頃，功過只須付毛穎。"]'),
('533c22de-d61b-4956-b5ee-574224fafafb','遊西湖','張侃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夜來雨足半篙水，西湖荷花紛錦綺。',112,'全唐诗/poet.song.204000.json','["夜來雨足半篙水，西湖荷花紛錦綺。", "扁舟載酒作清游，香入衣襟風緩起。", "西湖之景天下無，萬句千言空滿紙。", "山依華屋屋依山，湖光渺渺相回環。", "因思古人比西子，又見今人比賢士。", "東坡詩句脫塵凡，不比今人較形似。", "今時亦自有詩人，毫端無窮契天理。"]'),
('5ea86379-d98e-49e1-986e-5694d80cec9f','黑雲行','張侃','宋','宋诗','song-poetry','','[]','山頭墨雲未肯歸，牐邊積水正漣漪。',64,'全唐诗/poet.song.204000.json','["山頭墨雲未肯歸，牐邊積水正漣漪。", "去年苦旱望甘雨，今年久陰藏晴曦。", "天心人意默相契，雨多不止尺入地。", "訟風擬學韓退之，深恨綠牋無好辭。"]'),
('9cd1ad10-f681-4bea-83c9-dcafa7cd6d89','金牛行','張侃','宋','宋诗','song-poetry','','[]','君不見晉陵縣北異事傳，夜氣將深纔出沒。',131,'全唐诗/poet.song.204000.json','["君不見晉陵縣北異事傳，夜氣將深纔出沒。", "古來至寶默有數，精英之藏寧久鬰。", "我閒試爲訪遺蹤，惜許邦人忘歲月。", "不然上亦逼星躔，兩無相合歸芒芴。", "當時奮身萬策湖，愛向東山穿香骨。", "豈知服猛盡奔馳，潛地而馳真異物。", "雨侵古蘚滿荒臺，虛名空在何有哉。", "嗚呼金牛計已竭，胡不犠尊陳帝闕。"]'),
('7ba469e7-447f-4cd1-b7bb-60fb939ba580','槎浦並海','張侃','宋','宋诗','song-poetry','','[]','海風顛狂衣袂摺，長檣巨艦去如葉。',96,'全唐诗/poet.song.204000.json','["海風顛狂衣袂摺，長檣巨艦去如葉。", "却行小立視荒田，老翁擲杖呼妻妾。", "成行再拜告官儂，舊秋潮大經短堞。", "只因鹹水入田來，雖築田塍已晚哉。", "官儂不知苗根透，戽水浸苗望苗秀。", "日蒸水氣反枯苗，不如莫種只望潮。"]'),
('69bc37fb-34c2-47d4-93ce-144e6eeabd7e','自白馬湖穿夏蓋湖至後郭塘岸','張侃','宋','宋诗','song-poetry','','[]','連日天晴雲送雨，羣山環繞翠相聚。',80,'全唐诗/poet.song.204000.json','["連日天晴雲送雨，羣山環繞翠相聚。", "湖心波起小玉山，映带不多添媚嫵。", "十年江湖寄此身，每到佳處喜生津。", "豈知築隄限海水，底事毀泐築更頻。", "君知此理休更說，只緣今日人心別。"]'),
('dd7f95bb-6d65-4bb7-aa69-a9fcc375a607','西溪湖','張侃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','杭州西湖天下無，重樓複閣成畫圖。',227,'全唐诗/poet.song.204000.json','["杭州西湖天下無，重樓複閣成畫圖。", "中宵與客買舟去，千金間亦呼名姝。", "自言此游有真樂，月明星稀飛林烏。", "珍殽旨酒雜樽俎，水精之鱗盤橫鋪。", "光陰鼎鼎暗中去，事業泯泯紙上拘。", "蘇仙在郡情甚適，君復居山身頗臞。", "英風既往不可作，蹤跡勝槩生荒蕪。", "空留濃粧淡抹句，思士久泥反長吁。", "金罍有溪名西湖，我來適當夏之初。", "萬荷疊疊風捲翠，群山隠隠雲依梳。", "岸頭有亭翼然立，明秀拱挹美且都。", "名園花卉憶靈運，古洞深遠棲仙姑。", "月當下弦遲開鏡，高燒銀燭行冰壺。", "君不見水利及人居第一，爲壑勿學白圭術。"]'),
('a933259d-ede5-49b9-9fdb-fb71f41f5441','娥江下岸田爲潮汐衝擊今不可墾小民勺水煎鹵于上','張侃','宋','宋诗','song-poetry','','[]','江潮衝田漸成地，地久歸鹹有其味。',64,'全唐诗/poet.song.204000.json','["江潮衝田漸成地，地久歸鹹有其味。", "小民泥爐候泥乾，勺水煎鹽求淺利。", "農家耕田望秋成，煎鹽得錢盡力爭。", "嗚呼小民盡力爭，農家輟耒愁空生。"]'),
('d108f7cd-63c3-4cdf-838b-4e62ee028296','拽碑歎','張侃','宋','宋诗','song-poetry','','[]','上虞溪湖十四處，昔日是田納官賦。',192,'全唐诗/poet.song.204000.json','["上虞溪湖十四處，昔日是田納官賦。", "逢秋民間欠灌溉，縣官作文告后土。", "民間以田濬溪湖，田上官賦却抱輸。", "閑時潴水旱時用，縱未全熟無全逋。", "古來人心平似砥，今來人心薄于紙。", "不念平人輸賦苦，情願自爲悠久計。", "大臣奏事怡天顔，以民爲基古已然。", "况乃民間推己有，明知食是民之天。", "此事傳來猶未久，爲雨爲雲翻覆手。", "拽碑使平命工磨，別鎸奇文垂不朽。", "鬼神訶護屹不移，至今碑上光陸離。", "噫嘻人心不如石，使我歎息重歎息。"]'),
('d3f17880-098a-4a34-8592-f2b60e9c5ce4','讀劉義門碑','張侃','宋','宋诗','song-poetry','','[]','深秋檢旱步田隄，天清日懶風緩吹。',128,'全唐诗/poet.song.204000.json','["深秋檢旱步田隄，天清日懶風緩吹。", "行行不覺筋力倦，前山數鴈带斜飛。", "老農指點前頭路，便是義門植碑處。", "義門當日篤於親，十世同居無異語。", "可憐年遠子孫微，頼有此碑名未虧。", "子孫能守前人志，田雖一畝不忍離。", "斂襟讀碑幾百字，重歎今人深有愧。", "老農耕田莫深鋤，臺高要記義門居。"]'),
('ef20abb2-d3b8-4b26-84a5-c1c5253d7e0b','夜窮歌','張侃','宋','宋诗','song-poetry','','[]','山田多怕旱，引水以溉灌。',47,'全唐诗/poet.song.204000.json','["山田多怕旱，引水以溉灌。", "不知雨勢狂，衆流極迷漫。", "君不見三鄉農，一年之計一夜窮，雖有人力無由逢。"]'),
('9a295ad6-6c19-43c7-828c-a14802bce120','打魚網歎','張侃','宋','宋诗','song-poetry','','[]','山川信美何處無，只許漁翁把茅居。',144,'全唐诗/poet.song.204000.json','["山川信美何處無，只許漁翁把茅居。", "四時風月俱占斷，詩人琢句空長吁。", "漁翁平生家累重，得魚入市日曈矓。", "裹鹽糴米了晨炊，依舊尋魚波洶湧。", "山川雖好儂不知，只知取利他何爲。", "羣居出巧結新網，名以攔江縱所施。", "鯉魴未免僅出入，切勿因香戀微濕。", "破壞好景是漁翁，不用健羨琢句工。", "聖人設險今重險，取與不取戒以漸。"]'),
('8676a5ce-9953-4b1d-b50e-988f8d41e77f','小雨','張侃','宋','宋诗','song-poetry','','[]','墨雲偶過雨數點，萬葉辭柯霞山崦。',64,'全唐诗/poet.song.204000.json','["墨雲偶過雨數點，萬葉辭柯霞山崦。", "風聲怒號作新寒，斷蹊曲港路艱險。", "山中之民屋蓋茅，豐歲往往成樂郊。", "分有大小隨分足，旋折豆稭煨冷粥。"]'),
('a8d33d48-c0de-4ce2-812c-db66f82f6c36','采蕺歌','張侃','宋','宋诗','song-poetry','','[]','采蕺采蕺蕺漸綠，蕺山昨夜雨霑足。',96,'全唐诗/poet.song.204000.json','["采蕺采蕺蕺漸綠，蕺山昨夜雨霑足。", "越女提籃入市中，論價不止金與玉。", "開時花似蕎麥花，亦能蔓生走長蛇。", "龍肝鳳髓久無味，却尋野蔌新矜誇。", "聲名在世多相忌，最厭薰蕕同一器。", "我歌采蕺非虛辭，采蕺歌中有深意。"]'),
('15955b0c-539c-4835-bdaa-b0721be5ef0b','秋蟲篇','張侃','宋','宋诗','song-poetry','','[]','縣樓漏鼓聲逄逄，秋深夜永睡未濃。',268,'全唐诗/poet.song.204000.json','["縣樓漏鼓聲逄逄，秋深夜永睡未濃。", "窗前秋色已可掬，枕畔秋凉能暗通。", "偶思向來所歷事，記一忘十馬牛風。", "醒然如寤或省起，四壁不耐吟秋蛩。", "秋蛩賦命抑何小，聲則甚大凄而雄。", "艱難七月陳王業，警戒再四由姬公。", "如何秋蛩蒙好語，意謂有漸將成終。", "初非卒然來徑去，有如疾風轉孤蓬。", "入我牀下聲更切，恐我佐邑務纖洪。", "情知官府印窠大，不信民間機杼空。", "就中懶婦絲未理，狂謳野舞廢女紅。", "競言秋蛩非促織，自是合歡人不識。", "綠牙作籠金作柵，萬錢爭買成戲劇。", "撫枕三歎忽成詩，秋蛩秋蛩竟何爲。", "汝喙從此箝，汝聲從此辭。", "不平之鳴汝何預，宵爾之織汝無衣。", "自形自色雖天付，我欲睡矣汝且住。"]'),
('dea771be-058b-45af-98dc-90aa902471af','懷仁畫龍','張侃','宋','宋诗','song-poetry','','[]','懷仁兩龍今幾載，墨色欲盡形模在。',96,'全唐诗/poet.song.204000.json','["懷仁兩龍今幾載，墨色欲盡形模在。", "有時驅雨成波濤，妙處暗與神明會。", "三江七澤龍所居，夜深簸弄明月珠。", "爲人圖畫雖左計，不識憑依當殿隅。", "世間紛紛稱畫手，誰識懷仁是劉叟。", "龍兮龍兮神其靈，長使邦人書大有。"]'),
('d5efa5db-9327-4904-bec9-03761e693828','前日昨日行','張侃','宋','宋诗','song-poetry','','[]','二九相喚不出手，婦人紉衣先紉袖。',96,'全唐诗/poet.song.204000.json','["二九相喚不出手，婦人紉衣先紉袖。", "門外霜風吹倒人，相見玉壺冰舊酒。", "去年家居坐竹窗，日陰移處梅梢長。", "今年負丞在山邑，並海寒氣非尋常。", "前日昨日風四起，頃刻凍合省河水。", "鴈宿蘆花亦倦飛，只待桃花初水肥。"]'),
('9aca5726-956f-4345-ac75-d67cfc215927','望雨行','張侃','宋','宋诗','song-poetry','','[]','去年雨多浸坤軸，排簷日日注銀竹。',128,'全唐诗/poet.song.204000.json','["去年雨多浸坤軸，排簷日日注銀竹。", "菊花已老强飄黄，荷葉雖枯猶護綠。", "今年梅雨久不來，暑風吹乾生塵埃。", "苦求涓滴潤田畝，敢望瀲灧添酒杯。", "昨日雨意十分好，雨聲不斷真是寶。", "誰知好處放些慳，尚使老農惱情抱。", "拙翁負丞方五旬，爲民致禱施殷勤。", "飛雲漸黑開又合，戀戀未竟林花紛。"]'),
('b681f151-04a9-421e-aeaa-7d230d193e7e','題鼠狼捕雀圖','張侃','宋','宋诗','song-poetry','','[]','三雀相逐枯竹低，鼠狼睥睨雀高飛。',64,'全唐诗/poet.song.204000.json','["三雀相逐枯竹低，鼠狼睥睨雀高飛。", "可憐一雀翎翅短，天寒日暮充爾饑。", "充作饑腸僅一飽，雀雀悲鳴猶未了。", "至今不敢眎枯竹，揀得寒林深處宿。"]'),
('24de854a-05a0-4d81-a748-85320dd202d5','題禪鄉院壁間墨梅','張侃','宋','宋诗','song-poetry','','[]','昔年曾作梅花夢，夢回衣上寒香重。',96,'全唐诗/poet.song.204000.json','["昔年曾作梅花夢，夢回衣上寒香重。", "矮窗偶見一枝開，早是江南春意動。", "凡花不似梅之清，精神骨相由天成。", "屢從畫手細傳本，但知刻畫非寫生。", "官塘荒寺門斜掩，歲久廊欹風雨颭。", "不須晴雪明千堆，賸喜墨痕留數點。"]'),
('bc15d9fc-e14e-466f-88a7-ec182c77dad2','潮','張侃','宋','宋诗','song-poetry','','[]','人身日夕何曾休，血隨氣運長周流。',92,'全唐诗/poet.song.204000.json','["人身日夕何曾休，血隨氣運長周流。", "偶然逆轉背常理，未免凝結成贅疣。", "少年每誦海潮賦，徑以人身爲譬喻。", "君看沙漲潮頭回，却向別流亂衝去。", "攔不住潮頭，從此失故步。", "人身調養勿傷和，潮汛緩來爭奈何。"]'),
('d58064b4-6524-4a1c-8b2e-604c24824624','羣牛浴小港','張侃','宋','宋诗','song-poetry','','[]','羣牛見水身半濕，水淺泥深踝全入。',64,'全唐诗/poet.song.204000.json','["羣牛見水身半濕，水淺泥深踝全入。", "摇頭擺尾緩緩游，羣牛相呼卒未休。", "牧童在旁短鞭指，童既無言牛漸邇。", "人牛兩忘日自長，水茫茫兮禾蒼蒼。"]'),
('81166d70-431a-4c96-a51b-e1976afdfd91','多稼亭','張侃','宋','宋诗','song-poetry','','[]','前年毘陵登多稼，萬頃黄雲在亭下。',96,'全唐诗/poet.song.204000.json','["前年毘陵登多稼，萬頃黄雲在亭下。", "斷碑依壁毫髮微，擊壤老人歌聖化。", "今年負丞到會稽，州園瓦影碧參差。", "中有一亭容數客，鬰鬰兩字標璇題。", "吾聞國以民爲本，民向東郊事耕墾。", "與民同樂識見高，秋成沽酒來遊遨。"]'),
('ba1bb98b-735d-418e-9bb1-1a1b5459738a','山中老人送蕙花山荷葉因成長句','張侃','宋','宋诗','song-poetry','','["\u534e\u5c71"]','山中老人久不見，忽然遇我清溪濱。',192,'全唐诗/poet.song.204000.json','["山中老人久不見，忽然遇我清溪濱。", "手把幽蕙數十本，清香襲襲侵衣巾。", "向來我曾著數語，定是久闇蛛蝥塵。", "老人詳說種蕙法，泥酥沙軟水力平。", "亂山深處少人跡，歛藏不耀席上珍。", "即今得登君子堂，藹然能被天地仁。", "小盆別種山荷葉，種時近水開晚春。", "青青之色亭亭立，似與巴豆爲弟兄。", "不然太華山頭種，小變厥初翻樣新。", "草木至微同是性，出處一異虧本真。", "老人前身恐是郭，隨緣衣飯甘淡泊。", "爾雅讀書吾未能，聊爲老人書大略。"]'),
('eb4c550e-84c6-41d8-8ba5-1d19d837bc33','明月堂聞松風','張侃','宋','宋诗','song-poetry','','[]','此去中秋纔七日，明月堂前秋可即。',198,'全唐诗/poet.song.204000.json','["此去中秋纔七日，明月堂前秋可即。", "山深水遠斷人蹤，僧云居此探消息。", "老松夭矯雙鳳翔，翠色依月新凝光。", "神仙所居無乃是，我來訪古摩蘚蒼。", "夜長月正當窗白，風入松梢聲劃劃。", "娥江元自通濤江，脫似江潮撼僧牀。", "君不見東坡先生豪一世，寄語重門休便閉。", "胸中吐出黄初詩，詩勢如潮夐無比。", "又不見后山居士真仙人，每遇奇觀精神生。", "悠悠江水流不盡，晚日浮沈潮勢平。", "披衣起坐寂無語，松影參差復如故。", "風聲四散不暫停，遥見江流趁東去。"]'),
('14ed69b4-f11a-45d4-aeb6-1895d9a10477','簡曾舜卿','張侃','宋','宋诗','song-poetry','','[]','三十五日不見君，今番寵訪又三旬。',64,'全唐诗/poet.song.204000.json','["三十五日不見君，今番寵訪又三旬。", "喜君風度勝似舊，未暇取酒細論文。", "西關之西蔣灣北，隨分各有數間屋。", "只待梅花摘索開，共君清賞意自足。"]'),
('14c429ac-b311-458a-9fa9-b99d962bc317','蘇李河梁相別圖','張侃','宋','宋诗','song-poetry','','[]','古人重交情，初不分秦越。',83,'全唐诗/poet.song.204000.json','["古人重交情，初不分秦越。", "詩句聯珠璣，中心瑩日月。", "何人作此圖，筆墨已超絕。", "因圖想當時，交情重于別。", "君不見朔風漠漠沙草寒，子卿仗節歸漢班。", "河梁執手不忍去，安得同飛無羽翰。"]'),
('2bed8d48-ad56-4040-8810-f866e12203da','陶夢得弼袖詩見訪用元韻','張侃','宋','宋诗','song-poetry','','[]','大雅不作詩格變，只今知誰傳妙手。',131,'全唐诗/poet.song.204000.json','["大雅不作詩格變，只今知誰傳妙手。", "既愛虛飄狀風雲，又愛雕鎪桮杞柳。", "半生于此寓吾身，曉吟夕鍛苦用心。", "可憐汩汩逐外物，未免漸漸虧天真。", "我今久已乾面唾，閉門政要深自坐。", "春來織柳鶑弄聲，秋至凋葉蛩相和。", "牀頭一卷古人詩，疾讀緩讀莫相疑。", "君不見口耳之學求宗派，不問血脈在不在。"]'),
('70ac5287-9b27-4c9e-bb37-540dd2bd2bd0','十里舖歌','張侃','宋','宋诗','song-poetry','','[]','山容偏向秋深瘦，轎行十里日將晝。',131,'全唐诗/poet.song.204000.json','["山容偏向秋深瘦，轎行十里日將晝。", "斜斜雁字雜真行，節節芙蓉攢錦繡。", "向來頗恨日月遲，而今翻道光陰驟。", "是中有策君豈知，心要清閒手長袖。", "片言輕發潛禍機，駟馬難追焉用救。", "州家因旱授民詞，差官下縣拯民饑。", "嗟予竊粟慚一飽，破裘短袂肩相隨。", "君不見流行坎止言所寓，初程且到十里舖。"]'),
('1a9d18ec-3dc0-486b-a2c3-75ce63a9af15','雨後生凉絡緯聲清可愛','張侃','宋','宋诗','song-poetry','','[]','玄蟬聲清入吾耳，暑氣駸駸猶未已。',64,'全唐诗/poet.song.204000.json','["玄蟬聲清入吾耳，暑氣駸駸猶未已。", "殘花挺挺留鹿葱，嬌態娉娉是荷婢。", "偶然一雨雲紉裳，池邊雨過風送凉。", "小蟲深集楊柳影，一段笙歌清更長。"]'),
('fc83d9aa-4de1-4b20-9139-a3be1072f777','東坡祠','張侃','宋','宋诗','song-poetry','','[]','先生筆端侔造化，妙歲清名滿天下。',128,'全唐诗/poet.song.204000.json','["先生筆端侔造化，妙歲清名滿天下。", "久知富貴等浮雲，已悟世情同啖蔗。", "置居陽羨山水妍，湔滌埃塵聊稅駕。", "豈知地主無所容，天地雖寬如傳舍。", "一朝焚券還其居，意氣不迫愈閒暇。", "年深此事竟莫傳，欲紀詩篇愧陶謝。", "先生祠堂幽且深，今人那識古人心。", "但把丹鉛較形似，滿廊遺像成兒戲。"]'),
('9019a5be-948e-431f-9525-8d344db94d94','象田老饋山茶用東坡先生韻奉寄','張侃','宋','宋诗','song-poetry','','[]','前時著脚清凈坊，山童殷勤進山茗。',256,'全唐诗/poet.song.204000.json','["前時著脚清凈坊，山童殷勤進山茗。", "半杯春雲滿晴空，午困瞢騰頓能醒。", "山深有鳥聲清圓，俗名搗藥頗堪聽。", "從來不起市朝想，定亦久知存所性。", "何如搗茶伴老衲，疾病去盡竟歸正。", "數株寒菊带秋清，一篆香烟留日永。", "顧我服官走芳塵，心雖超悟力未猛。", "氣猿意馬難同防，未免稍縱肆頑獷。", "人言茶味怕齒知，日漸月漬遣胃冷。", "不然除膩立奇勳，氣象森嚴費忠鯁。", "建溪早芽細如鍼，來春喊聲徧山嶺。", "銅模新製號鳳團，絳紗斜紉護龍餠。", "竹窗拂拭金石堅，碾破霏霏光炯炯。", "舊曾識此今罕見，山茗一旗生舜井。", "冠裳不加貌自若，厥包斷不請僥倖。", "須知老衲定中人，任柳生肘木生癭。"]'),
('57369be6-c16a-4ddc-9371-fd70eae62356','獨孤憲公檜','張侃','宋','宋诗','song-poetry','','[]','古人聲名期不朽，一言之謬如此酒。',128,'全唐诗/poet.song.204000.json','["古人聲名期不朽，一言之謬如此酒。", "今人隨世就聲名，浮雲變滅無不有。", "詎知老杜可歎詩，爭似憲公當陛奏。", "文章遠繼商周作，氣骨已逼秋山秀。", "晚分符竹行其志，務在人民安𤱶畝。", "仁聲既遠姓氏傳，遺跡常存鬼神守。", "老檜槎枒枝榦古，參天黛色猶衝斗。", "終然依附得聲名，孰謂今人不如否。"]'),
('ec5fcccb-7cb4-4081-b8a3-6b5eafc47248','立冬後述情','張侃','宋','宋诗','song-poetry','','[]','山城並水寒較早，鴛瓦新霜寫花草。',64,'全唐诗/poet.song.204000.json','["山城並水寒較早，鴛瓦新霜寫花草。", "五朝三朝風蕭蕭，九日十日雲飄飄。", "秋將歸去冬又至，寒色不遮萬山翠。", "小窗倚徙片時間，有美人兮隔江水。"]'),
('b17e898b-22d4-4a44-8471-18201c44b22f','田家歲晚','張侃','宋','宋诗','song-poetry','','[]','田家舂米盛土倉，祠竈新鱠鯉與魴。',96,'全唐诗/poet.song.204000.json','["田家舂米盛土倉，祠竈新鱠鯉與魴。", "粥分口數顧長健，不賣癡呆儂自當。", "爇火照天田蠶好，打灰如願從所禱。", "一聲竹爆陽春回，城裏看燈歸已曉。", "我生把筆作耕鋤，年餘三十腹空虛。", "不如爾農隨分足，只怕門前人催租。"]'),
('72c6b14a-c48e-42b7-8ff1-d11e9ce06133','石人行','張侃','宋','宋诗','song-poetry','','[]','君不見深閨有女禮自防，心事炯然並秋霜。',131,'全唐诗/poet.song.204000.json','["君不見深閨有女禮自防，心事炯然並秋霜。", "江頭日日望夫壻，願身成石立道傍。", "人傳其下多風雨，天地默與之低昂。", "靈犀一點磨不盡，歷歲既遠名獨香。", "因思萬物皆歸寓，獨許頑質加冠裳。", "刻形肖貌此何態，儼然如在端而莊。", "惜哉愚俗竟莫儗，翁媼同處天一方。", "嗚呼翁媼計雖得，胡不爲柱支明堂。"]'),
('f806bed5-f69c-4b2f-af23-9a569ba6564c','纂風浦','張侃','宋','宋诗','song-poetry','','[]','短茅黄瓦排門戶，祖父從來在此住。',96,'全唐诗/poet.song.204000.json','["短茅黄瓦排門戶，祖父從來在此住。", "不思城市好風光，只要秋成有分數。", "年年借本事荒田，探前望後庶有補。", "海門相近潮吐吞，不似今番難撐拄。", "夏初幼婦生小孫，嚶咿作聲求飼乳。", "婦饑苦語出肝腸，摇頭怕說纂風浦。"]'),
('686f790c-e4c1-4286-8cfd-8f673f9a468d','喜雪童謠','張侃','宋','宋诗','song-poetry','','[]','屋上三日留乾雪，添得人間訝奇絕。',64,'全唐诗/poet.song.204000.json','["屋上三日留乾雪，添得人間訝奇絕。", "不須待伴窘風雨，只要呈祥了時節。", "小兒戲拾疑是花，舞低婆娑最堪誇。", "最堪誇處漸堆積，生寒到骨思歸家。"]'),
('fd9e2b15-8cc4-42cc-afd3-62001c0c510b','雪飛不已戲作長歌','張侃','宋','宋诗','song-poetry','','[]','清溪怒號多北風，乞水來自河伯宮。',128,'全唐诗/poet.song.204000.json','["清溪怒號多北風，乞水來自河伯宮。", "多應飛雨作寒色，呼吸雲氣鞭癡龍。", "冬深萬木凍欲折，那有卉藥成纖洪。", "造化小兒一餉戲，鎪瓊鏤玉何其工。", "庭前婆娑萬花舞，春意已徧翡翠叢。", "可憐世情多冷眼，怨咨竟欲訟天工。", "了知妙處不用力，豈爲汝輩眼目供。", "明朝晴烏耀燭龍，向之幻景須臾空。"]'),
('4b2f82ab-a923-47b2-8e36-dbd06dfc37f8','止雪用東坡先生韻','張侃','宋','宋诗','song-poetry','','[]','常年有句吟雨葉，今年只了吟飛雪。',160,'全唐诗/poet.song.204000.json','["常年有句吟雨葉，今年只了吟飛雪。", "社中誰是錦繡腸，令我褫氣歎妙絕。", "固知天運陰陽戾，那問家園花草折。", "逞妍妬舞費斑鏤，幻色潛光亦消滅。", "前時有句送渠歸，日華摇金雲暗掣。", "滕家娘子躭清游，瑣碎回風到簾纈。", "只須頭次陣堂堂，底用十番空屑屑。", "民家朿縕带濕炊，醉客糜金謾飛瞥。", "海隠來徵鶴隠句，恰如白佛偈重說。", "昏霾未見天清明，石炭儗鑄一寸鐵。"]'),
('cbbcf4cb-661a-421c-8031-274de50ed236','梅','張侃','宋','宋诗','song-poetry','','[]','江梅有遠韻，不與世浮沈。',48,'全唐诗/poet.song.204000.json','["江梅有遠韻，不與世浮沈。", "誦我壁間句，知渠歲晚心。", "疎花生古意，暖艷啅幽禽。", "此處知誰解，霜天啟角音。"]'),
('39e6f04f-3620-4bf1-a7f2-94d49d5392ab','時雨三首  其一','張侃','宋','宋诗','song-poetry','','[]','旬日風消雨，今朝山出雲。',48,'全唐诗/poet.song.204000.json','["旬日風消雨，今朝山出雲。", "柳深開潤色，荷靚匝清芬。", "江燕新調語，沙鷗自引羣。", "農人相賀語，田畝可耕耘。"]'),
('054cbf81-82bd-4f13-96e6-e68b4cc9b8d8','時雨三首  其二','張侃','宋','宋诗','song-poetry','','[]','時雨催農事，庭陰散午凉。',48,'全唐诗/poet.song.204000.json','["時雨催農事，庭陰散午凉。", "地寬平野色，雲密閟林光。", "送目孤村外，舒情小艇旁。", "斜暉猶返照，何必問商羊。"]'),
('14314e58-c02b-4394-bf5d-b759a1c0d4f4','時雨三首  其三','張侃','宋','宋诗','song-poetry','','[]','矮屋原卑濕，頹牆上古苔。',48,'全唐诗/poet.song.204000.json','["矮屋原卑濕，頹牆上古苔。", "世間多少事，眼下兩三杯。", "詩卷無人惜，凉船有客來。", "明朝梅已斷，只是一聲雷。"]'),
('aecdfc67-d3ac-450a-98b7-3a739b7ce397','游西湖李氏園池','張侃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖水平春色，名園接杳微。',48,'全唐诗/poet.song.204000.json','["湖水平春色，名園接杳微。", "輕風生翠影，細雨醒香霏。", "意足休嫌野，身閒不受鞿。", "隔舟多妓女，歌逐片雲飛。"]'),
('208b2e57-8b58-40e4-8df7-154961f471d8','歸鴈亭逢所知','張侃','宋','宋诗','song-poetry','','[]','歸鴈亭前別，于今又五年。',48,'全唐诗/poet.song.204000.json','["歸鴈亭前別，于今又五年。", "水深涵落日，春晚尚餘妍。", "把酒聽吳曲，浮家入楚天。", "秋風遞消息，爲問有書傳。"]'),
('3c7e0db3-2edf-42ca-a894-2bf8def6dde1','黄龍洞','張侃','宋','宋诗','song-poetry','','[]','傳道黄龍穴，深藏不測淵。',48,'全唐诗/poet.song.204000.json','["傳道黄龍穴，深藏不測淵。", "翠藤依壽木，石壁隔塵緣。", "恐有神仙分，來觀古洞天。", "善權知不遠，雙鶴舞胎仙。"]'),
('06cdac4c-8b55-42e0-9b60-68ab50cc90de','何道兩山','張侃','宋','宋诗','song-poetry','','[]','兩山青不盡，吾眼未曾經。',48,'全唐诗/poet.song.204000.json','["兩山青不盡，吾眼未曾經。", "問法維摩室，留名處士星。", "地深藏白霧，天遠納蒼冥。", "我亦倦游者，何時結草亭。"]'),
('7fe792f7-fce3-4291-a85a-89ff444553cc','秀州城外','張侃','宋','宋诗','song-poetry','','[]','月色明于晝，閒登百步橋。',48,'全唐诗/poet.song.204000.json','["月色明于晝，閒登百步橋。", "天低雲宿野，地遠水通潮。", "吹笛回賓鴈，彎弓絆落鵰。", "年來無片善，所得是風標。"]'),
('9200f837-073e-4891-ae61-c563d4b07440','初秋夜坐  其一','張侃','宋','宋诗','song-poetry','','[]','酷暑秋仍有，臨流興未忘。',48,'全唐诗/poet.song.204000.json','["酷暑秋仍有，臨流興未忘。", "好風吹過雨，午夜得新凉。", "促織聲偏細，舂鋤立自雙。", "人生隨處好，最好是家鄉。"]'),
('b0a1fdbd-c158-4ecc-8d3a-1663b9b309de','初秋夜坐  其二','張侃','宋','宋诗','song-poetry','','[]','夜深天籟息，露重月華新。',48,'全唐诗/poet.song.204000.json','["夜深天籟息，露重月華新。", "此去何須懶，從來只任真。", "入秋山有色，積雨水生粼。", "萬事乘除耳，一樽聊可親。"]'),
('fe540425-d034-4c35-baf7-f2ed299a333f','雨','張侃','宋','宋诗','song-poetry','','[]','傍海風先冷，殘秋雨漸疎。',48,'全唐诗/poet.song.204000.json','["傍海風先冷，殘秋雨漸疎。", "柳凋閒摶黍，水凈見舂鋤。", "游客惟筇竹，民家半草居。", "近時潮候訊，玉筯當園蔬。"]'),
('adc4d328-85c1-4f51-a089-4cdf9bd53d53','明心院','張侃','宋','宋诗','song-poetry','','[]','村東古蘭若，門徑久荒凉。',48,'全唐诗/poet.song.204000.json','["村東古蘭若，門徑久荒凉。", "鸛舞風幡小，蛩吟露葉黄。", "潮音隨法轉，茗盌怕詩忙。", "一片牆根石，無人爲發揚。"]'),
('5ecb199b-3042-4653-a523-72612e326957','嘲絡緯','張侃','宋','宋诗','song-poetry','','[]','時序方中伏，簷前絡緯鳴。',48,'全唐诗/poet.song.204000.json','["時序方中伏，簷前絡緯鳴。", "凉風雖暫至，秋氣未全清。", "荷葉綠偏斷，芙蓉錦漸成。", "勸渠莫多事，促織又司衡。"]'),
('c1fd19f5-79dd-449a-af79-9e141b5e4d1a','中夜起坐納凉','張侃','宋','宋诗','song-poetry','','[]','風迅中宵起，簷虛入戶凉。',48,'全唐诗/poet.song.204000.json','["風迅中宵起，簷虛入戶凉。", "一輪明月影，八尺綠筠牀。", "久望重梅雨，閒尋晚芰香。", "天河漸分曉，結語問牛郎。"]'),
('8c4d03d6-2762-49be-9311-6e0c5e66cfed','趙紫芝詩卷','張侃','宋','宋诗','song-poetry','','[]','天樂無他好，精神盡在詩。',48,'全唐诗/poet.song.204000.json','["天樂無他好，精神盡在詩。", "墓藏山色遠，語到水心知。", "名極天還妬，身亡道自垂。", "勿嫌官職小，君復鶴相隨。"]'),
('488d2a8f-f819-4aae-a022-cd4c5aab00c2','周晉仙詩卷','張侃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晉仙新寺住，曉夕在吟邊。',48,'全唐诗/poet.song.204000.json','["晉仙新寺住，曉夕在吟邊。", "相去二三里，聞名五七年。", "西湖聽鴈夜，霅水釣魚天。", "語逸山精泣，宜爲萬古傳。"]'),
('140f2383-93a7-4cb1-8596-c016e613e209','柳下詩卷','張侃','宋','宋诗','song-poetry','','[]','退之名振世，無本肯從游。',48,'全唐诗/poet.song.204000.json','["退之名振世，無本肯從游。", "既以吾儒重，方知異說休。", "不才空剩語，馳譽勝荒丘。", "朴老深于律，遺篇處處留。"]'),
('9194832f-30fc-4b85-814b-01ea51e76b26','偶成','張侃','宋','宋诗','song-poetry','','[]','細雨遲春色，閒雲接曉天。',48,'全唐诗/poet.song.204000.json','["細雨遲春色，閒雲接曉天。", "清時依薄宦，秀句近華牋。", "地冷梅枝少，川明竹影圓。", "翻思年少日，折柳繫漁船。"]'),
('27149b2a-bf0d-45c1-a6bd-f6b89353a1c2','花事','張侃','宋','宋诗','song-poetry','','[]','立春踰十日，猶未見芳菲。',48,'全唐诗/poet.song.204000.json','["立春踰十日，猶未見芳菲。", "雲葉垂垂滿，簷絲緩緩飛。", "池魚寒未上，林鴈暖方歸。", "因靜無思慮，由人論瘠肥。"]'),
('77227315-bc6b-4b01-9fda-014c93b34e7f','芍藥','張侃','宋','宋诗','song-poetry','','[]','春意垂垂盡，名花續續開。',48,'全唐诗/poet.song.204000.json','["春意垂垂盡，名花續續開。", "誰知傾國色，元未著香埃。", "曾向蕪城見，還驚茗水來。", "貪看詩律細，忘覆掌中杯。"]'),
('1f328d86-5390-4f5c-8ef0-df243b836d37','春盡','張侃','宋','宋诗','song-poetry','','[]','韶光餘十日，明歲又重來。',48,'全唐诗/poet.song.204000.json','["韶光餘十日，明歲又重來。", "柳外黄鸝怨，山中杜宇催。", "一番風送雨，幾處錦成堆。", "且飲深杯酒，携筇緩緩回。"]'),
('9d19d74c-9cea-443e-a16b-e5dbad80bd06','隠者','張侃','宋','宋诗','song-poetry','','[]','山蹊通綫道，舊有隠人居。',48,'全唐诗/poet.song.204000.json','["山蹊通綫道，舊有隠人居。", "生計多藏芋，秋盤近薦魚。", "簷牙松得壽，籬角草堪鋤。", "只欲逢熙運，誰能更上書。"]'),
('dca62d87-3a77-4949-9f7f-10fefbb537f4','雨後','張侃','宋','宋诗','song-poetry','','[]','雨後秋容穉，雲游日色微。',48,'全唐诗/poet.song.204000.json','["雨後秋容穉，雲游日色微。", "遠山依舊瘦，汙水已新肥。", "燕子稀疎舞，螢光冷淡飛。", "官閒清到骨，無是亦無非。"]'),
('f7c1e44c-37ce-4e1a-bb61-16188c04f77d','秋色','張侃','宋','宋诗','song-poetry','','[]','野闊因秋見，山高入霧微。',48,'全唐诗/poet.song.204000.json','["野闊因秋見，山高入霧微。", "曉看天色暝，午更宿陰圍。", "有地堪容隠，無言且息機。", "爲知閒處好，不是厭輕肥。"]'),
('5d3a785f-81cd-46bf-82f6-e0e9e524396f','夜宿','張侃','宋','宋诗','song-poetry','','[]','舟宿隄邊寺，天虛露氣清。',48,'全唐诗/poet.song.204000.json','["舟宿隄邊寺，天虛露氣清。", "秋從今夜冷，月比舊時明。", "水鳥紛紛下，墟煙冉冉輕。", "田家生計好，不逐世間名。"]'),
('a16a2e63-2c1c-4599-9143-2536465114d2','家園夜月','張侃','宋','宋诗','song-poetry','','[]','荒畦多古木，月送影婆娑。',48,'全唐诗/poet.song.204000.json','["荒畦多古木，月送影婆娑。", "須信閒中好，翻嫌塵事多。", "簷低排遠岫，堂近俯清波。", "夜靜頻來往，漁樵互奏歌。"]'),
('03832860-0e22-4175-9f56-bb47864c1fd4','來鴈','張侃','宋','宋诗','song-poetry','','[]','雲外新來鴈，風回字倒看。',48,'全唐诗/poet.song.204000.json','["雲外新來鴈，風回字倒看。", "深知吳地暖，生怕塞天寒。", "水國沙汀遠，西疇稻粒殘。", "排羣宜穩睡，報夜喜平安。"]'),
('1e8eef68-9f19-432c-944e-6d2cafa70717','宵征','張侃','宋','宋诗','song-poetry','','[]','澗遠泉聲激，山回月影重。',48,'全唐诗/poet.song.204000.json','["澗遠泉聲激，山回月影重。", "宵征滿凉意，曉色带秋容。", "衣薄初霑露，橋陰久傍松。", "茅簷因雨濕，催織是鳴蛩。"]'),
('8c43ab4f-9593-4317-bbf4-24cb3ef50a8a','伯牙瀆','張侃','宋','宋诗','song-poetry','','[]','古賢真好事，瀆以伯牙名。',48,'全唐诗/poet.song.204000.json','["古賢真好事，瀆以伯牙名。", "岸轉天無盡，春回草漸榮。", "當年流水曲，今日賦詩情。", "可惜知音少，令人恨未平。"]'),
('dab3b1ca-fd70-4f63-89c5-bb65fafaa14a','張涇匯','張侃','宋','宋诗','song-poetry','','[]','我閒尋勝槩，人自號荒郊。',48,'全唐诗/poet.song.204000.json','["我閒尋勝槩，人自號荒郊。", "木老含生意，橋迂接水坳。", "浴鳬歸艇集，戲蝶野花梢。", "汎宅吾宗遠，虛勞歎繫匏。"]'),
('d79c3fbb-0571-4ab1-851e-a8535dddcdf6','穀日  其一','張侃','宋','宋诗','song-poetry','','[]','姬旦陳王業，農官報歲功。',48,'全唐诗/poet.song.204000.json','["姬旦陳王業，農官報歲功。", "新晴春滿野，宿霧曉披空。", "賣卜煩鄰叟，知時訪老翁。", "更須圖夕雨，土脈盡豐融。"]'),
('9e912b2a-7ac9-4dd4-b6f2-37af9c8cfe26','穀日  其二','張侃','宋','宋诗','song-poetry','','[]','欲識田家趣，清溪曲抱村。',48,'全唐诗/poet.song.204000.json','["欲識田家趣，清溪曲抱村。", "齊民當日術，學稼古人言。", "瑞實歸千室，餘功到小園。", "元機亭育際，始見道尤尊。"]'),
('5b99463e-9d1f-4edd-afab-4294858ebfe6','夜宿育王莊北窗','張侃','宋','宋诗','song-poetry','','[]','破壁排矮窗，新篁出粉牆。',48,'全唐诗/poet.song.204000.json','["破壁排矮窗，新篁出粉牆。", "開尊侵綠色，得雨借初凉。", "名保千年在，身安萬念忘。", "詩情亦漫興，何暇細商量。"]'),
('ead7e292-74f1-4e67-9784-47ee3b6bdaa8','再用韻促季文結水邊亭','張侃','宋','宋诗','song-poetry','','[]','一朝飛驥足，十載歎龜藏。',48,'全唐诗/poet.song.204000.json','["一朝飛驥足，十載歎龜藏。", "臨水軒亭好，逢人笑語凉。", "須先心地遠，莫厭斧聲忙。", "未數漳南景，裁詩拂蘚蒼。"]'),
('ee038b87-4091-42d3-b8f5-493f6face71a','寄題富沙倅廨靜凉亭詩','張侃','宋','宋诗','song-poetry','','[]','南中多暑氣，來覓靜凉詩。',48,'全唐诗/poet.song.204000.json','["南中多暑氣，來覓靜凉詩。", "但得政無擾，自然民不欺。", "亭中人藴藉，欄外水漣漪。", "想見賓朋過，銜杯樂聖時。"]'),
('e4ed9860-3d64-40cd-b8b6-44ba783a80b3','和朱季文即事','張侃','宋','宋诗','song-poetry','','[]','種竹多臨水，山隨雲影藏。',48,'全唐诗/poet.song.204000.json','["種竹多臨水，山隨雲影藏。", "夏深元有暑，秋淺未全凉。", "箇箇飛螢入，雙雙歸燕忙。", "幾年觀物理，不復叩員蒼。"]'),
('336ae057-b2b0-40a1-b122-23b872f2b94c','將歸','張侃','宋','宋诗','song-poetry','','[]','將歸浮小艇，水色綠添痕。',48,'全唐诗/poet.song.204000.json','["將歸浮小艇，水色綠添痕。", "楊柳迷低岸，鶑花滿舊園。", "日長迎雨燕，沙暖起風鴛。", "眼界須當闊，臨溪築小軒。"]'),
('d4c8d5b7-a853-4edd-a83a-b34cd6f65f55','歲晚','張侃','宋','宋诗','song-poetry','','[]','水斂風生壑，雲深雪滿天。',48,'全唐诗/poet.song.204000.json','["水斂風生壑，雲深雪滿天。", "寒光憐袖薄，瑞色向梅妍。", "淺酌生春酒，閒賡餽歲篇。", "吹燈看家信，獨步到窗前。"]'),
('2e157b30-c019-42dc-8522-1a89e66b5b8c','拙軒偶書三首  其一','張侃','宋','宋诗','song-poetry','','[]','歸來開一室，復以拙爲名。',48,'全唐诗/poet.song.204000.json','["歸來開一室，復以拙爲名。", "道在何妨小，身閒不用榮。", "柳絲愁斷續，花靨笑輕盈。", "只此觀天運，逢時物自成。"]'),
('6381ce40-602c-4802-814f-e33a724d990a','拙軒偶書三首  其二','張侃','宋','宋诗','song-poetry','','[]','廊深人罕到，益友兩三人。',48,'全唐诗/poet.song.204000.json','["廊深人罕到，益友兩三人。", "得意文章妙，相忘情味真。", "蜂來窺硯水，燕去潤香芹。", "如此逍遥過，胸中無點塵。"]'),
('4e7ebbd5-2751-4819-948b-120dcbe01aab','拙軒偶書三首  其三','張侃','宋','宋诗','song-poetry','','[]','侵晨門外立，山色已浮春。',48,'全唐诗/poet.song.204000.json','["侵晨門外立，山色已浮春。", "斫竹流溪水，提籃擇細鱗。", "柳濃將作絮，梅小未生仁。", "自拆紅泥酒，歌呼到北鄰。"]'),
('164cbc32-0bb6-466c-8a18-f22193ee99d0','足軒','張侃','宋','宋诗','song-poetry','','[]','人爵何須戀，翛然郭外居。',48,'全唐诗/poet.song.204000.json','["人爵何須戀，翛然郭外居。", "隨緣常二滿，散帙富三餘。", "劖石梅花賦，堆庭柿葉書。", "呼兒邀客至，反櫂或巾車。"]'),
('fed9be04-4527-49ef-aa83-0597325fa2dc','定軒','張侃','宋','宋诗','song-poetry','','[]','門前流水競，洗盡市塵交。',48,'全唐诗/poet.song.204000.json','["門前流水競，洗盡市塵交。", "秉我中心正，從渠異說譊。", "向來多肘柳，近已去心茅。", "隠几觀天地，晨曦動翠梢。"]'),
('d9c86fcb-e606-4d6a-8209-5f08a563f914','十月初五日自白門之丹陽宿於驛亭中是夕風雪大作','張侃','宋','宋诗','song-poetry','','[]','輾轉耿不寐，青燈遥夜闌。',48,'全唐诗/poet.song.204000.json','["輾轉耿不寐，青燈遥夜闌。", "關河千里遠，風雪一窗寒。", "旅食腰圍減，征鞍髀肉酸。", "想知雙鶴髮，朝夕望平安。"]'),
('9e2a36a3-f79a-46d6-b54c-c2074d892a04','感昔','張侃','宋','宋诗','song-poetry','','[]','先君年壯日，邂逅鄭當時。',48,'全唐诗/poet.song.204000.json','["先君年壯日，邂逅鄭當時。", "把酒對今月，彈琴論古詩。", "眼前多俗韻，徽外少人知。", "除却瑶山老，無繇訪斷碑。"]'),
('5b5a94b6-81e9-4343-aeec-ecd4759cf8ab','正月尾雪','張侃','宋','宋诗','song-poetry','','[]','今歲春來晚，晴寒比舊添。',48,'全唐诗/poet.song.204000.json','["今歲春來晚，晴寒比舊添。", "雲深天欲雪，風定瓦堆鹽。", "幽艷迷瓊屑，前山隠翠尖。", "詩人疑是瑞，就喚野人占。"]'),
('2afdb526-6dc6-4093-b735-c156e4d3a2a4','觀薌林堂帖','張侃','宋','宋诗','song-poetry','','[]','功名落落俟天時，險阻艱難定漢基。',64,'全唐诗/poet.song.204000.json','["功名落落俟天時，險阻艱難定漢基。", "老子掛冠從早歲，諸公頌德盡良規。", "既知中夏馳清譽，合去薌林賦好詩。", "事到百年方始定，晴窗細與拂烏絲。"]'),
('d3e883b5-6410-4500-8c86-791180c87d65','新晴','張侃','宋','宋诗','song-poetry','','[]','披披雲陣從東去，薄薄晨光向北開。',64,'全唐诗/poet.song.204000.json','["披披雲陣從東去，薄薄晨光向北開。", "花態最嬌依宿靄，柳枝無力輥香埃。", "心清更覺虛簷遠，事少緣無俗客來。", "野鳥互吟閒自在，三三兩兩啄莓苔。"]'),
('7ab8d939-271d-488a-9b9c-3bbab3cfcf47','夜坐','張侃','宋','宋诗','song-poetry','','[]','青燈點粟伴窗幽，檢盡詩篇倦即休。',64,'全唐诗/poet.song.204000.json','["青燈點粟伴窗幽，檢盡詩篇倦即休。", "萬事如雲同舞燕，此心似水羨飛鷗。", "客來不過談閒事，我壯須當辦小舟。", "雨雜風聲欺客枕，清眠無夢兩悠悠。"]'),
('315da361-72e9-4c1b-bdd8-64cc1a2fc73c','久雨','張侃','宋','宋诗','song-poetry','','[]','今年梅雨已淋漓，梅盡多時雨意癡。',64,'全唐诗/poet.song.204000.json','["今年梅雨已淋漓，梅盡多時雨意癡。", "漫說池荷能潤色，豈知岸柳亦顰眉。", "一天黯黮雲陰殢，六月清凉客子宜。", "兀坐小樓香半綫，紛紜萬事只心知。"]'),
('cd744a77-89d2-474c-9c92-65c441d87c52','梁湖夜望','張侃','宋','宋诗','song-poetry','','[]','秋带凉風葉互鳴，風隨潮汐候時生。',64,'全唐诗/poet.song.204000.json','["秋带凉風葉互鳴，風隨潮汐候時生。", "導源甚遠紋微起，乘勢初來花轉輕。", "白鷺幾枝閒可畫，晴山數點曉猶明。", "偶來又作詩中計，久矣難成五字城。"]'),
('9fde7287-ee69-495c-ac09-5ecc2caaa263','和中秋韻','張侃','宋','宋诗','song-poetry','','[]','月魄詩魂兩鬭清，却嫌歌管揭危亭。',64,'全唐诗/poet.song.204000.json','["月魄詩魂兩鬭清，却嫌歌管揭危亭。", "遥知山鬼形難遯，誰洗天公眼暫明。", "物外風光何皛皛，人間爝火謾熒熒。", "酒狂徑欲騎鯨去，一拂鴻蒙散窅冥。"]'),
('ea0a8512-7907-4e62-8dd2-41bb5d35e765','奉寄曾舜卿二首  其一','張侃','宋','宋诗','song-poetry','','[]','我與懶翁非淺交，向來寓止在西郊。',64,'全唐诗/poet.song.204000.json','["我與懶翁非淺交，向來寓止在西郊。", "繞庭草際綠浮色，滿檻花梢紅解苞。", "只要同心勝膠漆，豈緣一字倩推敲。", "四年會面休深歎，辛苦揚雄述解嘲。"]'),
('46f65723-9510-4565-ab27-b9ca39ac88be','奉寄曾舜卿二首  其二','張侃','宋','宋诗','song-poetry','','[]','一幅吳牋秋滿天，幾回書字欠人傳。',64,'全唐诗/poet.song.204000.json','["一幅吳牋秋滿天，幾回書字欠人傳。", "知君性懶存吾道，顧我官閒只舊年。", "詩句鍊成猶未穩，酒杯空泛未曾傳。", "庭前柏子西來意，近日能明若箇禪。"]'),
('4e6f0294-fd11-47e4-8a3e-e2d1e1aeb32e','寄曾兄','張侃','宋','宋诗','song-poetry','','[]','富貴功名莫問渠，閒中氣味復何如。',64,'全唐诗/poet.song.204000.json','["富貴功名莫問渠，閒中氣味復何如。", "年來格外添新句，夜靜燈前理舊書。", "用拙不妨存我性，得時未免駕高車。", "君家文獻人難比，會見芳名上玉除。"]'),
('dbd600a5-87dd-487b-aab2-b939c1fdef7a','次王子元韻二首  其一','張侃','宋','宋诗','song-poetry','','[]','眼看珠玉混泥塗，奇貨何人解與居。',64,'全唐诗/poet.song.204000.json','["眼看珠玉混泥塗，奇貨何人解與居。", "賣劍買牛知已晚，壞車殺馬計何疎。", "卑飛莫辨雞羣鶴，高義難兼熊掌魚。", "却羨臨川王介甫，愛君獨上萬言書。"]'),
('1668db9d-8da8-45d5-bce1-7cc296b1585a','次王子元韻二首  其二','張侃','宋','宋诗','song-poetry','','[]','皮骨三年走道塗，移文良負北山居。',64,'全唐诗/poet.song.204000.json','["皮骨三年走道塗，移文良負北山居。", "甘貧我固輕諸阮，勇退吾猶恥二疏。", "好著短衣看射虎，休彈長劍爲無魚。", "人生識字多憂患，飽睡從今莫讀書。"]'),
('238b43f5-4896-4aae-bd80-637cf503e8b7','用秦少游韻二首  其一','張侃','宋','宋诗','song-poetry','','[]','春風花草繡林皋，索莫誰憐止酒陶。',64,'全唐诗/poet.song.204000.json','["春風花草繡林皋，索莫誰憐止酒陶。", "晚學文章真末技，早知州縣亦徒勞。", "年光可歎石中火，人事休磨笑裏刀。", "分外更須貪富貴，如求兔角與龜毛。"]'),
('b2ce5bac-a076-4292-9343-226e0a3ee2ef','用秦少游韻二首  其二','張侃','宋','宋诗','song-poetry','','[]','未工射雉怯如皋，欲掛衣冠慕老陶。',64,'全唐诗/poet.song.204000.json','["未工射雉怯如皋，欲掛衣冠慕老陶。", "莫爲功名多戚戚，須知身世兩勞勞。", "求魚切戒空緣木，買犢不妨先賣刀。", "未有田園作歸計，年來留滯感潘毛。"]'),
('1c2ae5ff-8159-486b-8a9e-aa2956479ad2','戲用東坡先生韻二首  其一','張侃','宋','宋诗','song-poetry','','[]','冠世文章李翰林，掀天功業漢淮陰。',64,'全唐诗/poet.song.204000.json','["冠世文章李翰林，掀天功業漢淮陰。", "抹靴捧硯榮雖甚，受鉞登壇眷益深。", "遠竄夜郎揮老淚，生擒雲夢負初心。", "窮泉二子應追恨，不解君前早脫簪。"]'),
('de9f6087-00f1-4d0c-bd53-2475c5115a9b','戲用東坡先生韻二首  其二','張侃','宋','宋诗','song-poetry','','[]','倦看冠蓋閙如林，夢想扁舟破晚陰。',64,'全唐诗/poet.song.204000.json','["倦看冠蓋閙如林，夢想扁舟破晚陰。", "步月南樓情不淺，卧風北牖味殊深。", "朱旂黄紙非吾事，木板青衫負壯心。", "游宦半生成底事，鬢絲零落不勝簪。"]'),
('f6854e33-49ad-4097-9e10-114a6ab3ae4e','豚犬夜誦東坡贈王子直詩堅索次韻余率然成章可笑深不自量也','張侃','宋','宋诗','song-poetry','','[]','年來典盡鷫鸘裘，遠宦深慚馬少游。',64,'全唐诗/poet.song.204000.json','["年來典盡鷫鸘裘，遠宦深慚馬少游。", "痛哭恨無裨國論，偷安終不爲身謀。", "誰憐饑虎空摇尾，却羨寒龜暗縮頭。", "但得渭川千畝竹，也勝霜鬢取封侯。"]'),
('38fa42e5-07c7-4cd8-905e-f2c03535b8e9','田元長和煙字韻詩見寄復用前韻','張侃','宋','宋诗','song-poetry','','[]','幾年無夢到凌煙，身似春蠶已再眠。',64,'全唐诗/poet.song.204000.json','["幾年無夢到凌煙，身似春蠶已再眠。", "寡合荆人和白雪，獨醒蜀道上青天。", "漁樵好去任爭席，富貴儻來羞執鞭。", "見說高真足官府，不妨長作地行仙。"]'),
('5c7ddc96-7b35-48c5-b29f-20803674642c','用文伯起韻','張侃','宋','宋诗','song-poetry','','[]','老人癡鈍性可憎，微子誰與爲友朋。',64,'全唐诗/poet.song.204000.json','["老人癡鈍性可憎，微子誰與爲友朋。", "久廢未容收顙馬，一呼寧復責饑鷹。", "無緣下榻留徐孺，好去登門訪李膺。", "吾道不行吾已矣，短桴浮海要同乘。"]'),
('27fe63ff-bd41-47f9-8f35-b7e8d9981b8a','和曾舜卿秋日偶成','張侃','宋','宋诗','song-poetry','','[]','久無名酒共君傾，靜對溪山悅我情。',64,'全唐诗/poet.song.204000.json','["久無名酒共君傾，靜對溪山悅我情。", "雨沁荷花多退色，風穿梧葉强成聲。", "乾坤納納從來大，歲月堂堂未用驚。", "甚欲著書傳後世，只愁議論太平平。"]'),
('96efdd96-a5e2-418f-9b1c-1ad6abf243d1','樓源清叔舊有詩云樹冷鴉啼月天寒鴈带雲曾舜卿足成四韻又有詠雪詩云來從天外無非雨散在人間盡是花亦佳句也清叔死已數月因用後二句爲詩弔之','張侃','宋','宋诗','song-poetry','','[]','見說樓君用志佳，曾吟雪句被人誇。',64,'全唐诗/poet.song.204000.json','["見說樓君用志佳，曾吟雪句被人誇。", "來從天外無非雨，散在人間盡是花。", "偶到銅陵尋舊友，歸由宣郡棄生涯。", "碧雲暮合愁偏聚，孤塚纍纍日易斜。"]'),
('1f0f9392-01c3-4cfb-94ea-f1d35acf0972','甬東','張侃','宋','宋诗','song-poetry','','[]','侵晨風雨闇城樓，渺渺蒲帆海盡頭。',64,'全唐诗/poet.song.204000.json','["侵晨風雨闇城樓，渺渺蒲帆海盡頭。", "遠景暫煩雙目送，清游不負此生謀。", "半杯綠蟻衝寒色，幾箇白鷗分客愁。", "相近梅開遲雪舞，肯容興盡剡溪舟。"]'),
('77953cc1-98c5-4fc7-84a6-bc98b091ef29','池邊','張侃','宋','宋诗','song-poetry','','[]','簿書才了聽蜂衙，閒到池邊景漸佳。',64,'全唐诗/poet.song.204000.json','["簿書才了聽蜂衙，閒到池邊景漸佳。", "雲亦有心時散影，風都無力晚生花。", "勞神空覓三年艾，妄想休乘八月槎。", "睡思全清還解否，歙瓶新瀹建溪茶。"]'),
('43215b80-4db1-443b-bfb6-7e6b887e3959','書考  其一','張侃','宋','宋诗','song-poetry','','[]','二年薄宦在金臺，牆角雙扉向晚開。',64,'全唐诗/poet.song.204000.json','["二年薄宦在金臺，牆角雙扉向晚開。", "罕有金貂來換酒，且看野馬共浮埃。", "已書下考甘平進，久律吾身愧不才。", "却喜清貧如昨日，知心相識自然來。"]'),
('8bcdc603-e2c4-45ca-83ff-9f4ca176025d','書考  其二','張侃','宋','宋诗','song-poetry','','[]','負丞虞水恰年餘，誰信官居似野居。',64,'全唐诗/poet.song.204000.json','["負丞虞水恰年餘，誰信官居似野居。", "乍起柳風清午枕，久因梅雨理殘書。", "眼前毀譽何須較，酒裏功名定不虛。", "只把廉勤替疏拙，翻嫌苦苦學懸魚。"]'),
('bc6069a0-5812-4557-8e82-e30fd0fb0055','紅梅','張侃','宋','宋诗','song-poetry','','[]','天然標致出羣品，綠葉青枝說太狂。',64,'全唐诗/poet.song.204000.json','["天然標致出羣品，綠葉青枝說太狂。", "卯酒醺酣紅玉軟，春風觸撥瑞龍香。", "清臞尚餘山澤相，淡薄强隨時世粧。", "更道北人初不識，杏花應不敢承當。"]'),
('1f8dacf5-d6a3-4a37-ba85-aed34f07363c','春時','張侃','宋','宋诗','song-poetry','','[]','兩日閒爲汗漫游，谿邊長是喚扁舟。',64,'全唐诗/poet.song.204000.json','["兩日閒爲汗漫游，谿邊長是喚扁舟。", "杯盤草草同真率，笑語悠悠得細酬。", "別墅橋欹泥沒膝，東園亭小雨霑頭。", "不知桃李都開遍，更趁殘花一醉休。"]'),
('fad56004-80de-43d2-a251-ce9f896cd3a8','雨','張侃','宋','宋诗','song-poetry','','[]','一片雲飛雨趁來，常年此候捷如雷。',64,'全唐诗/poet.song.204000.json','["一片雲飛雨趁來，常年此候捷如雷。", "滿天盡黑都吹散，俄頃還明又復回。", "準擬却無真失望，等閒易有竟難猜。", "化工若念農辛苦，早賜傾盆亦快哉。"]'),
('f8569177-0ff7-49bc-a614-02f3b463dd0f','巧夕前一日雨','張侃','宋','宋诗','song-poetry','','[]','天時人事逐番新，轉盼初秋感慨頻。',64,'全唐诗/poet.song.204000.json','["天時人事逐番新，轉盼初秋感慨頻。", "月傍銀河移扇影，天留絲雨洗香塵。", "民間但欲逢豐歲，酒裏何妨換好春。", "一笑且隨吾意適，燕支菱芡伴盤珍。"]'),
('1a7cf5c5-e640-446a-a33a-f77ca243f481','偶書','張侃','宋','宋诗','song-poetry','','[]','事業從教下瀧舠，一年竊祿在江皋。',64,'全唐诗/poet.song.204000.json','["事業從教下瀧舠，一年竊祿在江皋。", "腥汙砧几憎蠅賦，愛護文書却鼠刀。", "風約浮萍雲疊岫，日藏老檜雨翻濤。", "深慚無補公家事，只願年豐弓載櫜。"]'),
('4f638310-5b15-4622-a791-ff610fcfc550','聞方孚若寺丞訃二首  其一','張侃','宋','宋诗','song-poetry','','[]','清時補外駕朱轓，德政碑成達帝閽。',64,'全唐诗/poet.song.204000.json','["清時補外駕朱轓，德政碑成達帝閽。", "都把功名垂竹帛，盡留官職付兒孫。", "生前花藥千株在，身後詞章幾卷存。", "履道宅邊雲黯黯，知誰挂劍酹清尊。"]'),
('88ee1167-eae2-481b-9837-c8f9b2e68eeb','聞方孚若寺丞訃二首  其二','張侃','宋','宋诗','song-poetry','','[]','憶昨家君出帥時，惟公英氣少人知。',64,'全唐诗/poet.song.204000.json','["憶昨家君出帥時，惟公英氣少人知。", "要除五事心常在，費盡千言氣不卑。", "渺渺淮波紛櫂檝，晶晶霜日照旌旗。", "論功未盡還知否，應有名賢爲立碑。"]'),
('fa38d349-f695-4a3b-9dd4-614145400f31','收潘廷亨逵訊','張侃','宋','宋诗','song-poetry','','[]','舊年淛右水連天，聞說閩中水亦然。',64,'全唐诗/poet.song.204000.json','["舊年淛右水連天，聞說閩中水亦然。", "官裏勸分雖遍及，民間慳糴爲無錢。", "大風拔木揚塵土，細雨打花空媚妍。", "甲子一晴差可喜，農家只願屢豐年。"]'),
('ad6835ba-60f6-451c-b955-ce87457f411e','題蕭照漁樵對語圖','張侃','宋','宋诗','song-poetry','','[]','世人大半愛漁樵，不道漁樵心志凋。',64,'全唐诗/poet.song.204000.json','["世人大半愛漁樵，不道漁樵心志凋。", "漫釣溪魚臨月夕，每沽村酒怕霜朝。", "檀欒男女衣藍縷，澹泊生涯舟蕩摇。", "偷得片時相對語，從頭至尾盡無聊。"]'),
('5f1a1b27-9328-4b1d-8dcc-ea17f109185f','閒中憶曾舜卿知丞','張侃','宋','宋诗','song-poetry','','[]','官舍如舟近古河，隔河老木尚新峨。',64,'全唐诗/poet.song.204000.json','["官舍如舟近古河，隔河老木尚新峨。", "森羅星象螢分度，經緯水紋魚擲梭。", "月滿秋容隨處好，風含凉意向人多。", "香蒲泉石供清翫，遥憶騷翁在澗阿。"]'),
('6a1fcb4d-a366-474c-bb50-9e260485c053','宿等慈僧房','張侃','宋','宋诗','song-poetry','','[]','小小禪房若箇寬，氎巾楮帳護幽閒。',64,'全唐诗/poet.song.204000.json','["小小禪房若箇寬，氎巾楮帳護幽閒。", "貪看天外雲千變，忘數簷前竹幾竿。", "老衲呪經祈雨切，臞翁煮粥當晨餐。", "早知一念能持靜，不學槐安蟻走盤。"]'),
('db063143-375d-4518-9f41-e6051e512feb','姑惡','張侃','宋','宋诗','song-poetry','','[]','一雙姑惡屋邊啼，飛入垂楊伴夕暉。',64,'全唐诗/poet.song.204000.json','["一雙姑惡屋邊啼，飛入垂楊伴夕暉。", "不悟形骸非昔日，但思怨恨沒休期。", "婦聞孄語猶翻悔，汝得佳名免此譏。", "事事直須存分義，從今緘口莫相疑。"]'),
('f8528f42-d6c0-42a8-a110-f1bed43cd550','冬晚','張侃','宋','宋诗','song-poetry','','[]','冬晴日暖如春天，墨雲忽過雨生寒。',64,'全唐诗/poet.song.204000.json','["冬晴日暖如春天，墨雲忽過雨生寒。", "定飛柳絮呈農瑞，未放梅花到酒樽。", "歷尾無多更舊歲，筆端不韻祇陳言。", "須臾刮地風聲壯，吹折南牆老竹根。"]'),
('85790e29-afde-4a19-909c-6f418af14abc','冬後書事','張侃','宋','宋诗','song-poetry','','[]','兀坐茅簷意自閒，哦詩因得數苔斑。',64,'全唐诗/poet.song.204000.json','["兀坐茅簷意自閒，哦詩因得數苔斑。", "一番雨過歸寒水，數片雲浮疊晚山。", "近日陰晴多不定，自來冷暖不相關。", "春深泛棹清溪上，穩釣漁村三兩灣。"]'),
('f16c6973-a936-4a8c-a9e9-04ff06d388c3','天機','張侃','宋','宋诗','song-poetry','','[]','汎觀物理任天機，莫泥春殘事遽非。',64,'全唐诗/poet.song.204000.json','["汎觀物理任天機，莫泥春殘事遽非。", "蝶粉鶑衣陰處泊，燕泥鷗雪雨中歸。", "裝成閒景真堪翫，寫入清吟細解圍。", "一榻凉風清午暑，拙翁睡起理絺衣。"]'),
('c9580646-df17-4263-9072-7a4e825d719b','同鄉人別朱希文察判于詠春亭','張侃','宋','宋诗','song-poetry','','[]','今春醵飲咏春亭，水闊山遥眼界清。',64,'全唐诗/poet.song.204000.json','["今春醵飲咏春亭，水闊山遥眼界清。", "前度來時多值雨，今番到此却逢晴。", "蠶方三幼餐乾葉，燕喜雙飛泊短楹。", "小別諸君休作惡，陽關四疊不須成。"]'),
('f57b5427-977e-4887-b7ea-5db69feb79d1','家園二首  其一','張侃','宋','宋诗','song-poetry','','[]','當年迂叟圃初成，野草閒花不記名。',64,'全唐诗/poet.song.204000.json','["當年迂叟圃初成，野草閒花不記名。", "康節巾車臨小徑，東坡詩板照高楹。", "久知氣象歸前輩，擬學規模愧後生。", "惟有至公能格物，莫將險躁起心兵。"]'),
('1424a1a7-222a-4184-a38d-cc33b3898916','家園二首  其二','張侃','宋','宋诗','song-poetry','','[]','堪笑吾家五畝園，新添石岸築雲軒。',64,'全唐诗/poet.song.204000.json','["堪笑吾家五畝園，新添石岸築雲軒。", "眼看流水清無底，面揖羣山翠欲奔。", "拂拂好風凉入座，娟娟明月影侵門。", "弟兄歲晚團欒處，自摘青蔬薦酒尊。"]'),
('e75663f8-b0b0-4f0b-b0cd-5b76351711a4','次韻韋中實雨悶','張侃','宋','宋诗','song-poetry','','[]','與世相違願不才，春殘花底尚銜杯。',64,'全唐诗/poet.song.204000.json','["與世相違願不才，春殘花底尚銜杯。", "詩從碧霧愁邊得，門向青山好處開。", "東里沈君投檄去，西鄰韋叟趁閒來。", "喜無俗駕知予懶，坐看庭陰閟古槐。"]'),
('bb6b40e6-b0c0-4238-981a-9eb06ac53644','偶成','張侃','宋','宋诗','song-poetry','','[]','前朝晴暖昨朝寒，細雨催花聲不閒。',64,'全唐诗/poet.song.204000.json','["前朝晴暖昨朝寒，細雨催花聲不閒。", "處處閉門掃蠶蟻，家家垂柳隠綿蠻。", "東灣泛艇看人渡，北埭扶筇向晚還。", "惟有羣山怕陳迹，輕煙冉冉薄螺鬟。"]'),
('3389bf49-9805-46e1-82b5-d909aaba9b08','虛庭','張侃','宋','宋诗','song-poetry','','[]','虛庭幽閴日陰移，旋拂藤牀近小池。',64,'全唐诗/poet.song.204000.json','["虛庭幽閴日陰移，旋拂藤牀近小池。", "雲自悠揚峰疊疊，風常和暖日漪漪。", "青衫漫仕安愚分，白酒初篘滿屈巵。", "竹外流螢三兩箇，微光猶足映書帷。"]'),
('eab7357b-c9f1-4c20-8ae6-c48830a4def1','西村','張侃','宋','宋诗','song-poetry','','[]','籃輿軋軋過西村，小麥青青雨露恩。',64,'全唐诗/poet.song.204000.json','["籃輿軋軋過西村，小麥青青雨露恩。", "山色無窮開遠近，民家守分度昕昏。", "僧精持課歸林下，客自携尊醉竹根。", "每日塵氛牽百念，要須結屋浸溪痕。"]'),
('eef9a558-c98a-45ee-9e3e-e27465b35025','南村','張侃','宋','宋诗','song-poetry','','[]','郁李花開春漸殘，海棠猶自映杯柈。',64,'全唐诗/poet.song.204000.json','["郁李花開春漸殘，海棠猶自映杯柈。", "燕隨風舞迎人暖，鳩喚雨來連夜寒。", "兩水中分清可燭，羣山環揖秀堪餐。", "兒童成隊逢寒食，紙剪飛鳶貼霧端。"]'),
('b4e5d317-b81f-49b2-81ee-80d80fdf579c','病起','張侃','宋','宋诗','song-poetry','','[]','秋深雨意轉連綿，聲到枯荷清未眠。',64,'全唐诗/poet.song.204000.json','["秋深雨意轉連綿，聲到枯荷清未眠。", "久悟是非姑掩卷，且看童稚互攤錢。", "園蔬土潤青堪饌，徑竹行疎翠可憐。", "賸喜病夫今已健，碧腴膏莫問人傳。"]'),
('7582ea2b-3e6d-47eb-be02-68fb3a54e779','象山住持僧于修求詩戲題五十六字','張侃','宋','宋诗','song-poetry','','[]','的知前聖定曾來，山脈深長景漸開。',64,'全唐诗/poet.song.204000.json','["的知前聖定曾來，山脈深長景漸開。", "霜幹都無新氣象，風幡不染舊塵埃。", "漁樵雖過何嘗問，父老相傳莫浪猜。", "慚愧修公堅有請，依前題作小天台。"]'),
('9f105d12-cc76-4b7a-a1ee-43e1a6a42083','催雪次韻韋中實','張侃','宋','宋诗','song-poetry','','[]','海隠方搜催雪詩，韋郎落筆補新辭。',64,'全唐诗/poet.song.204000.json','["海隠方搜催雪詩，韋郎落筆補新辭。", "雲邊花舞瓊千點，座上風流玉一枝。", "如許寒光宜應瑞，不勝幻色又添奇。", "政須瀹茗清靈府，盡把文章潤色之。"]'),
('6fe5571c-7582-4b76-b32b-97d586732481','溪上','張侃','宋','宋诗','song-poetry','','[]','水痕依綠四無邊，雨脚垂簷細更妍。',64,'全唐诗/poet.song.204000.json','["水痕依綠四無邊，雨脚垂簷細更妍。", "楊柳不遮愁處眼，牡丹猶倚醉時肩。", "紛紛燈火疑星燦，汩汩聲名類蟻旋。", "閒憑蓬窗仍感舊，開箱重爲整詩篇。"]'),
('95725bbf-6229-4d5c-9120-3cca01dbfd43','題剡溪圖','張侃','宋','宋诗','song-poetry','','[]','欲識詩清處，須來天盡頭。',24,'全唐诗/poet.song.204000.json','["欲識詩清處，須來天盡頭。", "可人一溪雪，催我上扁舟。"]'),
('33155695-da1c-41d5-b7cf-b7a0f75ed8fe','贈別','張侃','宋','宋诗','song-poetry','','[]','野樹參差綠，山花零亂紅。',24,'全唐诗/poet.song.204000.json','["野樹參差綠，山花零亂紅。", "夕陽一樽酒，聊與故人同。"]'),
('0134ac21-766c-4d1e-b95e-239372798922','雨中','張侃','宋','宋诗','song-poetry','','[]','寒山草木疎，蒼翠因雨濕。',24,'全唐诗/poet.song.204000.json','["寒山草木疎，蒼翠因雨濕。", "日暮來不來，前溪借蓑笠。"]'),
('4fc7b35c-9003-4244-9b3f-a831446c6ba1','花珠二絕  其一','張侃','宋','宋诗','song-poetry','','[]','雨細成珠琲，紛紛入綠花。',24,'全唐诗/poet.song.204000.json','["雨細成珠琲，紛紛入綠花。", "綠花無不濕，傾處又成波。"]'),
('804358ce-6780-4b51-9ed3-daf3774518be','花珠二絕  其二','張侃','宋','宋诗','song-poetry','','[]','堦遠滴成聲，荷深圓又碎。',24,'全唐诗/poet.song.204000.json','["堦遠滴成聲，荷深圓又碎。", "風動水銀收，亭亭開翡翠。"]'),
('cbfd2239-658d-40ba-b9eb-626e6d2b64d8','智果院','張侃','宋','宋诗','song-poetry','','[]','前輩經行處，壁間題小詩。',24,'全唐诗/poet.song.204000.json','["前輩經行處，壁間題小詩。", "梅花還好否，要見出塵姿。"]'),
('7ac758dd-1b61-43ba-9ed8-ac7ef4862a1f','嘲梅花','張侃','宋','宋诗','song-poetry','','[]','緘蘂怯寒風，清香已暗通。',24,'全唐诗/poet.song.204000.json','["緘蘂怯寒風，清香已暗通。", "數株籬落外，生毓任元功。"]'),
('10286a62-4e75-4cd9-ab7c-acbe68832ebe','梅花謝嘲','張侃','宋','宋诗','song-poetry','','[]','騷客多吟詠，無非泥酒杯。',24,'全唐诗/poet.song.204000.json','["騷客多吟詠，無非泥酒杯。", "君知儂澹泊，歲歲幾番來。"]'),
('4b01d991-e71c-4ada-b1df-609297f60b80','梅花自解','張侃','宋','宋诗','song-poetry','','[]','孤根在寒谷，無分逐東風。',24,'全唐诗/poet.song.204000.json','["孤根在寒谷，無分逐東風。", "流輩剛言好，中心只固窮。"]'),
('5cd76a0c-2f45-41f2-9957-a8b01d6db9aa','理髮有白者','張侃','宋','宋诗','song-poetry','','[]','今年三十六，吾髮白雙莖。',24,'全唐诗/poet.song.204000.json','["今年三十六，吾髮白雙莖。", "不耐秋霖滴，愁濃遣未平。"]'),
('72ac34bd-ca3d-47c7-bcce-3928c62da18a','春去','張侃','宋','宋诗','song-poetry','','[]','春去留無計，殘花更可人。',24,'全唐诗/poet.song.204000.json','["春去留無計，殘花更可人。", "多情玉蝴蝶，隨雨伴香塵。"]'),
('ea13ecbe-d6ab-4e81-ae1b-7852e1c83c32','題鎮廳西軒','張侃','宋','宋诗','song-poetry','','[]','焚香覺心清，觀書消日永。',24,'全唐诗/poet.song.204000.json','["焚香覺心清，觀書消日永。", "門前剝啄稀，且喜官職冷。"]'),
('f9e612b4-89de-4598-a8a6-9b6cbe283f52','十五夜月二絕  其一','張侃','宋','宋诗','song-poetry','','[]','閒來庭下立，月影照人清。',24,'全唐诗/poet.song.204000.json','["閒來庭下立，月影照人清。", "偏到中秋好，遲眠已四更。"]'),
('df0478ba-99df-46c2-8000-eca81a162c39','十五夜月二絕  其二','張侃','宋','宋诗','song-poetry','','[]','秋光初破蘂，香遠逐人來。',24,'全唐诗/poet.song.204000.json','["秋光初破蘂，香遠逐人來。", "多是蟾宮種，何妨兩處開。"]'),
('72ebddcf-6a4f-4ea6-b4fe-4ff3c5e0929e','十六夜月二首  其一','張侃','宋','宋诗','song-poetry','','[]','昨宵清不盡，今夜色增明。',24,'全唐诗/poet.song.204000.json','["昨宵清不盡，今夜色增明。", "想見清虛殿，冰輪漸漸生。"]'),
('a850db29-4c91-457f-aef5-d7eb039233db','十六夜月二首  其二','張侃','宋','宋诗','song-poetry','','[]','松風傳地籟，花月滿庭心。',24,'全唐诗/poet.song.204000.json','["松風傳地籟，花月滿庭心。", "記得金臺下，孤樽細細斟。"]'),
('138df513-4e67-45c4-98b4-66604fa61121','王梅磎題玉枕峰二絕  其一','張侃','宋','宋诗','song-poetry','','[]','靜處翻千偈，忙中認一身。',24,'全唐诗/poet.song.204000.json','["靜處翻千偈，忙中認一身。", "忽看枕峰句，便作是非人。"]'),
('be7afdc6-67f4-40f3-9cbe-52279aa9df33','王梅磎題玉枕峰二絕  其二','張侃','宋','宋诗','song-poetry','','[]','向來雲影卧，今日復如何。',24,'全唐诗/poet.song.204000.json','["向來雲影卧，今日復如何。", "不是相知少，人間險處多。"]'),
('09b12a00-6e0c-4c08-a186-d28d0c5a47af','中秋','張侃','宋','宋诗','song-poetry','','[]','中秋添月色，携酒上金臺。',24,'全唐诗/poet.song.204000.json','["中秋添月色，携酒上金臺。", "世事無窮盡，江山入句來。"]'),
('2614301a-f3e3-4a23-9c90-058fef670db2','禹廟','張侃','宋','宋诗','song-poetry','','[]','當時計水功，直爲萬世利。',24,'全唐诗/poet.song.204000.json','["當時計水功，直爲萬世利。", "梅梁破浪歸，底事成兒戯。"]'),
('4fe15e79-61d4-4775-8354-511a4e6150c4','題雁山行紀','張侃','宋','宋诗','song-poetry','','[]','當年雁來游，少憩存夜氣。',24,'全唐诗/poet.song.204000.json','["當年雁來游，少憩存夜氣。", "自從開此奇，便有草鞵費。"]'),
('c16155d3-e146-49ff-9344-bbc198854c7e','示法果院僧則','張侃','宋','宋诗','song-poetry','','[]','山深雲卧冷，結屋在山椒。',24,'全唐诗/poet.song.204000.json','["山深雲卧冷，結屋在山椒。", "我意如雲懶，隨緣聽海潮。"]'),
('6112313e-4149-471d-82d4-de9050ad07a4','贈仁上人','張侃','宋','宋诗','song-poetry','','[]','塵事紛如掃，僧窗對竹開。',24,'全唐诗/poet.song.204000.json','["塵事紛如掃，僧窗對竹開。", "欲酬清靜債，一歲五番來。"]'),
('6225018e-5800-4c2e-86bf-a05494c4aaaa','天竺逢僧禮','張侃','宋','宋诗','song-poetry','','[]','于今僧輩少，學業又全疎。',24,'全唐诗/poet.song.204000.json','["于今僧輩少，學業又全疎。", "日莫山深處，相迎有浩初。"]'),
('e8f0d21a-dc43-41e5-aa26-4f79119c5998','秋魚眼','張侃','宋','宋诗','song-poetry','','[]','江湖毓羣魚，水大隨所揀。',24,'全唐诗/poet.song.204000.json','["江湖毓羣魚，水大隨所揀。", "奈何世上人，尋到秋魚眼。"]'),
('13a0fee5-4a10-4b14-b716-b7b3267b4aef','寒蘆四鴻  其一','張侃','宋','宋诗','song-poetry','','[]','蘆葉滿沙洲，鳬翁取次游。',24,'全唐诗/poet.song.204000.json','["蘆葉滿沙洲，鳬翁取次游。", "生綃纔半尺，占得江南秋。"]'),
('a3508a7a-b92c-484d-a731-839a0ea3878a','寒蘆四鴻  其二','張侃','宋','宋诗','song-poetry','','[]','見山真見山，翠滿簷楣間。',24,'全唐诗/poet.song.204000.json','["見山真見山，翠滿簷楣間。", "屏几漫畫障，意足水墨閒。"]'),
('988265c3-87d8-43a0-98f4-17b27a38c687','救婆廟二首  其一','張侃','宋','宋诗','song-poetry','','[]','曲徑接山阿，行人說救婆。',24,'全唐诗/poet.song.204000.json','["曲徑接山阿，行人說救婆。", "須知閨室女，識見已爭多。"]'),
('593f9c54-d24d-4c74-9339-c1f83cd84f8f','救婆廟二首  其二','張侃','宋','宋诗','song-poetry','','[]','海水有枯竭，喬松易摧折。',24,'全唐诗/poet.song.204000.json','["海水有枯竭，喬松易摧折。", "高名萬古存，地志書英烈。"]'),
('bc740c8a-016f-4c24-8136-9af0dff05a01','對酒','張侃','宋','宋诗','song-poetry','','[]','柳絮隨風舞，金沙貼地開。',24,'全唐诗/poet.song.204000.json','["柳絮隨風舞，金沙貼地開。", "爲緣春滿眼，不厭酒深盃。"]'),
('5c807759-78cf-49b5-a18e-6509f1e60606','偶成','張侃','宋','宋诗','song-poetry','','[]','風暖輕拖練，天寒皺作鞾。',24,'全唐诗/poet.song.204000.json','["風暖輕拖練，天寒皺作鞾。", "江湖只如此，今古幾消磨。"]'),
('4398f623-9a23-4917-bcb0-b3a62f7aa5b2','戲題','張侃','宋','宋诗','song-poetry','','[]','雨後露華白，風前嵐氣清。',24,'全唐诗/poet.song.204000.json','["雨後露華白，風前嵐氣清。", "秋心愁不展，垂白睡難成。"]'),
('3cf7a63e-e264-41ea-aa4d-5c94e786afb1','桃花菊','張侃','宋','宋诗','song-poetry','','[]','誰將秋菊蘂，故作小桃紅。',24,'全唐诗/poet.song.204000.json','["誰將秋菊蘂，故作小桃紅。", "輕薄隨時好，飄零風雨中。"]'),
('61f74f6b-ffa0-4299-bffc-5f94744f6287','雪霽','張侃','宋','宋诗','song-poetry','','[]','微雪寒侵煖，新晴風掃氛。',24,'全唐诗/poet.song.204000.json','["微雪寒侵煖，新晴風掃氛。", "天公念穡事，秋稼定如雲。"]'),
('4bcad716-2eb4-482d-995b-254bf5887203','蘇成之庚申歲相別甲申歲方會甬東  其一','張侃','宋','宋诗','song-poetry','','[]','憶與成之別，于今廿五年。',24,'全唐诗/poet.song.204000.json','["憶與成之別，于今廿五年。", "今朝復相見，話舊竹窗前。"]'),
('5b69b126-93ca-46f8-bef0-80a2f216e321','蘇成之庚申歲相別甲申歲方會甬東  其二','張侃','宋','宋诗','song-poetry','','[]','世態頻頻換，君心炯炯明。',24,'全唐诗/poet.song.204000.json','["世態頻頻換，君心炯炯明。", "能言少時事，滿座便風生。"]'),
('651688aa-15ca-4e03-a7b8-b03fd49ad997','雨中','張侃','宋','宋诗','song-poetry','','[]','風清園蝶粉猶輕，雨冷吳蠶繭未成。',32,'全唐诗/poet.song.204000.json','["風清園蝶粉猶輕，雨冷吳蠶繭未成。", "盡說溪村年事好，又添漁子笑浮生。"]'),
('3da16b62-910d-4382-aab1-c0a2587d3e1a','春去','張侃','宋','宋诗','song-poetry','','[]','橫雨顛風勢轉加，紅情綠意不容誇。',32,'全唐诗/poet.song.204000.json','["橫雨顛風勢轉加，紅情綠意不容誇。", "明朝春去忙如箭，滿市人携謝豹蝦。"]'),
('4b0531d7-4091-4067-b572-4171629dbf16','浮來廟','張侃','宋','宋诗','song-poetry','','[]','仙槎飛去訪牛郎，頑石浮來立道旁。',32,'全唐诗/poet.song.204000.json','["仙槎飛去訪牛郎，頑石浮來立道旁。", "能使鄉民知所敬，隻雞巵酒卜豐穰。"]'),
('3920abd2-64b0-4cd7-af39-ee6704df8f55','梅子','張侃','宋','宋诗','song-poetry','','[]','一株綠色未成陰，千點微酸已沁心。',32,'全唐诗/poet.song.204000.json','["一株綠色未成陰，千點微酸已沁心。", "雨露功深人不識，摘來先與了清吟。"]'),
('a85a2487-47b3-4e4c-8dbc-70f47325e84a','今歲朱櫻紅熟樽俎間日有此品口占二絕  其一','張侃','宋','宋诗','song-poetry','','[]','積雨淋漓花頓空，櫻桃滿樹漬猩紅。',32,'全唐诗/poet.song.204000.json','["積雨淋漓花頓空，櫻桃滿樹漬猩紅。", "相陪從事風流裏，遥想香燈摇落中。"]'),
