('dbc0fbc1-e361-48fc-8108-e947c346796f','軒亭','張侃','宋','宋诗','song-poetry','','[]','籃輿清曉過軒亭，軒外山圍未了青。',32,'全唐诗/poet.song.204000.json','["籃輿清曉過軒亭，軒外山圍未了青。", "我意他年尋一壑，只因今日眼曾經。"]'),
('514127b6-1a2f-49b9-b35b-f58b3360fa20','延桂堂','張侃','宋','宋诗','song-poetry','','[]','靜看桂影上簾櫳，幾度吟詩句未工。',32,'全唐诗/poet.song.204000.json','["靜看桂影上簾櫳，幾度吟詩句未工。", "從此相忘天地外，主人袖手小闌東。"]'),
('983a29e0-0fc5-446a-b5fe-81697352a26c','小池','張侃','宋','宋诗','song-poetry','','[]','小池栽得數枝蓮，也占新凉七月天。',32,'全唐诗/poet.song.204000.json','["小池栽得數枝蓮，也占新凉七月天。", "說道南灣納空闊，盡將野意換韶妍。"]'),
('864aa29c-c2b3-4ac2-8759-2b84e6559439','水月泉','張侃','宋','宋诗','song-poetry','','[]','水清月白又初秋，㶁㶁山泉入澗流。',32,'全唐诗/poet.song.204000.json','["水清月白又初秋，㶁㶁山泉入澗流。", "我已重來君解否，生平厭作是非謀。"]'),
('5360eeea-c239-4e75-911b-c722bf15480e','江下','張侃','宋','宋诗','song-poetry','','[]','昔曾襆被宿江潯，風雨欺人春未深。',32,'全唐诗/poet.song.204000.json','["昔曾襆被宿江潯，風雨欺人春未深。", "轉盼六年重到此，越山依舊隠雲心。"]'),
('be17b01f-a530-483f-bd62-2205058a0119','丈亭','張侃','宋','宋诗','song-poetry','','[]','潮水衝沙未轉清，急摇雙艣似鵝鳴。',32,'全唐诗/poet.song.204000.json','["潮水衝沙未轉清，急摇雙艣似鵝鳴。", "須臾停艣依荒岸，草屋疎燈記夜程。"]'),
('980ca3eb-4bcd-4560-a8e8-5e74e12795b1','題懷謝驛','張侃','宋','宋诗','song-poetry','','[]','謝公洗屐水平池，笑傲東山望一時。',32,'全唐诗/poet.song.204000.json','["謝公洗屐水平池，笑傲東山望一時。", "究竟後人能尚友，驛名懷謝著深思。"]'),
('f39adf5a-bfa2-4233-b5d2-3070c636050e','偶得','張侃','宋','宋诗','song-poetry','','[]','客舍牆根草未生，市橋官柳已欣榮。',32,'全唐诗/poet.song.204000.json','["客舍牆根草未生，市橋官柳已欣榮。", "洪鈞造物元無意，只是東風有世情。"]'),
('ef4a9dd2-6843-4032-affc-2c41b8f04dfc','偶成','張侃','宋','宋诗','song-poetry','','[]','竹奴角簟頗相宜，正是書齋寂靜時。',32,'全唐诗/poet.song.204000.json','["竹奴角簟頗相宜，正是書齋寂靜時。", "白鳥忽穿林影去，自携紈扇細題詩。"]'),
('0a02bb98-625f-4ece-bb81-ed5125127062','偶書二絕  其一','張侃','宋','宋诗','song-poetry','','[]','靜觀萬物各隨緣，天亦何心付自然。',32,'全唐诗/poet.song.204000.json','["靜觀萬物各隨緣，天亦何心付自然。", "鸜鵒不材鸚鵡貴，豈知鸜鵒得天年。"]'),
('46711456-43db-43be-bd8f-38b174cab3ce','偶書二絕  其二','張侃','宋','宋诗','song-poetry','','[]','久知鳬短鶴長語，誰賦花榮竹脆詩。',32,'全唐诗/poet.song.204000.json','["久知鳬短鶴長語，誰賦花榮竹脆詩。", "物理無窮難測識，且傾美酒樂天時。"]'),
('efa86ff6-17e7-47d2-912c-719ecf898e65','偶題','張侃','宋','宋诗','song-poetry','','[]','夜深水冷無香餌，若箇黄鱗肯上鈎。',32,'全唐诗/poet.song.204000.json','["夜深水冷無香餌，若箇黄鱗肯上鈎。", "我欲釣鼇安爾用，一竿風月好迴舟。"]'),
('372d6530-d421-43b9-9200-030a33d4c816','題司馬才叔詩後','張侃','宋','宋诗','song-poetry','','[]','司馬才名世所賢，銀鈎珠唾尚依然。',32,'全唐诗/poet.song.204000.json','["司馬才名世所賢，銀鈎珠唾尚依然。", "塵埃試看蛛絲壁，倒指於今六十年。"]'),
('f2e46288-c712-4f87-a6e7-65178ccd7d76','六言  其一','張侃','宋','宋诗','song-poetry','','[]','梅長官深有味，木居士喜清游。',28,'全唐诗/poet.song.204000.json','["梅長官深有味，木居士喜清游。", "未用三熏三沐，且占一壑一邱。"]'),
('d617f283-35e1-4cba-9e66-0b04f504a31a','六言  其二','張侃','宋','宋诗','song-poetry','','[]','色惟有用文子，翠亦堪餐此君。',28,'全唐诗/poet.song.204000.json','["色惟有用文子，翠亦堪餐此君。", "未須歌南浦雨，終是望渭北雲。"]'),
('d519da15-616f-4445-8461-98b281f062b8','睡寒山拾得贊','張侃','宋','宋诗','song-poetry','','[]','人居火宅無不有，你亦投身携掃帚。',32,'全唐诗/poet.song.204000.json','["人居火宅無不有，你亦投身携掃帚。", "一朝放下困騰騰，明月寒潭只依舊。"]'),
('5746abb2-d95c-4403-b13d-0c28937a6695','僧熊畫布袋贊','張侃','宋','宋诗','song-poetry','','[]','弄盡精神真捏怪，橫拖拄杖街頭賣。',32,'全唐诗/poet.song.204000.json','["弄盡精神真捏怪，橫拖拄杖街頭賣。", "忽然兩步走歸來，四大不收圖睡快。"]'),
('62f15644-b954-4471-8555-e3d3cca4eb9b','蘇李松石圖贊','張侃','宋','宋诗','song-poetry','','[]','東坡先生，錦繡心胸。',180,'全唐诗/poet.song.204000.json','["東坡先生，錦繡心胸。", "戲作怪石，一時告功。", "當其落筆，雨霈風從。", "齊安赤壁，惠州鶴峰。", "十年飽覽，孰可攖鋒。", "溫潤枯淡，變態不同。", "一卷之石，作倚盤松。", "龍眠居士，孰覊其蹤。", "一瞬八表，如鶴在空。", "東坡頌美，佳名日穹。", "明窗展觀，松古石窿。", "天下之寶，豈間窮通。", "東坡之節，龍眠之隠。", "一異出處，如琴加軫。", "吁嗟二公，人中之龍。", "百餘歲後，仰止英風。", "我生後時，何以形容。", "紀述惟贊，愧非揚雄。"]'),
('87faf831-5373-4d56-a171-e3a2b2406ff2','辛巳自贊','張侃','宋','宋诗','song-poetry','','[]','徐永昇畫時，予弱冠而綴文。',88,'全唐诗/poet.song.204000.json','["徐永昇畫時，予弱冠而綴文。", "趙可大畫時，予三十而有立。", "錢誦畫時，予究道之出入。", "蓋嘗晦其聲名，謝其等級。", "惡脂韋而取容，與傲世而長揖。", "客問直夫，處事太執。", "直夫俛而笑曰，人各是其所習。"]'),
('10daa2cf-7816-472b-86a3-2c9e049d9161','戊寅自贊','張侃','宋','宋诗','song-poetry','','[]','有伯夷之清，而無萬世之準。',92,'全唐诗/poet.song.204000.json','["有伯夷之清，而無萬世之準。", "有孟郊之古，而無一代之名。", "能操守而冰潔，視富貴如雲輕。", "前乎直夫是一臞叟，後乎直夫是一書生。", "既不能潤乎詩書，又不能事乎縱橫。", "客有過者曰：嘻，視彼拙貌，徒汙丹青。"]'),
('10f1c054-0f77-4076-bb5a-df8b4322c0d8','客有誦唐詩者又有誦江西詩者因再用斜川九日韻','張侃','宋','宋诗','song-poetry','','[]','泛觀今人詩，機巧由心生。',108,'全唐诗/poet.song.204000.json','["泛觀今人詩，機巧由心生。", "鏤冰與鑄木，未免求虛名。", "豈知製作妙，渾然同水清。", "塵埃數張紙，亦足傳佳聲。", "羣趨不知守，辛勤到莫齡。", "奈何口耳間，一見意已傾。", "投身入詩社，被褐生光榮。", "黨同伐異說，初非出本情。", "我願剖藩籬，學力隨所成。"]'),
('22217474-bfb1-48ba-9008-b3aaf54b3b55','有作','張侃','宋','宋诗','song-poetry','','[]','名塵愧屢拂，世垢思一澣。',48,'全唐诗/poet.song.204000.json','["名塵愧屢拂，世垢思一澣。", "急索脛已腫，虛驚背獨汗。", "窘步裁免跌，高談卒成謾。", "辰去將奈何，磨頭髻如彈。"]'),
('506aab0f-f8f5-48c1-a1be-1b73cd6fe13a','偶成','張侃','宋','宋诗','song-poetry','','[]','長歌詠考槃，灑落似休官。',48,'全唐诗/poet.song.204000.json','["長歌詠考槃，灑落似休官。", "愛竹臨溪倚，携書坐石看。", "足煩猶看屨，髮禿自忘冠。", "顧爲無多欲，持身到處安。"]'),
('1db81de4-e31d-4168-9ae7-e549ac5cbeac','探野航古梅','張侃','宋','宋诗','song-poetry','','[]','池邊梅未綻，不是怯霜風。',24,'全唐诗/poet.song.204000.json','["池邊梅未綻，不是怯霜風。", "待得陽和到，清香一線通。"]'),
('90290be4-1400-4146-b33b-45636ca87eea','贈句容士人','張侃','宋','宋诗','song-poetry','','[]','山川清美天下稀，五瑞同時盍紀碑。',32,'全唐诗/poet.song.204000.json','["山川清美天下稀，五瑞同時盍紀碑。", "碑上只言人物盛，若言德政愧無之。"]'),
('1e783546-0893-4791-ab82-fa3c5ab73915','句','張侃','宋','宋诗','song-poetry','','[]','剩喜聯官忘爾汝，故令元化奪胚胎。',16,'全唐诗/poet.song.204000.json','["剩喜聯官忘爾汝，故令元化奪胚胎。"]'),
('51c6375b-f04d-40f3-ba47-e5dd49bd4d61','存目','張侃','宋','宋诗','song-poetry','','[]','詩題：先公守汝陰都曹路君挂冠東歸載乖崖公留其錄語今傳播世間三十年矣過居潁昌……首句：誰聞鬷蔑言。',48,'全唐诗/poet.song.204000.json','["詩題：先公守汝陰都曹路君挂冠東歸載乖崖公留其錄語今傳播世間三十年矣過居潁昌……首句：誰聞鬷蔑言。"]'),
('196316a7-ac78-4b77-ba2b-ad6ee8ebe7ea','月波樓','袁似道','宋','宋诗','song-poetry','','[]','繡節移華屋，下照鴛湖闊。',120,'全唐诗/poet.song.204000.json','["繡節移華屋，下照鴛湖闊。", "飛梯駕秋旻，傑觀壓雲堞。", "銖積日用間，經營妙無跡。", "圖畫劃天開，景物劖地絕。", "簡靜還樂邦，登覽追逸轍。", "彩舫回波心，芳樽浮月夕。", "清吟開酣飲，長嘯雜橫笛。", "新詩紀遊情，□酒驚醉魄。", "傳看大軸盈，準擬堅珉刻。", "□□望其成，抑以觀稼穡。"]'),
('7e04cd9f-39bc-489a-8994-0cbde20a77a9','赤壁觀泉','朱慶朝','宋','宋诗','song-poetry','','[]','渺渺長流自古今，憑高凝眸幾迴深。',32,'全唐诗/poet.song.204000.json','["渺渺長流自古今，憑高凝眸幾迴深。", "欲知最上源頭處，只在工夫着意尋。"]'),
('51edb683-6f63-4596-9d38-8df1d81bba1b','應試渡江','朱慶朝','宋','宋诗','song-poetry','','[]','旭日澄江新氣齊，登舟直上武林西。',32,'全唐诗/poet.song.204000.json','["旭日澄江新氣齊，登舟直上武林西。", "桂花香發正秋月，隔岸漁歌相喚啼。"]'),
('4a28b028-79cd-4297-9371-c6b08160926a','句','丁大全','宋','宋诗','song-poetry','','[]','雲從百丈潭中起，雨向九重天上來。',16,'全唐诗/poet.song.204000.json','["雲從百丈潭中起，雨向九重天上來。"]'),
('ae0d06f1-5c87-4770-baaf-88bc1a8e5b1e','至錢塘浄慈寺寫古松於壁因題','馬宋英','宋','宋诗','song-poetry','','[]','磨盡一錠兩錠墨，掃出千年萬年樹。',32,'全唐诗/poet.song.204000.json','["磨盡一錠兩錠墨，掃出千年萬年樹。", "月明烏鵲誤飛來，踏枝不著空歸去。"]'),
('e4320803-9dd7-4f77-bd44-e762ca0f4375','賦梅','林靖之','宋','宋诗','song-poetry','','[]','與月淡交連影瘦，于春無競著花疎。',32,'全唐诗/poet.song.204000.json','["與月淡交連影瘦，于春無競著花疎。", "細雨歛塵棲萼潤，輕雲度谷壓香低。"]'),
('b9b7bb0f-9839-496d-8dbb-92938acbbdee','垂虹亭','陳武子','宋','宋诗','song-poetry','','[]','行樂江亭上，情彌天壤間。',48,'全唐诗/poet.song.204000.json','["行樂江亭上，情彌天壤間。", "舟譏王訪雪，妓鄙謝登山。", "佳致輸公擅，清歡愧爾慳。", "賓僚陪宴笑，興盡莫輕還。"]'),
('eb0ab0e0-20b7-4ae4-877b-8d334d1213e3','歌','開禧牧童','宋','宋诗','song-poetry','','[]','朝出耕田暮飯牛，林泉風月共悠悠。',32,'全唐诗/poet.song.204000.json','["朝出耕田暮飯牛，林泉風月共悠悠。", "九重雖竊阿衡貴，爭得功名到白頭。"]'),
('3c507524-7362-4247-b8af-8aa15fe983cd','句','開禧牧童','宋','宋诗','song-poetry','','[]','玉津園內行天討，怨血空啼杜宇紅。',16,'全唐诗/poet.song.204000.json','["玉津園內行天討，怨血空啼杜宇紅。"]'),
('7f771327-439f-450d-b5c6-59499951f861','春曉','尤带','宋','宋诗','song-poetry','','[]','東方看欲曙，三五斗參橫。',48,'全唐诗/poet.song.204000.json','["東方看欲曙，三五斗參橫。", "月影斜穿竹，雞聲遠逐鶑。", "花街紅露膩，柳浪翠烟輕。", "滄海升朝日，春光滿太清。"]'),
('139422f1-b7ee-4cd4-8b7e-9374fef43101','句','釋皓','宋','宋诗','song-poetry','','[]','楚雁傳歸信，吳鷗候過船。',12,'全唐诗/poet.song.204000.json','["楚雁傳歸信，吳鷗候過船。"]'),
('c46b2f71-a84d-4bcf-a546-a622f5ec0cca','題姚雪蓬騎牛小照','趙東師','宋','宋诗','song-poetry','','[]','騎牛無笠又無蓑，斷嚨橫岡到處過。',32,'全唐诗/poet.song.204000.json','["騎牛無笠又無蓑，斷嚨橫岡到處過。", "暖日暄風不常有，前村雨暗却如何。"]'),
('35e7bdec-12c8-42d1-aa38-5e47cb346738','訪姚雪蓬貶所','釋淵','宋','宋诗','song-poetry','','[]','故里田園拋弟妹，異鄉燈火對妻兒。',32,'全唐诗/poet.song.204000.json','["故里田園拋弟妹，異鄉燈火對妻兒。", "十年漂泊孤篷雪，誰補梅花入楚辭。"]'),
('9c089a28-3369-4814-b038-6f5447cd86ec','江郊旅舍','毛滄洲','宋','宋诗','song-poetry','','[]','京旅江郊僻，樓居賸得清。',48,'全唐诗/poet.song.204000.json','["京旅江郊僻，樓居賸得清。", "柳風羅带嫋，荷雨水銀傾。", "日夜潮來去，東西山送迎。", "悠悠千古興，吳越暮雲平。"]'),
('c706571b-febf-4fd6-a1d2-9641a2855fc1','賜宜春易太極','徐經孫','宋','宋诗','song-poetry','','[]','易有太極，在天地先。',60,'全唐诗/poet.song.204000.json','["易有太極，在天地先。", "兩儀四象，是謂後天。", "春臺得之，云自希夷。", "吉凶禍福，予以前知。", "八十二宮，頗與俗殊。", "數往知來，亶其然乎。"]'),
('9fcd6d61-7578-4006-87a1-f0afd6967252','元旦訓孫','徐經孫','宋','宋诗','song-poetry','','[]','咨爾潭生，今歲十六。',140,'全唐诗/poet.song.204000.json','["咨爾潭生，今歲十六。", "棄汝幼志，企慕老宿。", "收汝放心，歸就檢束。", "業必精思，書必勤讀。", "敬事父母，出入必告。", "欽奉師模，傳習必熟。", "友愛同氣，如手如足。", "珍重自身，如珪如玉。", "非禮勿視，祇汙青目。", "非禮勿聽，祇亂心曲。", "非禮勿言，言必招辱。", "非禮勿動，動必非福。", "翁作箴言，爾其佩服。", "念哉敬哉，中有天祿。"]'),
('fc5039f2-5bf1-47ec-a81e-24eb83a9e05c','覺溪八景 龍門春浪','徐經孫','宋','宋诗','song-poetry','','[]','雷奔石壁間，瀑瀉洞門側。',24,'全唐诗/poet.song.204000.json','["雷奔石壁間，瀑瀉洞門側。", "蜿蜒乘洪濤，變化莫可測。"]'),
('599feef1-17bb-4147-93a0-02ee1c34e316','覺溪八景 鰲頭秋風','徐經孫','宋','宋诗','song-poetry','','[]','西風吹石岐，鱗甲起深轍。',24,'全唐诗/poet.song.204000.json','["西風吹石岐，鱗甲起深轍。", "借問去來人，誰是騎鯨客。"]'),
('4493c5d0-72eb-43a8-b99c-bcf76ebbf023','覺溪八景 羅阜朝雲','徐經孫','宋','宋诗','song-poetry','','[]','初生半崖陰，漸失雙峰翠。',24,'全唐诗/poet.song.204000.json','["初生半崖陰，漸失雙峰翠。", "倏忽滿太虛，蒼生望霖雨。"]'),
('c8fd9461-f385-4c6f-b88f-99c19067658e','覺溪八景 潘溪夜月','徐經孫','宋','宋诗','song-poetry','','[]','溪月濯銀盤，溪橋卧脩軏。',24,'全唐诗/poet.song.204000.json','["溪月濯銀盤，溪橋卧脩軏。", "沙凈碧波寒，分明見蟾闕。"]'),
('785332cb-e31f-43f7-9ae1-8c18a90abb1e','覺溪八景 隆福晚鐘','徐經孫','宋','宋诗','song-poetry','','[]','山圍古寺陰，曙隔鯨音發。',24,'全唐诗/poet.song.204000.json','["山圍古寺陰，曙隔鯨音發。", "悠揚三四聲，喚上東林月。"]'),
('2b6d25a6-eda1-4a43-a825-a2a8bf537563','覺溪八景 驪塘暮雨','徐經孫','宋','宋诗','song-poetry','','[]','飄蕭鷗鷺群，淅瀝孤蒲晚。',24,'全唐诗/poet.song.204000.json','["飄蕭鷗鷺群，淅瀝孤蒲晚。", "雲斷山月明，新泉落前澗。"]'),
('c8b1720c-32b9-4844-99f3-34d37024e9fe','覺溪八景 水北書聲','徐經孫','宋','宋诗','song-poetry','','[]','林館碧溪陰，絃歌雜燈影。',24,'全唐诗/poet.song.204000.json','["林館碧溪陰，絃歌雜燈影。", "夜分猶吾伊，學海在人境。"]'),
('8d030379-0237-43be-ab60-7fe5afdb42a7','覺溪八景 東源詩社','徐經孫','宋','宋诗','song-poetry','','[]','詩家在東臯，雞林價爭售。',24,'全唐诗/poet.song.204000.json','["詩家在東臯，雞林價爭售。", "作者復幾人，風月三千首。"]'),
('6a8afb18-e175-4bc5-a05c-1cf79e252412','題施山觀音閣','徐經孫','宋','宋诗','song-poetry','','[]','閣道連雲棧，簷牙覆竹陰。',48,'全唐诗/poet.song.204000.json','["閣道連雲棧，簷牙覆竹陰。", "南來天馬渡，北落水龍吟。", "林鳥疑譚偈，田花欲佈金。", "憑欄觀下界，洞見遠公心。"]'),
('e6106e43-644a-4830-a008-37a07a38dcf5','長子思訦赴江西庾幕','徐經孫','宋','宋诗','song-poetry','','[]','三年永豐簿，兩載半臨川。',48,'全唐诗/poet.song.204000.json','["三年永豐簿，兩載半臨川。", "納滿無多日，奇逢有二天。", "臨民須近厚，減價要重蠲。", "莫道違離遠，常如在膝前。"]'),
('ce6c572b-6f43-4aa7-acdc-db4f99496b1e','思訦生朝分忠勤酒侑之以詩','徐經孫','宋','宋诗','song-poetry','','[]','帝正纔五五，吾子始生時。',48,'全唐诗/poet.song.204000.json','["帝正纔五五，吾子始生時。", "潘縣花將錦，陶門柳欲絲。", "與民同樂意，在我即琴棋。", "酒自忠勤出，公餘薦一巵。"]'),
('32b84628-80ba-40ba-a3bd-b737b0592b61','病中有感','徐經孫','宋','宋诗','song-poetry','','[]','習懶多成病，旬餘久覆杯。',48,'全唐诗/poet.song.204000.json','["習懶多成病，旬餘久覆杯。", "帳中聞燕語，瓶裏看花開。", "醫已肱三折，愁來腸九迴。", "何時得疏散，屐齒印蒼苔。"]'),
('5b97dd8e-d40d-4aed-948a-c6453eccf607','幼子思誼舉次孫命名陽生','徐經孫','宋','宋诗','song-poetry','','[]','吾年七十四，始見兩孫枝。',48,'全唐诗/poet.song.204000.json','["吾年七十四，始見兩孫枝。", "陽德初回候，蟾光欲滿時。", "傳家惟簡冊，願汝似蘭芝。", "何日解言語，能吟公此詩。"]'),
('32de4ad8-72d1-4205-8085-e960fb5d9a1f','送思訦之官鰲峰','徐經孫','宋','宋诗','song-poetry','','[]','我如汝年時，昉問便江戍。',168,'全唐诗/poet.song.204000.json','["我如汝年時，昉問便江戍。", "選穽如海深，望洋吁可怖。", "汝今亦宜教，去作鰲峰主。", "有民環百里，待汝字而撫。", "何以奉寬條，何以撫黎庶。", "惟公則生明，平心閲牒訴。", "惟廉則寡過，莫受脂膏汙。", "惟勤則集事，慎勿習逸豫。", "惟儉可無求，只學我清苦。", "持此四字符，便是作縣譜。", "去家三百里，兩地無多路。", "安問來與往，時走一健步。", "居官而民宜，暌隔非所慮。", "三年課最歸，可以見君父。"]'),
('b0907096-4540-428e-97f6-a25371c00829','咸淳壬申六月不暑','徐經孫','宋','宋诗','song-poetry','','[]','常年六月六，暑氣何其酷。',216,'全唐诗/poet.song.204000.json','["常年六月六，暑氣何其酷。", "犬有吐舌煩，貓得負背燠。", "今日胡不然，蕭然凉氣足。", "陽烏潛其輝，小雨時霢霂。", "重袂猶未溫，浴了肌起粟。", "老病固宜然，壯者亦不浴。", "短至未及間，秋陰如許毒。", "本朝王火德，德與堯運續。", "文明耀四海，年世不待卜。", "吾君乾六龍，剛健粹如玉。", "吾相泰九二，夬夬出莧陸。", "君臣德既同，詎有此陰伏。", "吾聞氛氣惡，殺氣盛西北。", "襄城既失守，生靈爛魚肉。", "匹夫尚懷憂，知此妄屠戮。", "臣固告上天，忍淚不敢哭。", "願言掃陰邪，日月舜耳目。", "中國盛陽明，從今調玉燭。"]'),
('7015a12c-fcc1-45a3-a6f8-5bb21458ffe7','題伴雲樵唱','徐經孫','宋','宋诗','song-poetry','','[]','佛法生憎綺語，道人安用樵歌。',28,'全唐诗/poet.song.204000.json','["佛法生憎綺語，道人安用樵歌。", "有時言外悟意，不覺山中爛柯。"]'),
('08e8e926-681f-4fca-b829-b34e5fe6a5b3','自贊夏端甫所繪真','徐經孫','宋','宋诗','song-poetry','','[]','老我不堪位置，歸來久混漁樵。',28,'全唐诗/poet.song.204000.json','["老我不堪位置，歸來久混漁樵。", "忽然珠玉在側，見之令人意消。"]'),
('98c17b7a-9bf6-4ece-be87-97942545964b','春班遇雪','徐經孫','宋','宋诗','song-poetry','','[]','拜賜通班近玉墀，小臣今日覩朝儀。',32,'全唐诗/poet.song.204000.json','["拜賜通班近玉墀，小臣今日覩朝儀。", "雪花飛在藍袍上，潔白其身正此時。"]'),
('c9100c94-0a86-449c-85b5-f0e66da128b5','和端茶訓子  其一','徐經孫','宋','宋诗','song-poetry','','[]','東坡月窟天香遠，山谷雲濤味玉溫。',32,'全唐诗/poet.song.204000.json','["東坡月窟天香遠，山谷雲濤味玉溫。", "相對兩翁元祐老，說茶風味到今存。"]'),
('a8500380-1ce8-40d2-be75-0ed71319f8f3','和端茶訓子  其二','徐經孫','宋','宋诗','song-poetry','','[]','寫詩只到黄山谷，又失西川蘇子賢。',32,'全唐诗/poet.song.204000.json','["寫詩只到黄山谷，又失西川蘇子賢。", "更把名章細商略，續絃那可惜膠煎。"]'),
('704be21d-03d9-48b1-9f62-1af6e23550e2','和端茶訓子  其三','徐經孫','宋','宋诗','song-poetry','','[]','三日君詩當刮目，看來字字到雲和。',32,'全唐诗/poet.song.204000.json','["三日君詩當刮目，看來字字到雲和。", "從今喜入聖人手，孔杏壇中取瑟歌。"]'),
('1f8eafb6-90f2-4de7-8bfb-bc52605194c2','南英會芳亭','徐經孫','宋','宋诗','song-poetry','','[]','衆芳會處得春多，草色隨人氣亦和。',32,'全唐诗/poet.song.204000.json','["衆芳會處得春多，草色隨人氣亦和。", "聞道吾宗好兄弟，棣花香裏細吟哦。"]'),
('c1dd354d-02cc-4419-90aa-521f266fdeee','過嚴子陵釣灘','徐經孫','宋','宋诗','song-poetry','','[]','仰止高風不可攀，且圖生出鬼門關。',32,'全唐诗/poet.song.204000.json','["仰止高風不可攀，且圖生出鬼門關。", "稽首臺前無復過，歸家斬却釣魚竿。"]'),
('5e9059d5-417c-4b1b-956a-21b9367beccb','和臨湘奉議孫敷山歸田十詠  其一','徐經孫','宋','宋诗','song-poetry','','[]','仰止高風早賦歸，晚生自恨不同時。',32,'全唐诗/poet.song.204000.json','["仰止高風早賦歸，晚生自恨不同時。", "公如嶺上孤松秀，我亦松間百尺絲。"]'),
('5889b1c1-b8e1-41e3-925f-51c7f37dbc16','和臨湘奉議孫敷山歸田十詠  其二','徐經孫','宋','宋诗','song-poetry','','[]','尚記千官拱帝堯，日隨環珮早趨朝。',32,'全唐诗/poet.song.204000.json','["尚記千官拱帝堯，日隨環珮早趨朝。", "螭坳氈下從容際，咫尺天顔未覺遥。"]'),
('491f61c4-2fd9-4322-a700-fe61f2caac1a','和臨湘奉議孫敷山歸田十詠  其三','徐經孫','宋','宋诗','song-poetry','','[]','喬山却似會稽陰，千里孤臣淚滿襟。',32,'全唐诗/poet.song.204000.json','["喬山却似會稽陰，千里孤臣淚滿襟。", "沐浴恩波無地報，始知滄海未爲深。"]'),
('c3242daf-ffea-4c1f-9f12-fa9966dc222f','和臨湘奉議孫敷山歸田十詠  其四','徐經孫','宋','宋诗','song-poetry','','[]','咸淳天子憐臣老，紫殿清華極邃情。',32,'全唐诗/poet.song.204000.json','["咸淳天子憐臣老，紫殿清華極邃情。", "賦祿玉隆真晝錦，有時聽得步虛聲。"]'),
('9d5d5e16-6be2-48db-8bb9-f7de42ad00f6','和臨湘奉議孫敷山歸田十詠  其五','徐經孫','宋','宋诗','song-poetry','','[]','九重憂責詎能分，不雨羞爲出岫雲。',32,'全唐诗/poet.song.204000.json','["九重憂責詎能分，不雨羞爲出岫雲。", "累疏丐歸今得請，保全晚節荷明君。"]'),
('7a0fcca9-7851-4d96-83e9-073c88f47305','和臨湘奉議孫敷山歸田十詠  其六','徐經孫','宋','宋诗','song-poetry','','[]','北窗自有來薰處，長夏何妨一枕高。',32,'全唐诗/poet.song.204000.json','["北窗自有來薰處，長夏何妨一枕高。", "竹薄未能遮照徧，西風我欲障葡萄。"]'),
('074dc3e4-88fd-4ba6-a8d4-e691d5017c46','和臨湘奉議孫敷山歸田十詠  其七','徐經孫','宋','宋诗','song-poetry','','[]','活水一溪如玉瑩，好山四面似螺堆。',32,'全唐诗/poet.song.204000.json','["活水一溪如玉瑩，好山四面似螺堆。", "個中自足歸吾老，莫待北山文勒回。"]'),
('43ae63cf-6217-4b46-82d0-72d495daa9c7','和臨湘奉議孫敷山歸田十詠  其八','徐經孫','宋','宋诗','song-poetry','','[]','家有園池幸未荒，客來有酒或傳觴。',32,'全唐诗/poet.song.204000.json','["家有園池幸未荒，客來有酒或傳觴。", "秋宵玩月冬觀雪，春日尋芳夏納凉。"]'),
('d247e577-cbae-428b-be0d-2dba37ddb0d0','和臨湘奉議孫敷山歸田十詠  其九','徐經孫','宋','宋诗','song-poetry','','[]','人心易溺誰能拯，世道如瀾孰與回。',32,'全唐诗/poet.song.204000.json','["人心易溺誰能拯，世道如瀾孰與回。", "頼有聖賢遺訓在，好懷每爲古書開。"]'),
('97e58623-4012-4110-a02e-c8896d5d713c','和臨湘奉議孫敷山歸田十詠  其一○','徐經孫','宋','宋诗','song-poetry','','[]','早眠晏起自安恬，頭上從教白髮添。',32,'全唐诗/poet.song.204000.json','["早眠晏起自安恬，頭上從教白髮添。", "和了十詩賒七字，太平時節效陶潛。"]'),
('76a2cefb-268e-4b9c-b406-a3ec3cfb6b43','題安原寺','徐經孫','宋','宋诗','song-poetry','','[]','杜老曾留脩覺句，韓公亦有岳山題。',32,'全唐诗/poet.song.204000.json','["杜老曾留脩覺句，韓公亦有岳山題。", "愧無健筆希前哲，謾把飛紅當踏泥。"]'),
('4acba0b7-dd76-46a4-94f5-d5691e45cc56','病起  其一','徐經孫','宋','宋诗','song-poetry','','[]','去年習懶因成癖，瘦骨支離怯病魔。',32,'全唐诗/poet.song.204000.json','["去年習懶因成癖，瘦骨支離怯病魔。", "今日團圓環四世，玉蒲細切泛金荷。"]'),
('167732e2-acb9-48af-90fc-7098ac9cb001','病起  其二','徐經孫','宋','宋诗','song-poetry','','[]','上高殊邑尚吾鄉，千里相忘是建康。',32,'全唐诗/poet.song.204000.json','["上高殊邑尚吾鄉，千里相忘是建康。", "王事賢勞宜不廢，師生義重詎能忘。"]'),
('3bf5857a-d2d8-4d74-b34a-1d1042950b23','出朝賦歸來好  其一','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，籬下菊花應未老。',28,'全唐诗/poet.song.204000.json','["歸來好，籬下菊花應未老。", "晚香猶可薦清樽，淵明醉後和衣倒。"]'),
('fdf3bb8d-e941-407a-85fd-ad21e9b1c5b8','出朝賦歸來好  其二','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，兩歲引年章屢草。',28,'全唐诗/poet.song.204000.json','["歸來好，兩歲引年章屢草。", "聖恩寬辱不容閑，今得生還真大造。"]'),
('c457bbee-cbcc-4fd9-93e4-14b0941ea628','出朝賦歸來好  其三','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，顔巷安居樂吾道。',28,'全唐诗/poet.song.204000.json','["歸來好，顔巷安居樂吾道。", "此行不敢怨風聞，只恨舒君言不早。"]'),
('043fa54d-1f62-466c-a5a6-d61549d4061c','出朝賦歸來好  其四','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，一入山林迹如掃。',28,'全唐诗/poet.song.204000.json','["歸來好，一入山林迹如掃。", "杜門謝客免愆尤，几凈窗明讀莊老。"]'),
('cd3cd3b6-a29e-45d5-b09a-390d80ded931','出朝賦歸來好  其五','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，菊後梅前宜問道。',28,'全唐诗/poet.song.204000.json','["歸來好，菊後梅前宜問道。", "退朝羽翼此心生，從此五更無起早。"]'),
('02c73a07-e0d5-4278-91c1-fdfeb974d172','出朝賦歸來好  其六','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，從此五更無起早。',28,'全唐诗/poet.song.204000.json','["歸來好，從此五更無起早。", "雖然𤱶畝瓣香心，天子萬年多壽考。"]'),
('c9618b64-086b-4764-9a95-9eb014f629bc','出朝賦歸來好  其七','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，三徑須宜有花草。',28,'全唐诗/poet.song.204000.json','["歸來好，三徑須宜有花草。", "於中竹柏可耐寒，更種長松成四老。"]'),
('540d9660-0261-42e6-957d-b74b4dddea3b','出朝賦歸來好  其八','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，飲食起居隨晏早。',28,'全唐诗/poet.song.204000.json','["歸來好，飲食起居隨晏早。", "閑身樂得未龍鍾，東阡西陌尋芳草。"]'),
('debd62cb-95aa-4a32-88f9-701859f14fd9','出朝賦歸來好  其九','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，茅簷曝背無煩惱。',28,'全唐诗/poet.song.204000.json','["歸來好，茅簷曝背無煩惱。", "欣時讀易困時眠，箇中輸與癡頑老。"]'),
('f3c3b343-8818-4b21-a285-f41051a00dcc','出朝賦歸來好  其一○','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，龍門有山名七寶。',28,'全唐诗/poet.song.204000.json','["歸來好，龍門有山名七寶。", "宿生泉石頗有緣，往來儘可休吾老。"]'),
('73e5f87b-deed-4f75-969b-259783fc16de','出朝賦歸來好  其一一','徐經孫','宋','宋诗','song-poetry','','[]','歸來好，萬喜千歡無煩惱。',28,'全唐诗/poet.song.204000.json','["歸來好，萬喜千歡無煩惱。", "日課吾孫讀古書，此是吾家傳世寶。"]'),
('27b8a7dc-2ff1-47c7-ba68-6f2897f9291e','北坑拜掃有感','徐經孫','宋','宋诗','song-poetry','','[]','手植松楸四十年，扶疏枝葉欲參天。',32,'全唐诗/poet.song.204000.json','["手植松楸四十年，扶疏枝葉欲參天。", "四兒惟有衰翁在，時領孫曹拜墓前。"]'),
('d931702e-00f0-4135-a0b7-20345898e347','題金魚郎','徐經孫','宋','宋诗','song-poetry','','[]','金魚有術妙談天，走遍江湖謁踆躔。',32,'全唐诗/poet.song.204000.json','["金魚有術妙談天，走遍江湖謁踆躔。", "玉带貴人如一遇，定知換酒不論錢。"]'),
('f9a432b1-68f9-4674-8208-d4412bb0ef9c','贈射虎人','徐經孫','宋','宋诗','song-poetry','','[]','馮婦下車須有勇，將軍射石亦通神。',32,'全唐诗/poet.song.204000.json','["馮婦下車須有勇，將軍射石亦通神。", "南山白額新除害，好賞今時射虎人。"]'),
('68804f51-9323-405d-a16f-dfcc800f5174','去國','徐經孫','宋','宋诗','song-poetry','','[]','崎嶇山路記曾遊，誰識爲臣去國愁。',64,'全唐诗/poet.song.204000.json','["崎嶇山路記曾遊，誰識爲臣去國愁。", "柏府官中羞豸角，桐江臺上愧羊裘。", "重違君命留行者，既竭吾才歸去休。", "霜露感人千里思，松楸未掃已三秋。"]'),
('325aa5a8-860a-4aa9-8f24-2f7ab564fd0d','北壑瀛洲亭','徐經孫','宋','宋诗','song-poetry','','[]','山中有水水中洲，欲訪蓬瀛此處求。',64,'全唐诗/poet.song.204000.json','["山中有水水中洲，欲訪蓬瀛此處求。", "孤嶼插天如搢笏，危亭臨渚似飛樓。", "並崖香草仙餘藥，隔岸人家風引舟。", "箇裏藏脩功行滿，弘文學館快情遊。"]'),
('eb2394ce-c7c1-41f8-957d-e99c475d3eeb','山塘精舍','徐經孫','宋','宋诗','song-poetry','','[]','歸來魚鳥亦相親，草創山塘謾以名。',64,'全唐诗/poet.song.204000.json','["歸來魚鳥亦相親，草創山塘謾以名。", "旋築堤防留水住，盡除菑翳聽松聲。", "族姻語語人情洽，雲勢陰陰天氣清。", "好續溪山真率會，從今八景又重成。"]'),
('d48aa31c-fcaf-4162-b69c-a0446cc71eff','恭和御製詩','徐經孫','宋','宋诗','song-poetry','','[]','多士新彈貢禹冠，對天忠切動龍顔。',64,'全唐诗/poet.song.204000.json','["多士新彈貢禹冠，對天忠切動龍顔。", "臚傳聲徹頒袍笏，燕喜筵開肅佩環。", "樂奏簫韶成廣內，詩成奎畫照人間。", "微臣捧詔慚疏拙，也抱傳宣拜賜還。"]'),
('420e7f10-6834-456a-8f75-cdcbc95325a2','弭節堂','徐經孫','宋','宋诗','song-poetry','','[]','慇懃主禮重賓榮，弭節新堂慶落成。',64,'全唐诗/poet.song.204000.json','["慇懃主禮重賓榮，弭節新堂慶落成。", "語熟不妨移座密，更長那復記杯行。", "轄投相共傳佳話，榻下于今見故情。", "太史定知牛斗分，客星也傍使星明。"]'),
('4ecba42b-cec7-4d74-aa47-00c25303e8ca','慶仲明弟領鄉薦','徐經孫','宋','宋诗','song-poetry','','[]','記得溪山橫膝語，何時解取世科收。',64,'全唐诗/poet.song.204000.json','["記得溪山橫膝語，何時解取世科收。", "薦名恰在二八數，屈指重來四十秋。", "歲月滔滔催後進，功名冉冉繼前脩。", "福州得捷知安福，更願君恩賜狀頭。"]'),
('68351dee-f7da-4a8d-b305-be5d6581fbba','福州即景','徐經孫','宋','宋诗','song-poetry','','[]','一別居諸歲月增，遥聞此景畫難能。',64,'全唐诗/poet.song.204000.json','["一別居諸歲月增，遥聞此景畫難能。", "潮田種稻重收穀，道路逢人半是僧。", "城裏三山千簇寺，夜間七塔百枝燈。", "常年六月東山裏，地湧寒泉潄齒冰。"]'),
('2c4d94cd-32e5-4afd-8f54-551d0c6454bb','福州鹿鳴宴','徐經孫','宋','宋诗','song-poetry','','[]','鹿鳴今日宴佳賓，六萬場中一百人。',64,'全唐诗/poet.song.204000.json','["鹿鳴今日宴佳賓，六萬場中一百人。", "鰲嶺峰前連巨釣，龍臺高處耀脩鱗。", "假途文字皆由命，實地功名好致身。", "得意春風馬蹄速，杏園交慶綠袍新。"]'),
('27658d1c-f29d-4354-9a57-727747e10d48','長孫敏學授承務郎','徐經孫','宋','宋诗','song-poetry','','[]','辛勤場屋一書生，六卷時文謾策名。',64,'全唐诗/poet.song.204000.json','["辛勤場屋一書生，六卷時文謾策名。", "身事兩朝奚所補，恩覃五世亦何榮。", "前人慶澤宜豐報，爾輩官曹詎可輕。", "移孝爲忠斯不負，更須勤學紹家聲。"]'),
('fe43ee7a-6041-4631-b0a7-3f6dfb38c2dd','黄元肇江山風月閣','徐經孫','宋','宋诗','song-poetry','','[]','江山到處堪圖畫，風月無邊自古今。',64,'全唐诗/poet.song.204000.json','["江山到處堪圖畫，風月無邊自古今。", "但要清明如外境，便分動靜即吾心。", "坡仙取用原無盡，康節登臨豈浪吟。", "天理流行須體識，莫將嘲弄費光陰。"]'),
('ffd21de3-42b0-4eb2-8663-c6ad073c4d7c','培芳亭草創胥會','徐經孫','宋','宋诗','song-poetry','','[]','培芳草創强鋪筵，畫出清明三月天。',64,'全唐诗/poet.song.204000.json','["培芳草創强鋪筵，畫出清明三月天。", "長少團欒還五世，笑談邂逅集群賢。", "或歌或弈杯無算，非竹非絲樂自然。", "過則相規善相勉，須令和氣藹無邊。"]'),
('50482178-f5dd-4727-be32-fb69c5141fef','送仲時弟','徐經孫','宋','宋诗','song-poetry','','[]','江關千里隔山川，有弟能來慰眼前。',64,'全唐诗/poet.song.204000.json','["江關千里隔山川，有弟能來慰眼前。", "方喜鴈行隨處樂，可堪蟾影別時圓。", "暑行勿亟宜强飯，湍激多驚莫問船。", "歸到家山相勞苦，團欒恰是菊花天。"]'),
('26d2d4b7-7d11-4d50-8f3d-4f2f36d7c3eb','題西坡屷心亭','徐經孫','宋','宋诗','song-poetry','','[]','翛然古木湛然池，樂意相關自造微。',64,'全唐诗/poet.song.204000.json','["翛然古木湛然池，樂意相關自造微。", "莊子非魚真實問，海翁狎鳥本忘機。", "樽中有酒逢人酌，琴上無弦信手揮。", "禿盡剡藤吟不就，妙哉川泳與雲飛。"]'),
('a5d5bff6-c128-40ae-9074-7089dcb1ea2c','賀汝立拜恩封','徐經孫','宋','宋诗','song-poetry','','[]','君恩歲序兩俱新，鸞誥叨榮鶴髮親。',64,'全唐诗/poet.song.204000.json','["君恩歲序兩俱新，鸞誥叨榮鶴髮親。", "天上龍光疏雨露，堂前燕笑壽松椿。", "孫枝子舍皆騰踏，蘭省璧池交問津。", "此去椒盤重獻頌，斑衣中有綠衣人。"]'),
('3c07780d-0b5c-4b9b-a0f8-d2ae020ad3c1','和李後林分惠瓊花降字韻','徐經孫','宋','宋诗','song-poetry','','[]','詩句尋芳自抑揚，一觀佳什覺心降。',64,'全唐诗/poet.song.204000.json','["詩句尋芳自抑揚，一觀佳什覺心降。", "山中玉蕊雖無數，天上瓊花孰有雙。", "愧我未能瞻后土，荷君分惠到南窗。", "從今可小中興瑞，大地移根到此邦。"]'),
('38062dbe-adb6-4a54-9a51-ed3893afd7f7','乙丑三月十二夜夢得家有園池樂壽康之句覺而足成效邵康節作首尾吟八首  其一','徐經孫','宋','宋诗','song-poetry','','[]','家有園池樂壽康，四時隨分得徜徉。',64,'全唐诗/poet.song.204000.json','["家有園池樂壽康，四時隨分得徜徉。", "鱼遊春水吾同趣，蓮拆秋房客共嘗。", "風裏松聲傳古調，雪中梅蕊驗初陽。", "官閑身老猶幫俸，家有園池樂壽康。"]'),
('498f60f7-6e7a-4e78-8444-735c55d8a336','乙丑三月十二夜夢得家有園池樂壽康之句覺而足成效邵康節作首尾吟八首  其二','徐經孫','宋','宋诗','song-poetry','','[]','家有園池樂壽康，閑中日月覺偏長。',64,'全唐诗/poet.song.204000.json','["家有園池樂壽康，閑中日月覺偏長。", "睡餘携幼遊花圃，飯後呼童給鶴糧。", "堆案縱橫書數冊，隨盤歡喜酒三觴。", "客來問我渾無事，家有園池樂壽康。"]'),
('5f30c32f-ca7c-4115-a6fd-baab7982ec62','乙丑三月十二夜夢得家有園池樂壽康之句覺而足成效邵康節作首尾吟八首  其三','徐經孫','宋','宋诗','song-poetry','','[]','家有園池樂壽康，君恩廣大壽無疆。',64,'全唐诗/poet.song.204000.json','["家有園池樂壽康，君恩廣大壽無疆。", "玉龍自是神仙骨，紫殿容依日月光。", "不織不蠶時賜帛，無功無過歲支糧。", "老臣得此知慚愧，家有園池樂壽康。"]'),
('a4328f01-46cc-410f-8e24-08644ccb2921','乙丑三月十二夜夢得家有園池樂壽康之句覺而足成效邵康節作首尾吟八首  其四','徐經孫','宋','宋诗','song-poetry','','[]','家有園池樂壽康，撫存松菊未爲荒。',64,'全唐诗/poet.song.204000.json','["家有園池樂壽康，撫存松菊未爲荒。", "斛租不及胡椒數，樊圃何如步障長。", "靜裏謾看猿弄臂，閑中時聽鶴鳴吭。", "山林陰密宜藏拙，家有園池樂壽康。"]'),
('d7ec8b75-320d-4e5c-80b4-2ce46434617d','乙丑三月十二夜夢得家有園池樂壽康之句覺而足成效邵康節作首尾吟八首  其五','徐經孫','宋','宋诗','song-poetry','','[]','家有園池樂壽康，人生何用苦乾忙。',64,'全唐诗/poet.song.204000.json','["家有園池樂壽康，人生何用苦乾忙。", "三冬慣曝茅簷日，九夏貪眠竹簟凉。", "大寫文書遮老眼，熟煨芋栗飽枯腸。", "無榮無辱渾無事，家有園池樂壽康。"]'),
('837e933e-e064-42a4-a339-6c4466dc946d','乙丑三月十二夜夢得家有園池樂壽康之句覺而足成效邵康節作首尾吟八首  其六','徐經孫','宋','宋诗','song-poetry','','[]','家有園池樂壽康，北窗何敢傲羲皇。',64,'全唐诗/poet.song.204000.json','["家有園池樂壽康，北窗何敢傲羲皇。", "池開滿引靈淵脈，戶廠西迎太乙光。", "初節易渝誰保晚，好人難做必觀常。", "老來自適閑中趣，家有園池樂壽康。"]'),
('64dc7729-d12d-4148-8f59-73e0924f6341','乙丑三月十二夜夢得家有園池樂壽康之句覺而足成效邵康節作首尾吟八首  其七','徐經孫','宋','宋诗','song-poetry','','[]','家有園池樂壽康，晴簷曝日小春陽。',64,'全唐诗/poet.song.204000.json','["家有園池樂壽康，晴簷曝日小春陽。", "爐存榾柮火難過，𧣴酌芹蔬味更長。", "更覺寒威潛出戶，便令和氣復連床。", "團圓家慶堪圖寫，家有園池樂壽康。"]'),
('54f86f26-42a6-489e-b909-96a3dde8a187','乙丑三月十二夜夢得家有園池樂壽康之句覺而足成效邵康節作首尾吟八首  其八','徐經孫','宋','宋诗','song-poetry','','[]','家有園池樂壽康，浮雲富貴利名場。',64,'全唐诗/poet.song.204000.json','["家有園池樂壽康，浮雲富貴利名場。", "欄栽藥相揚樓美，壇植花王姚魏良。", "忘機久結盟鷗社，得意閑觀狎鷺塘。", "提壺挈榼堪遊賞，家有園池樂壽康。"]'),
('8381159b-c21e-4d62-997c-ddd0a3e87d04','丙寅九月送龍門課試士友','徐經孫','宋','宋诗','song-poetry','','[]','凉風九月菊花天，路近龍門自坦然。',64,'全唐诗/poet.song.204000.json','["凉風九月菊花天，路近龍門自坦然。", "勝友如雲儒雅集，雄文麗藻燦連篇。", "平時學問勤攻玉，聖世功名好着鞭。", "黄屋臨軒新策士，姓名一一聽臚傳。"]'),
('dd0ae9d1-6736-402e-91f1-e5a1dc2db915','和胡適齋韻','徐經孫','宋','宋诗','song-poetry','','[]','得得高軒到澗泉，真成空谷喜跫然。',64,'全唐诗/poet.song.204000.json','["得得高軒到澗泉，真成空谷喜跫然。", "三詩惠我驚人句，八秩如公現世仙。", "一見長身知潤德，頗疑盛際有遺賢。", "君王已獲非熊兆，釣隠如今起渭川。"]'),
('2c0a10f7-83b6-489e-988d-77dc87348c69','悼陶德芳','徐經孫','宋','宋诗','song-poetry','','[]','袖有銀毫刺史章，先生不是薄淮陽。',64,'全唐诗/poet.song.204000.json','["袖有銀毫刺史章，先生不是薄淮陽。", "倦遊誰不思三徑，勇退今惟見一堂。", "講席有功周子學，義田無愧范公莊。", "忍聞耆舊銘旌舉，此語吟成淚數行。"]'),
('22de624e-7c84-434b-a6fd-3a1f0976e969','贈曾司戶','徐經孫','宋','宋诗','song-poetry','','[]','君家螺江頭，我家劍江邊。',60,'全唐诗/poet.song.204000.json','["君家螺江頭，我家劍江邊。", "千載會相望，飲水同一川。", "朅來古梅關，相識春風前。", "高義軋層漢，清譚響幽泉。", "努力學往哲，勿爲時俗牽。"]'),
('1d44c62d-7884-4edb-bede-1afeafc7067a','和黎丞梅關嶺','徐經孫','宋','宋诗','song-poetry','','[]','峭壁接高天，閒雲淡橫嶺。',48,'全唐诗/poet.song.204000.json','["峭壁接高天，閒雲淡橫嶺。", "稍便僧房靜，未覺官曹冷。", "風月兩閒人，山川一佳境。", "誰歟共茲樂，老仙白垂領。"]'),
('53bd4d1d-771a-4f76-a398-f5a093abd934','丙戌新春偶成','徐經孫','宋','宋诗','song-poetry','','[]','新年十許日，才有一篇詩。',48,'全唐诗/poet.song.204000.json','["新年十許日，才有一篇詩。", "鄉思風中亂，春心雨裏知。", "病緣衰驟至，懶與睡相宜。", "暗想泉溪上，杜鵑啼故枝。"]'),
('4bda2e83-e08d-4faf-a0bf-ae171092a711','小英石峰','徐經孫','宋','宋诗','song-poetry','','[]','舊作英巖隠，今爲庾嶠行。',48,'全唐诗/poet.song.204000.json','["舊作英巖隠，今爲庾嶠行。", "雖然一拳許，有此數峰青。", "崷崒警凡目，堅剛悖世情。", "墨卿相指似，只尺是蓬瀛。"]'),
('8233a3c1-1fec-40f8-a8e0-4d56bf798cae','送太庾黎丞','徐經孫','宋','宋诗','song-poetry','','[]','客懷秋易惡，送客更當秋。',48,'全唐诗/poet.song.204000.json','["客懷秋易惡，送客更當秋。", "薄宦相從久，孤征肯暫留。", "酒輕離思重，目短大江流。", "黄菊聊持贈，寒香晚不羞。"]'),
('ed743b73-baf7-4656-857d-bebcf19e7892','月夜赴郡會歸鞭轉不成寐觸事感懷','徐經孫','宋','宋诗','song-poetry','','[]','庾山高入雲，章水清見骨。',48,'全唐诗/poet.song.204000.json','["庾山高入雲，章水清見骨。", "山高晚宜梅，水清寒浸月。", "美人天一方，雲烟妙空闊。", "带月簪梅花，獨起舞殘雪。"]'),
('3248b470-8f22-4d0a-a85d-40302f59f7ce','雜興','徐經孫','宋','宋诗','song-poetry','','[]','梅花亦何奇，偏得幽人愛。',24,'全唐诗/poet.song.204000.json','["梅花亦何奇，偏得幽人愛。", "清寒風雪夜，一枝靜相對。"]'),
('18b760dd-1989-4fa4-908c-f2e592bf244a','秀巖  其一','徐經孫','宋','宋诗','song-poetry','','[]','風露增凉曉氣清，崎嶇取路遶溝堘。',64,'全唐诗/poet.song.204000.json','["風露增凉曉氣清，崎嶇取路遶溝堘。", "早田得雨秋耕遍，晚稻如雲歲事登。", "古澗蛇行泉曲折，崇岡虎踞石稜層。", "撩人野興皆詩料，自愧塵埃謝不能。"]'),
('3ab777be-aa2d-4825-b30b-102b61595a58','秀巖  其二','徐經孫','宋','宋诗','song-poetry','','[]','四山環抱似圍城，石屋中間地砥平。',64,'全唐诗/poet.song.204000.json','["四山環抱似圍城，石屋中間地砥平。", "天隔俗塵飛不到，神開寶藏畫難成。", "岩分上下光皆透，水有往來蹤不明。", "可惜韓張期界上，當時過此未知名。"]'),
('e2163b4a-f288-43cd-9044-65ef60e9d363','梅花','徐經孫','宋','宋诗','song-poetry','','[]','約臂金寒拓綺疏，搔頭玉重壓香酥。',32,'全唐诗/poet.song.204000.json','["約臂金寒拓綺疏，搔頭玉重壓香酥。", "含章檐下新妝額，試啟菱花得似無。"]'),
('2c54becd-bf40-4d43-a8f7-6f27b9227a5c','西陵望','嚴羽','宋','宋诗','song-poetry','','[]','西陵終日望，不見有歸橈。',24,'全唐诗/poet.song.204000.json','["西陵終日望，不見有歸橈。", "欲去猶回首，寒江起暮潮。"]'),
('e9b57a81-bc30-4c76-a2b0-f75371eab97f','閨怨  其一','嚴羽','宋','宋诗','song-poetry','','[]','昨夜中秋月，含愁顧影頻。',24,'全唐诗/poet.song.204000.json','["昨夜中秋月，含愁顧影頻。", "空留可憐影，不見可憐人。"]'),
('4c88996b-84bc-43a6-9a91-3cd3405256f8','閨怨  其二','嚴羽','宋','宋诗','song-poetry','','[]','欲作遼陽夢，愁多自不成。',24,'全唐诗/poet.song.204000.json','["欲作遼陽夢，愁多自不成。", "錯嫌烏臼鳥，半夜隔窗鳴。"]'),
('7bea24de-8652-440b-ba5e-7664a7e78d76','舟中示同志','嚴羽','宋','宋诗','song-poetry','','[]','見說春帆外，康廬水石多。',24,'全唐诗/poet.song.204000.json','["見說春帆外，康廬水石多。", "期君一把臂，長嘯入煙蘿。"]'),
('f5816471-cf3d-4849-9994-966352ca0adf','塞下絕句','嚴羽','宋','宋诗','song-poetry','','[]','莫被封侯誤，封侯似漢家。',24,'全唐诗/poet.song.204000.json','["莫被封侯誤，封侯似漢家。", "君看城下骨，萬古一黄沙。"]'),
('8bb59c76-daeb-43dd-9222-f1d50f0a95a2','送友人之楚州','嚴羽','宋','宋诗','song-poetry','','[]','黯黯離筵夕照收，江城羌笛起邊愁。',32,'全唐诗/poet.song.204000.json','["黯黯離筵夕照收，江城羌笛起邊愁。", "念君此去三千里，何處關山是楚州。"]'),
('b6bcf90b-aed3-44e3-8029-e74e4cac3aa1','酬故人見贈','嚴羽','宋','宋诗','song-poetry','','[]','湘江南去少人行，瘴雨蠻煙白草生。',32,'全唐诗/poet.song.204000.json','["湘江南去少人行，瘴雨蠻煙白草生。", "誰念梁園舊詞客，桄榔樹下獨聞鶑。"]'),
('a98043f7-094c-4ef2-a9dc-cff45f322ecc','羽林郎','嚴羽','宋','宋诗','song-poetry','','[]','貂帽狐裘塞北妝，黄鬚年少羽林郎。',32,'全唐诗/poet.song.204000.json','["貂帽狐裘塞北妝，黄鬚年少羽林郎。", "彎弓不怕天山雪，生縛名王入建章。"]'),
('0bb41e16-17ec-4c6f-8a38-5f4eb2577003','閨中詞','嚴羽','宋','宋诗','song-poetry','','[]','良人西去擊狂胡，妾在閨中對影居。',32,'全唐诗/poet.song.204000.json','["良人西去擊狂胡，妾在閨中對影居。", "萬里長看天外月，一生空得夢中書。"]'),
('cb3e60da-04d1-4c31-9222-b5c8f9add213','塞下曲六首  其一','嚴羽','宋','宋诗','song-poetry','','[]','孤城莽莽秋天外，竟日無雲空自哀。',32,'全唐诗/poet.song.204000.json','["孤城莽莽秋天外，竟日無雲空自哀。", "忽怪一時天盡黑，合羣胡雁向西來。"]'),
('9598bcff-c221-4935-8c2c-55ac80124cc7','塞下曲六首  其二','嚴羽','宋','宋诗','song-poetry','','[]','渺渺雲沙散橐駝，風吹黄葉渡黄河。',32,'全唐诗/poet.song.204000.json','["渺渺雲沙散橐駝，風吹黄葉渡黄河。", "羌人半醉蒲萄熟，塞雁初肥苜蓿多。"]'),
('71232bab-263e-4d80-9308-97f720dd32dd','塞下曲六首  其三','嚴羽','宋','宋诗','song-poetry','','[]','古戍秋生畫角哀，思歸泣盡望鄉臺。',32,'全唐诗/poet.song.204000.json','["古戍秋生畫角哀，思歸泣盡望鄉臺。", "胡天日落寒風起，但見黄沙萬里來。"]'),
('e88aa149-4636-4cf3-a399-c6f5255f5d59','塞下曲六首  其四','嚴羽','宋','宋诗','song-poetry','','[]','一身遠客逐戎旌，落日蕭條望古城。',32,'全唐诗/poet.song.204000.json','["一身遠客逐戎旌，落日蕭條望古城。", "漸近磧西無水草，北風沙起橐駝驚。"]'),
('869f438b-4448-4863-9a10-43682aa2f056','塞下曲六首  其五','嚴羽','宋','宋诗','song-poetry','','[]','玉關西去更無春，滿眼蓬蒿起塞塵。',32,'全唐诗/poet.song.204000.json','["玉關西去更無春，滿眼蓬蒿起塞塵。", "漢馬不歸青海月，胡笳愁殺隴頭人。"]'),
('bcdf932a-1dc2-4a0c-874f-985d4004be66','塞下曲六首  其六','嚴羽','宋','宋诗','song-poetry','','[]','天山一夜雪漫漫，虜去營空戰血乾。',32,'全唐诗/poet.song.204000.json','["天山一夜雪漫漫，虜去營空戰血乾。", "十萬征人回馬首，天邊烽火報平安。"]'),
('e29979f1-da31-439a-82e4-8521d718dfe5','江上送客','嚴羽','宋','宋诗','song-poetry','','[]','留君夜飲北風寒，且折梅花耐醉歡。',32,'全唐诗/poet.song.204000.json','["留君夜飲北風寒，且折梅花耐醉歡。", "明日桐廬潮去遠，孤帆天際若爲看。"]'),
('ace2ee24-0dad-40f7-b16c-870a3d423756','頼成之還自江西感舊有贈','嚴羽','宋','宋诗','song-poetry','','[]','十年心事兩蹉跎，南北東西別恨多。',32,'全唐诗/poet.song.204000.json','["十年心事兩蹉跎，南北東西別恨多。", "今日樽前重把手，相看爭奈白頭何。"]'),
('e6dada2c-e905-4710-82d9-ea99a11c02f7','聞笛','嚴羽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','江上誰家吹笛聲，月明霜白不堪聽。',32,'全唐诗/poet.song.205000.json','["江上誰家吹笛聲，月明霜白不堪聽。", "孤舟萬里瀟湘客，一夜歸心滿洞庭。"]'),
('697484c3-1142-4683-834d-2d3a63a3978d','舟中望落星寺','嚴羽','宋','宋诗','song-poetry','','[]','日暮黄沙壓岸平，江心風浪暗冥冥。',32,'全唐诗/poet.song.205000.json','["日暮黄沙壓岸平，江心風浪暗冥冥。", "南康一望何由到，愁殺舟中指落星。"]'),
('370fe12a-abd8-456f-8a9f-943cb56e0b5d','答李友山山中留別','嚴羽','宋','宋诗','song-poetry','','[]','已恨青山臨渡口，相思回首隔夫君。',32,'全唐诗/poet.song.205000.json','["已恨青山臨渡口，相思回首隔夫君。", "更堪重到相思處，不見青山見白雲。"]'),
('acc7a65a-b8ad-4de6-9ec5-2a8cefc2e0a5','秋日','嚴羽','宋','宋诗','song-poetry','','[]','西風催我轉胡牀，坐落秋山午夢凉。',32,'全唐诗/poet.song.205000.json','["西風催我轉胡牀，坐落秋山午夢凉。", "蟬老樹深音響別，滿天風雨带斜陽。"]'),
('ca62b5c3-973e-4d38-a4e5-d9c04fd651ed','新凉','嚴羽','宋','宋诗','song-poetry','','[]','小院新凉水竹通，鳴蟬聲斷晚來風。',32,'全唐诗/poet.song.205000.json','["小院新凉水竹通，鳴蟬聲斷晚來風。", "忽然坐睡瞢騰去，不覺殘書落手中。"]'),
('e58bffc4-479a-4bf0-a1ee-6902b2504e1a','臨池','嚴羽','宋','宋诗','song-poetry','','[]','乍凉池館雨初收，菱角蓮房共趁秋。',32,'全唐诗/poet.song.205000.json','["乍凉池館雨初收，菱角蓮房共趁秋。", "獨恨碧波渾占却，更無賸水浴沙鷗。"]'),
('9aa3c035-f968-480a-8342-062c4e35c4ea','北風','嚴羽','宋','宋诗','song-poetry','','[]','夜來雨雪北風顛，吹得波濤欲暗天。',32,'全唐诗/poet.song.205000.json','["夜來雨雪北風顛，吹得波濤欲暗天。", "世上如今少知己，煩君牢繫釣魚船。"]'),
('d4313096-565b-48e2-8b93-8712d0dfacbe','燕','嚴羽','宋','宋诗','song-poetry','','[]','巢破春雛半不存，銜泥空傍主人門。',32,'全唐诗/poet.song.205000.json','["巢破春雛半不存，銜泥空傍主人門。", "一生巧計輸黄雀，飲啄官倉長子孫。"]'),
('e1f46107-625a-467e-af7a-c85ce076c974','吳中送友歸豫章','嚴羽','宋','宋诗','song-poetry','','[]','川程極目渺空波，送爾歸舟奈別何。',32,'全唐诗/poet.song.205000.json','["川程極目渺空波，送爾歸舟奈別何。", "南國音書須早寄，江湖春雁已無多。"]'),
('022ce819-caa2-488b-81bd-536af5951f76','臨川送周月船入京','嚴羽','宋','宋诗','song-poetry','','[]','別時把酒已魂銷，別後音書更闃寥。',32,'全唐诗/poet.song.205000.json','["別時把酒已魂銷，別後音書更闃寥。", "一片離心寄春水，隨君船入浙江潮。"]'),
('c8a8b9d4-54e0-4f70-8b93-52b0bbd3e55f','別客','嚴羽','宋','宋诗','song-poetry','','[]','客鬢風霜晚，離亭鼓角聞。',48,'全唐诗/poet.song.205000.json','["客鬢風霜晚，離亭鼓角聞。", "念君當此去，把袂不能分。", "衡霍連秋氣，瀟湘合暮雲。", "愁心將落葉，向晚共紛紛。"]'),
('a46188b3-0800-4895-bd02-97dd00280061','送張季遠入京','嚴羽','宋','宋诗','song-poetry','','[]','手把一枝菊，贈金千里行。',48,'全唐诗/poet.song.205000.json','["手把一枝菊，贈金千里行。", "山川遥滿目，何處是吳京。", "飲罷北風起，蕭蕭胡雁聲。", "東流儻未盡，見我望君情。"]'),
('b3b5e45c-6549-44aa-be49-e95b767df4ca','訪益上人蘭若','嚴羽','宋','宋诗','song-poetry','','[]','獨尋青蓮宇，行過白沙灘。',48,'全唐诗/poet.song.205000.json','["獨尋青蓮宇，行過白沙灘。", "一徑入松雪，數峰生暮寒。", "山僧喜客至，林閣借人看。", "吟罷拂衣去，鐘聲雲外殘。"]'),
('264e8def-1cc0-48a4-92d2-1b1f3e6199eb','從軍行  其一','嚴羽','宋','宋诗','song-poetry','','[]','朔風嘶馬動，遥想雁門秋。',48,'全唐诗/poet.song.205000.json','["朔風嘶馬動，遥想雁門秋。", "負劍辭鄉邑，彎弓赴國讎。", "黄榆連白草，河隴去悠悠。", "報主男兒事，焉論萬戶侯。"]'),
('1c04d226-d563-462f-8bb3-9e8f53540453','從軍行  其二','嚴羽','宋','宋诗','song-poetry','','[]','翩翩雙白馬，結束向幽燕。',48,'全唐诗/poet.song.205000.json','["翩翩雙白馬，結束向幽燕。", "借問誰家子，邯鄲俠少年。", "彎弓隨漢月，拂劍倚胡天。", "說與單于道，今秋莫近邊。"]'),
('aa5e46e8-0f61-467d-855d-f68e5d5e95d6','出塞行','嚴羽','宋','宋诗','song-poetry','','[]','將軍救朔邊，都護上祁連。',48,'全唐诗/poet.song.205000.json','["將軍救朔邊，都護上祁連。", "六郡飛傳檄，三河聚控弦。", "連營當太白，吹角動胡天。", "何日匈奴滅，中原得晏然。"]'),
('e16df86b-a8f7-43b3-ab40-7df638287249','關山月','嚴羽','宋','宋诗','song-poetry','','[]','今夜關山月，偏能照馬鞍。',48,'全唐诗/poet.song.205000.json','["今夜關山月，偏能照馬鞍。", "盧龍征戍客，圓缺幾回看。", "遥想金閨裏，應悲玉露寒。", "黄沙三萬里，何日是長安。"]'),
('56c46ff2-20dc-4cf0-9b6d-60ae8f068f90','蜀女怨','嚴羽','宋','宋诗','song-poetry','','[]','幾時離月峽，五見紫蘭凋。',48,'全唐诗/poet.song.205000.json','["幾時離月峽，五見紫蘭凋。", "塞雁隨魂斷，江花逐淚飄。", "沙頭南北客，京口去來潮。", "日日無消息，空登萬里橋。"]'),
('8bb797ca-a732-4e69-9987-57e74f0ea034','尋寧山人所居','嚴羽','宋','宋诗','song-poetry','','[]','幽人以道隠，結室巖之東。',48,'全唐诗/poet.song.205000.json','["幽人以道隠，結室巖之東。", "余亦避世客，逢君於此中。", "鳥因留食至，泉爲煉丹紅。", "向晚下山去，月高秋色空。"]'),
('51136e52-a3d5-4e80-b912-9729f42a0020','江樓夜月懷故山友人陳聘君吳樗鄉','嚴羽','宋','宋诗','song-poetry','','[]','昨夜江樓月，思君好斷腸。',48,'全唐诗/poet.song.205000.json','["昨夜江樓月，思君好斷腸。", "猿聲相應發，山色更青蒼。", "楚塞來書遠，閩關隔夢長。", "今朝看愁鬢，爲爾半成霜。"]'),
('685ba685-8039-4b1a-a764-942ef45be95d','江上有懷上官良史','嚴羽','宋','宋诗','song-poetry','','[]','憶君悵不樂，立馬大江邊。',48,'全唐诗/poet.song.205000.json','["憶君悵不樂，立馬大江邊。", "塞雁來無際，驚沙度颯然。", "客心懸日夜，書札斷雲天。", "莫作青山老，空爲人所憐。"]'),
('44633cfd-8aaf-4df9-90bb-efa8f7556978','聞雁','嚴羽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','遠客驚秋雁，高樓復異鄉。',48,'全唐诗/poet.song.205000.json','["遠客驚秋雁，高樓復異鄉。", "聲兼邊哨苦，影落楚雲長。", "此夜頭堪白，他山葉又黄。", "年年洞庭浪，飄泊更無行。"]'),
('52f6ca67-6f8b-44f9-959f-30720a003b3c','送上官偉長','嚴羽','宋','宋诗','song-poetry','','[]','歲晚長愁緒，嗟君更遠行。',48,'全唐诗/poet.song.205000.json','["歲晚長愁緒，嗟君更遠行。", "兵戈今日淚，江海故人情。", "此別幾時見，寒猿一夜鳴。", "致君相許在，回首壯心驚。"]'),
('6a16eba7-7673-4374-846c-4052a49ca387','有懷閬風山人','嚴羽','宋','宋诗','song-poetry','','[]','把酒忽惆悵，君今吳楚閒。',48,'全唐诗/poet.song.205000.json','["把酒忽惆悵，君今吳楚閒。", "孤雲隨馬首，風雨隔河關。", "心事竟何在，此行殊未還。", "空將百年意，泣向寶刀環。"]'),
('ea86cc1e-abce-47ee-a279-1b825df36b3b','避亂途中','嚴羽','宋','宋诗','song-poetry','','[]','回首兵戈地，遺黎見幾人。',48,'全唐诗/poet.song.205000.json','["回首兵戈地，遺黎見幾人。", "他鄉空白髮，故國又青春。", "多難堪長客，偷生愧此身。", "本無匡濟略，歎息謾傷神。"]'),
('49443157-965c-48a8-8f8b-a4da13fdaa4a','將往豫章留別張少尹父子','嚴羽','宋','宋诗','song-poetry','','[]','江西飛鳥外，極目渺離愁。',48,'全唐诗/poet.song.205000.json','["江西飛鳥外，極目渺離愁。", "同侶時催發，征人不可留。", "江湖雙淚眼，天地一孤舟。", "揮棹從茲去，空傷旅鬢秋。"]'),
('868d3f99-957f-4271-acc4-eb58ff6a8546','懷南昌舊遊','嚴羽','宋','宋诗','song-poetry','','[]','昨在南昌府，清遊不可窮。',48,'全唐诗/poet.song.205000.json','["昨在南昌府，清遊不可窮。", "杯行江色裏，棹進月明中。", "樓笛吹晴雪，菱歌漾晚風。", "坐來懷舊迹，萬里一飄蓬。"]'),
('10c5595c-dc88-4ecb-a9da-fb732b20a513','寄山中同志','嚴羽','宋','宋诗','song-poetry','','[]','我有三足麂，放之在碧山。',48,'全唐诗/poet.song.205000.json','["我有三足麂，放之在碧山。", "別來幾千日，昨夢忽乘還。", "松色入天盡，巖花落地閒。", "憑君一問訊，沿月上潺湲。"]'),
('97bd0c72-7e47-458d-bfe5-28675054e550','望西山','嚴羽','宋','宋诗','song-poetry','','[]','西山橫翠新，中隠古仙真。',48,'全唐诗/poet.song.205000.json','["西山橫翠新，中隠古仙真。", "笑取玉麈尾，揖茲丹霞人。", "雲從石洞出，月落滄江頻。", "予亦將高卧，藤蘿挂葛巾。"]'),
('65bd9228-f30d-4155-ba79-69839482c6cf','秋夜臨汝館懷友人陳聘君頼竹莊','嚴羽','宋','宋诗','song-poetry','','[]','秋聲動梧竹，月色滿庭蕪。',48,'全唐诗/poet.song.205000.json','["秋聲動梧竹，月色滿庭蕪。", "此夕懷良友，天涯各一隅。", "飛飛羣過雁，切切未栖烏。", "安得從君去，扁舟駕五湖。"]'),
('28f86dd9-d876-4b75-9121-76a38bb3a2c7','樟樹鎮醉後題','嚴羽','宋','宋诗','song-poetry','','[]','吾憐樟樹好，取醉欲無還。',48,'全唐诗/poet.song.205000.json','["吾憐樟樹好，取醉欲無還。", "酒壓鵝兒色，辭歌雉子斑。", "朱樓當碧水，紅日下青山。", "興罷揚鞭去，蒼蒼煙霧閒。"]'),
('03b9d755-ed75-4a3c-9212-c2a3eba1a1b0','張奕見訪逆旅','嚴羽','宋','宋诗','song-poetry','','[]','歲晚傷爲旅，君來適慰情。',48,'全唐诗/poet.song.205000.json','["歲晚傷爲旅，君來適慰情。", "郊扉寒少色，江渚夜多聲。", "報國憐他日，爲儒愧此生。", "那言離合際，更觸壯心驚。"]'),
('0022891f-cfdf-4b78-badc-52072193c3c1','豫章城','嚴羽','宋','宋诗','song-poetry','','[]','愛此城高處，回鞭醉每醒。',48,'全唐诗/poet.song.205000.json','["愛此城高處，回鞭醉每醒。", "江花兩岸白，煙樹一行青。", "雲學山舒態，天隨水賦形。", "吾多徐孺子，獨向此沈冥。"]'),
('1dcc8e14-6f49-4835-8a70-bdb570c1c2aa','江行','嚴羽','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u7f81\u65c5", "\u601d\u4e61"]','暝色蒹葭外，蒼茫旅眺情。',48,'全唐诗/poet.song.205000.json','["暝色蒹葭外，蒼茫旅眺情。", "殘雲和雁斷，新月带潮生。", "天到水中盡，舟隨樹杪行。", "離家今幾宿，厭聽棹歌聲。"]'),
('1784a46f-d257-475b-8f7c-b1f8c4289f44','舟中苦熱','嚴羽','宋','宋诗','song-poetry','','[]','舟行何太熱，岸上莽塵沙。',48,'全唐诗/poet.song.205000.json','["舟行何太熱，岸上莽塵沙。", "閃閃浪頻過，昏昏日又斜。", "年衰愁作客，秋近苦思家。", "蝗旱三千里，江淮兒女嗟。"]'),
('de3a2eab-09a4-4eb3-b336-f4fb3b2ba829','江上泊舟','嚴羽','宋','宋诗','song-poetry','','[]','天際長愁客，沙邊舊驛亭。',48,'全唐诗/poet.song.205000.json','["天際長愁客，沙邊舊驛亭。", "風低江浦雁，雪暗夜船鐙。", "窮老嗟身拙，狂歌畏酒醒。", "此生何定著，江漢一浮萍。"]'),
('cea05ae7-2da5-4855-a586-573eb5710603','逢戴式之往南方','嚴羽','宋','宋诗','song-poetry','','[]','此老相逢日，中原正用兵。',48,'全唐诗/poet.song.205000.json','["此老相逢日，中原正用兵。", "黄塵空北望，白首更南征。", "今古悲秋意，江湖惜別情。", "幾時羣盜滅，匹馬會神京。"]'),
('69000a43-d230-4a19-9a20-ca2a716db355','塞下','嚴羽','宋','宋诗','song-poetry','','[]','鞍馬連年出，關河萬里賒。',48,'全唐诗/poet.song.205000.json','["鞍馬連年出，關河萬里賒。", "將軍思報國，壯士恥還家。", "大漠春無草，天山雪作花。", "誰憐李都尉，白首沒胡沙。"]'),
('0e57c53f-4bdc-4ecb-81ef-a886425b173a','吳江春望','嚴羽','宋','宋诗','song-poetry','','[]','客有東南別，憑高正憶家。',48,'全唐诗/poet.song.205000.json','["客有東南別，憑高正憶家。", "青春江上草，湖日岸頭沙。", "去鳥無邊盡，歸帆幾處斜。", "音徽不可問，惆悵結瑶華。"]'),
('3fed300f-ae3c-4677-9b4c-58b5947d9f5d','閒居寄友','嚴羽','宋','宋诗','song-poetry','','[]','蕭條遺世心，江海坐來深。',48,'全唐诗/poet.song.205000.json','["蕭條遺世心，江海坐來深。", "擁褐閒窺沼，思山欲借琴。", "有幡煙際寺，無葉水邊林。", "不見同袍友，憑誰伴苦吟。"]'),
('77db474b-b278-46ea-9874-4fd58d34a360','天末遇周子俊自行在還言石屏消息','嚴羽','宋','宋诗','song-poetry','','[]','不見石屏老，相逢問客船。',48,'全唐诗/poet.song.205000.json','["不見石屏老，相逢問客船。", "長沙聞近別，行在定虛傳。", "兵革來書斷，江湖望眼穿。", "他時同話此，把臂喜應顛。"]'),
('cea6c6f4-562a-40b2-ae1c-35456df3fa4c','喜友人相訪擬韋蘇州作','嚴羽','宋','宋诗','song-poetry','','[]','朝朝竹林院，閉戶讀殘書。',48,'全唐诗/poet.song.205000.json','["朝朝竹林院，閉戶讀殘書。", "几閣晨風入，荒郊寒露餘。", "故人步屧至，清坐每踟躕。", "輟卷還留興，漱泉同飯蔬。"]'),
('f56467ac-a929-4ddb-abe9-c2bf787d04a1','有感六首  其一','嚴羽','宋','宋诗','song-poetry','','[]','誤喜殘胡滅，那知患更長。',48,'全唐诗/poet.song.205000.json','["誤喜殘胡滅，那知患更長。", "黄雲新戰路，白骨舊沙場。", "巴蜀連年哭，江淮幾郡瘡。", "襄陽根本地，回首一悲傷。"]'),
('db34d494-8d08-4a03-99cf-9980efb511da','有感六首  其二','嚴羽','宋','宋诗','song-poetry','','[]','哀痛天災日，絲綸罪己深。',48,'全唐诗/poet.song.205000.json','["哀痛天災日，絲綸罪己深。", "王師曾北伐，胡馬尚南侵。", "謀國知誰計，和親豈聖心。", "願聞修實德，聽納諫臣箴。"]'),
('e965eb0b-fc9f-4ec0-ac64-f1e77924ae5d','有感六首  其三','嚴羽','宋','宋诗','song-poetry','','[]','聞道單于使，年來入國頻。',48,'全唐诗/poet.song.205000.json','["聞道單于使，年來入國頻。", "聖朝思息戰，異域請和親。", "今日唐虞際，羣公社稷臣。", "不妨盟墨詐，須戒覆車新。"]'),
('4ca25ffe-45b5-435d-9e68-7b1b401a6c8a','有感六首  其四','嚴羽','宋','宋诗','song-poetry','','[]','災異時時見，羣情恐懼中。',48,'全唐诗/poet.song.205000.json','["災異時時見，羣情恐懼中。", "修攘今日急，反側向來同。", "社稷堪多難，安危係數公。", "殘生江海去，老作一漁翁。"]'),
('e1f09133-f482-4d6b-9547-96173873562a','有感六首  其五','嚴羽','宋','宋诗','song-poetry','','[]','陛下春秋盛，謙卑每責躬。',48,'全唐诗/poet.song.205000.json','["陛下春秋盛，謙卑每責躬。", "得無勞聖慮，猶未定儲宮。", "付託關神器，乾坤在至公。", "早聞宣詔冊，歡喜萬方同。"]'),
('a3bd1017-1fc7-4af8-ad67-171612c7280e','有感六首  其六','嚴羽','宋','宋诗','song-poetry','','[]','傳聞降北將，猶未悔狂圖。',48,'全唐诗/poet.song.205000.json','["傳聞降北將，猶未悔狂圖。", "忍召豺狼入，甘先矢石驅。", "聖朝何負汝，天意屬亡胡。", "試看山東寇，如今更有無。"]'),
('c2299e44-9abf-4433-8b29-eb11873a8d91','三衢邂逅周月船論心數日臨分賦此二首  其一','嚴羽','宋','宋诗','song-poetry','','[]','同是江湖客，居然歲月多。',48,'全唐诗/poet.song.205000.json','["同是江湖客，居然歲月多。", "心期看白髮，歸夢付滄波。", "子去見家遠，吾衰奈別何。", "幾時船上月，載酒定相過。"]'),
('29468b66-e222-4c7e-b7dc-15a17e2b5e81','三衢邂逅周月船論心數日臨分賦此二首  其二','嚴羽','宋','宋诗','song-poetry','','[]','戎馬相逢日，那知復此閒。',48,'全唐诗/poet.song.205000.json','["戎馬相逢日，那知復此閒。", "客愁詩莫遣，世事酒相關。", "江上孤舟在，天隅兩鬢斑。", "更將憂國淚，滿袖送君還。"]'),
('29592312-ca13-40e5-85e3-9befa1ca967f','秋日廬陵送杜子野還攝鍾陵糾掾','嚴羽','宋','宋诗','song-poetry','','[]','暫見還分手，誰能不黯然。',48,'全唐诗/poet.song.205000.json','["暫見還分手，誰能不黯然。", "去帆蘆葉浦，別酒菊花天。", "他日思良會，空囊檢贈篇。", "鍾陵有雁過，莫忘尺書傳。"]'),
('f3712831-3908-4569-8fdb-eb553e498360','臨川逢鄭遐之雲夢','嚴羽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','天涯十載無窮恨，老淚鐙前語罷垂。',64,'全唐诗/poet.song.205000.json','["天涯十載無窮恨，老淚鐙前語罷垂。", "明發又爲千里別，相思應盡一生期。", "洞庭波浪帆開晚，雲夢蒹葭鳥去遲。", "世亂音書到何日，關河一望不勝悲。"]'),
('94f38468-4295-41ae-979c-597733523a5e','再送頼成之出都','嚴羽','宋','宋诗','song-poetry','','[]','天際晴霞欲變春，高樓分手淚沾巾。',64,'全唐诗/poet.song.205000.json','["天際晴霞欲變春，高樓分手淚沾巾。", "荆吳渺渺孤舟遠，江海悠悠白髮新。", "萬事蹉跎堪更問，十年離別亦何頻。", "江村幾處梅花發，明日相思是旅人。"]'),
('75470c1e-7924-464b-9de7-d1578326c9bd','將之潯陽途中寄諸從昆弟','嚴羽','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','渺渺孤帆去幾程，悠悠天際望湓城。',64,'全唐诗/poet.song.205000.json','["渺渺孤帆去幾程，悠悠天際望湓城。", "一身避亂辭鄉國，千里相思隔弟兄。", "猨叫匡廬寒暮色，雁過彭蠡带秋聲。", "江湖此去方漂泊，腸斷風塵遠別情。"]'),
('09207b82-f438-417f-b5af-7d9a0558a67f','紫霞樓夜飲','嚴羽','宋','宋诗','song-poetry','','[]','西樓孤絕倚天青，我愛明河對戶橫。',64,'全唐诗/poet.song.205000.json','["西樓孤絕倚天青，我愛明河對戶橫。", "露滿碧梧風屢起，煙消綠嶠月初生。", "仙人共酌丹霞酒，逸侶同吹白玉笙。", "不向此時窮笑傲，更從何處豁高情。"]'),
('d9c1ef2a-6fa7-46c8-bd71-0f7c5bb79fad','客中別表叔吳季高','嚴羽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','悠悠遠別半生悲，白日相逢又語離。',64,'全唐诗/poet.song.205000.json','["悠悠遠別半生悲，白日相逢又語離。", "海內風塵驚不定，天邊消息到何時。", "洞庭旅雁春歸盡，瓜步寒潮夜落遲。", "惆悵孤舟從此去，江湖未敢定前期。"]'),
('a6495da3-cb12-4898-a9dc-1d75f2a398dc','和上官偉長蕪城晚眺','嚴羽','宋','宋诗','song-poetry','','[]','平蕪古堞暮蕭條，歸思馮高黯未消。',64,'全唐诗/poet.song.205000.json','["平蕪古堞暮蕭條，歸思馮高黯未消。", "京口寒煙鴉外滅，歷陽秋色雁邊遥。", "晴江木落長疑雨，暗浦風多欲上潮。", "惆悵此時頻極目，江南江北路迢迢。"]'),
('391a618d-8b03-4573-bf83-d1440d80c0cf','寄郭招甫時在潯陽','嚴羽','宋','宋诗','song-poetry','','[]','夢向三江買釣船，挂帆西去白雲邊。',64,'全唐诗/poet.song.205000.json','["夢向三江買釣船，挂帆西去白雲邊。", "窗開曉色香鑪現，門落寒聲瀑布懸。", "百年酒興陶彭澤，四海詩名孟浩然。", "何日真尋塵外迹，焚香酌茗話先賢。"]'),
('356378a6-3b62-4b81-90c3-2d9653cc95fa','登滕王閣','嚴羽','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','高閣馮空浩蕩開，當時遺跡幾荒苔。',64,'全唐诗/poet.song.205000.json','["高閣馮空浩蕩開，當時遺跡幾荒苔。", "煙含晚市悠悠見，沙带澄潭渺渺回。", "此日登臨分壯氣，百年淪落憶雄材。", "可憐萬古神交意，日暮荒凉一歎哀。"]'),
('ca53df3e-df6f-4f53-a694-b9f9d9978e6b','早春寄潛齋王史君','嚴羽','宋','宋诗','song-poetry','','[]','昏昏醉睡慵朝起，日日柴門待暖開。',64,'全唐诗/poet.song.205000.json','["昏昏醉睡慵朝起，日日柴門待暖開。", "春至任從花鳥笑，客來還仗酒罇陪。", "移舟動覓依江柳，策杖時能訪早梅。", "忽憶使君聯騎出，此時乘興幾銜杯。"]'),
('818442e7-6274-4200-a782-e084bb22cf3b','送崔九過丹陽却上荆門省親','嚴羽','宋','宋诗','song-poetry','','[]','江國歸心一雁牽，河樓分手數杯傳。',64,'全唐诗/poet.song.205000.json','["江國歸心一雁牽，河樓分手數杯傳。", "千崖萬壑秋聲裏，匹馬孤帆落照邊。", "牛渚寒波翻極浦，荆門晚樹合遥天。", "他時莫枉瑶華問，南北相思各渺然。"]'),
('cd316194-4c56-498b-ad4a-0ef1cfb7d776','舟中寄漢陽故人','嚴羽','宋','宋诗','song-poetry','','[]','浦口停留待信風，城邊落日亂流通。',64,'全唐诗/poet.song.205000.json','["浦口停留待信風，城邊落日亂流通。", "梧桐院落秋聲裏，橘柚人家晚照中。", "棹歌幾處驚寒切，砧響千村入耳同。", "日日愁心西北望，漢陽楓葉落無窮。"]'),
('419c2e0c-fc1e-4281-8f08-0ff9f450208b','夜泊','嚴羽','宋','宋诗','song-poetry','','[]','夜聞估客送將歸，葭菼蕭條月色微。',64,'全唐诗/poet.song.205000.json','["夜聞估客送將歸，葭菼蕭條月色微。", "萬里江湖何處極，孤舟鴻雁自相依。", "杯拋黄菊乾賒酒，城掩清砧罷擣衣。", "不奈此時心斷絕，長沙南去故人稀。"]'),
('31e8fc56-c56a-480b-98e6-9704a12353c2','送吳儀甫之合淝謁杜帥','嚴羽','宋','宋诗','song-poetry','','[]','丁年劍氣欲凌雲，況復才華迥不羣。',64,'全唐诗/poet.song.205000.json','["丁年劍氣欲凌雲，況復才華迥不羣。", "投筆幾回思出塞，賦詩此日去從軍。", "沙場青草時差緩，淝水紅旗捷屢聞。", "玉帳元戎桑梓舊，行看幕府策奇勳。"]'),
('a8e4f5a1-4b63-470b-894a-f8a3b8ce6f77','楚江晚思','嚴羽','宋','宋诗','song-poetry','','[]','旅思遥遥倦向南，誰家煙火起晴嵐。',64,'全唐诗/poet.song.205000.json','["旅思遥遥倦向南，誰家煙火起晴嵐。", "孤城歸鳥連寒角，極浦斜陽带遠帆。", "楓葉自能悲楚客，竹枝何用怨江潭。", "今朝欲寫風波恨，千里書成手自緘。"]'),
('f0ecd029-54b7-4b4c-a41f-79b47fd05273','送趙立道赴闕仍試春官即事感興因成五十韻','嚴羽','宋','宋诗','song-poetry','','[]','嗣聖中天日，遺氓憶漢時。',288,'全唐诗/poet.song.205000.json','["嗣聖中天日，遺氓憶漢時。", "一王新盛禮，萬國賀重熙。", "官爵霑寰宇，光明冠本支。", "窮冬辭老母，吉日赴京師。", "祖席明斜照，寒江結暮澌。", "停杯愁把袂，立馬語臨期。", "草動春前色，梅繁雪後枝。", "湖山饒逸興，士友重遊嬉。", "菱唱工迷客，荷舟穩放維。", "土風珍縞带，吳饌熟蓴絲。", "塔寺開金碧，樓臺漾淼瀰。", "雲連句踐國，江動伍員祠。", "閶闔春朝早，觚稜霽景遲。", "柳迎仙仗輭，花簇御樓欹。", "苜蓿來宛馬，櫻桃薦寢帷。", "周家千歲歷，漢殿萬年卮。", "駐蹕山川遠，櫜弓歲月移。", "天俄憂杞國，日再仰咸池。", "弓劍羣臣淚，園陵故國悲。", "乾坤開帝統，雨露豁宸私。", "蜂蠆何爲爾，豺狼欲問誰。", "箭流元帥幙，城立叛營旗。", "國體存矜恤，皇猷務遠綏。", "且從鷹一飽，自待虎雙疲。"]'),
('5bb5ba83-fc2d-46d3-899c-b3b6ad672d14','庚寅紀亂','嚴羽','宋','宋诗','song-poetry','','[]','承平盜賊起，喪亂降自天。',288,'全唐诗/poet.song.205000.json','["承平盜賊起，喪亂降自天。", "荼毒恣兩道，兵戈浩相纏。", "此邦禍最酷，賤子忍具言。", "朝廷討亂初，誰任主將權。", "輜重道閒來，隠隠何闐闐。", "殿前盡貔虎，所向當無堅。", "組練照川明，戈戟耀日鮮。", "父老當時言，此賊不容吞。", "軍興法律在，進退非得專。", "奈何忽舍去，屯壘隨之遷。", "留兵不五百，當賊逾數千。", "英英胡將軍，策馬奮獨先。", "出入突且擊，勢絕飄風旋。", "殺賊不知數，屍骸相疊穿。", "誰謂散復來，其徒奈實繁。", "須臾塞城郭，合沓迷妖氛。", "將軍怒一呼，誓死報國恩。", "拔劍復入陣，鼓聲俄不聞。", "哀哉失壯士，白日爲之昏。", "嗟彼城中人，欲生無由緣。", "連頭受屠戮，赤族罹禍冤。", "妻孥悉驅虜，道路號相牽。", "或有小失意，性命無由全。", "言語方出口，腰領已不連。"]'),
('310b2cf1-e39a-4c35-99bb-71d57ca9411a','贈呂仲祥','嚴羽','宋','宋诗','song-poetry','','[]','雲中誦招隠，高卧閑琴尊。',192,'全唐诗/poet.song.205000.json','["雲中誦招隠，高卧閑琴尊。", "忽有呂夫子，清晨叩我門。", "夫子忠烈後，家聲四海聞。", "神交三十載，方此挹清芬。", "吾道識宗主，文章詔討論。", "期我名山遊，招我出塵紛。", "伊余抱病久，局促滯中園。", "平生海嶽交，零落今誰存。", "今日對夫子，使我開心魂。", "忽覺此身去，萬里如空雲。", "已見赤城霞，疑聞天姥猨。", "世道久崩迫，誰將玄化分。", "濛濛六合閒，莽莽塵沙昏。", "所以賢達士，甘將麋鹿羣。", "終欲從夫子，超然淩紫氛。", "松閒兩白鶴，爾實聞斯言。"]'),
('5a47c17e-41e8-4188-b631-000089f5925f','登豫章城感懷','嚴羽','宋','宋诗','song-poetry','','[]','憂來不自得，登城望高天。',180,'全唐诗/poet.song.205000.json','["憂來不自得，登城望高天。", "寒雲四面起，朔氣下長川。", "脫劍且却座，君知心惘然。", "奈何平生志，鬰抑江湖閒。", "凜凜秋風來，茫茫落日晚。", "長憂生白髮，沈想忘朝飯。", "向來經濟士，本自碌碌人。", "蕭曹刀筆吏，樊灌市井臣。", "徒步取勳業，漢道爲光新。", "我今何爲者，飄飄去鄉國。", "狂歌豫章城，醉卧風江碧。", "但取英雄笑，終慙倜儻生。", "名當以德載，事恥因人成。", "獨酌還獨酌，哀歌還寂寞。", "安得淩風翰，爲君拂寥邈。"]'),
('e162c4b7-38a4-4348-b2f0-1a11b9bef474','夢中作','嚴羽','宋','宋诗','song-poetry','','[]','少小尚奇節，無意縛珪組。',168,'全唐诗/poet.song.205000.json','["少小尚奇節，無意縛珪組。", "遠遊江海閒，登高屢懷古。", "前朝英雄事，約略皆可覩。", "將軍策單馬，談笑有荆楚。", "高視蔑袁曹，氣已蓋寰宇。", "天未豁壯圖，人空坐崩沮。", "丈夫生一世，成敗固有主。", "要非儓儗人，未死名已腐。", "夫何千載後，亦忝趨大府。", "主人敬愛客，開宴臨長浦。", "高論極興亡，歷覽窮川渚。", "殷勤芳草贈，窈窕邯鄲舞。", "媿無登樓作，一旦濫推許。", "懷哉揮此觴，別路如風雨。"]'),
('7142cc36-f44b-4bf5-b29f-07f9cfe32f72','劉荆州答','嚴羽','宋','宋诗','song-poetry','','[]','皇漢失中德，四海橫雕戈。',168,'全唐诗/poet.song.205000.json','["皇漢失中德，四海橫雕戈。", "驚塵暗九有，豺虎臨長河。", "流人滿川谷，積屍亂如麻。", "關洛既蕩析，楚壤空嵯峨。", "謬當牧守寄，無以救時訛。", "竟貽百代誚，家世隨蹉跎。", "安知千載下，夫子感慨多。", "人生固有志，成敗飄風過。", "且復登城隅，逍遥望山河。", "日暮襄漢碧，鳬鴨遊輕波。", "何以慰我心，玄熊閒黄駞。", "清觴宜城酒，二八邯鄲歌。", "願言寫懷抱，聯用寬吾家。", "勿言此歡易，樂罷歸無何。"]'),
('62449457-03dd-4696-83e6-088995abba45','廬陵客館雨霽登樓言懷寄友','嚴羽','宋','宋诗','song-poetry','','[]','終日坐汾淟，邈然無少欣。',144,'全唐诗/poet.song.205000.json','["終日坐汾淟，邈然無少欣。", "登樓一周覽，始見萬山羣。", "微雨洗殘暑，青天卷浮雲。", "襟懷兩廓落，朗若見夫君。", "見君君何在，顧影還獨笑。", "吏非金門遊，隠異滄浪調。", "江明秋月白，山空夜猨嘯。", "徒事百卷文，未返一竿釣。", "留滯豈勝愁，非君誰與謀。", "水寒終赴海，雁遠暫賓秋。", "舉世不可語，猶當傲巢由。", "贈君三尺劍，永駕五湖舟。"]'),
('75fcf83d-e6a2-4cd5-a025-139567d21428','送嚴次山','嚴羽','宋','宋诗','song-poetry','','[]','四年棲嶺表，三歲客海東。',132,'全唐诗/poet.song.205000.json','["四年棲嶺表，三歲客海東。", "人生貴安適，奔走成何功。", "去年喜歸來，山花春蒙茸。", "弟姪各捧觴，一笑生華風。", "南山多紫芝，北山多白薇。", "雲空汗漫臺，月午生凉輝。", "俯仰僅一載，脂車復征西。", "豈以丈夫志，萬里猶庭闈。", "豈以名山川，待公親品題。", "故園松桂林，一一含貞姿。", "何時賦歸來，毋令久凝思。"]'),
('c5f1d49f-cd27-4063-aff3-7496b34544bd','豫章留別諸公','嚴羽','宋','宋诗','song-poetry','','[]','登艫眺海日，涉島聽江猨。',120,'全唐诗/poet.song.205000.json','["登艫眺海日，涉島聽江猨。", "何意豫章國，還著孤蓬根。", "經過徐孺宅，出入洪喬門。", "昔看秋葉落，今見荷花繁。", "頗躭山水趣，正愜朋從溫。", "窮秋催客去，獨帆若雲奔。", "追攀感數子，酒襟餘淚痕。", "既傷歲月晚，復戀煙霞樽。", "歡樂無定序，聚散同朝昏。", "丈夫志四海，別離何足論。"]'),
('2e3dc501-5b7e-4340-b9dc-96b188123044','遊臨江慧力寺','嚴羽','宋','宋诗','song-poetry','','[]','舟中望古剎，川上移琴樽。',120,'全唐诗/poet.song.205000.json','["舟中望古剎，川上移琴樽。", "隠隠林閣見，迢迢鍾梵聞。", "列岫不離席，驚濤常在門。", "風帆與沙鳥，汎汎隨朝昏。", "天高一幡挂，靜室衆香焚。", "煙起多近郭，鴉歸無遠村。", "松際上微雪，經聲來暮猨。", "賞惟靜者契，法對高僧論。", "安得息塵駕，永懷贍獨園。", "明朝別此去，惆悵滿松雲。"]'),
('04a004c1-ae19-4639-912c-b516f4fc05d1','山居即事','嚴羽','宋','宋诗','song-poetry','','[]','稍欣入林深，已覺煩慮屏。',84,'全唐诗/poet.song.205000.json','["稍欣入林深，已覺煩慮屏。", "霜果垂秋山，歸禽度嵐嶺。", "紛紛葉易積，漠漠雲欲盛。", "磵戶寂無人，松蘿窅然暝。", "惟聞山鳥嗁，月出柴門靜。", "終歲寡持醪，延歡聊煮茗。", "羣書北窗下，帙亂誰能整。"]'),
('a16ec2ba-09a2-48e3-8f25-fd98431bc653','遊仙六首  其一','嚴羽','宋','宋诗','song-poetry','','[]','秋閒夜瑟瑟，月露明團團。',72,'全唐诗/poet.song.205000.json','["秋閒夜瑟瑟，月露明團團。", "褰衣步澗月，忽見雙飛鸞。", "上有騰空仙，天風飄佩環。", "清歌映巖谷，粲若玉煉顔。", "願升綠雲去，隨君向仙關。", "嚥食長不老，何用思人閒。"]'),
('8fe16a42-c504-495a-a117-5dc33bdd2ed0','遊仙六首  其二','嚴羽','宋','宋诗','song-poetry','','[]','憶讀玲瓏篇，來往虛皇閣。',60,'全唐诗/poet.song.205000.json','["憶讀玲瓏篇，來往虛皇閣。", "空見白芙蓉，秋風幾凋落。", "昨逢紫陽君，共有丹臺約。", "下視塵埃中，冠纓縛猨玃。", "世事行若此，悠悠復何託。"]'),
('17312704-7df1-4b34-859f-112827d84274','遊仙六首  其三','嚴羽','宋','宋诗','song-poetry','','[]','五老出東南，崔嵬相閒隔。',108,'全唐诗/poet.song.205000.json','["五老出東南，崔嵬相閒隔。", "清晨登絕頂，處處仙人跡。", "朱霞散九光，巖谷好顔色。", "回首空澄湖，黄濤正喧擊。", "石上弦素琴，神歡心自清。", "仙童三四人，忽來左右聽。", "嘹嘹誦金書，勸我餐瑶瓊。", "贈我一玉麈，邀我淩雲行。", "舍琴與之去，恍惚在蓬瀛。"]'),
('26a827b1-b022-4524-8b08-e4a3d8d43705','遊仙六首  其四','嚴羽','宋','宋诗','song-poetry','','[]','朝別簡寂觀，夜行石徑谿。',108,'全唐诗/poet.song.205000.json','["朝別簡寂觀，夜行石徑谿。", "谿光照厓綠，月色正相宜。", "石上三道士，頎然好丰姿。", "手弄金光草，或把珊瑚枝。", "馮風招素手，賜我一玉卮。", "歎我事遠遊，蕭颯朱顔衰。", "長林孤月落，羽蓋何葳蕤。", "童童乘之去，棄我忽若遺。", "明發闃無覩，但有青鼯嗁。"]'),
('2b4b9977-b0d2-4afb-9951-2e960fff1454','遊仙六首  其五','嚴羽','宋','宋诗','song-poetry','','[]','翩翩南來雲，如飛百雙鶴。',60,'全唐诗/poet.song.205000.json','["翩翩南來雲，如飛百雙鶴。", "我行忽見之，眇然意欣樂。", "五峰何峻秀，靈草生垠萼。", "願乘此雲去，去鍊黄金藥。", "千載儻來歸，不復見城郭。"]'),
('3de70190-5e0b-47f6-ad33-43b3dd436f00','遊仙六首  其六','嚴羽','宋','宋诗','song-poetry','','[]','瀑布好明月，上有石梁橫。',96,'全唐诗/poet.song.205000.json','["瀑布好明月，上有石梁橫。", "矯首望東海，正見蟾蜍生。", "揚輝天漢閒，下照篷丘城。", "桂實幾凋落，姮娥空聞名。", "咄哉玉斧子，不如白兔精。", "靈藥不服食，執柯獨何成。", "迢迢彩雲外，誰吹白玉笙。", "竦身一長聽，了若出寰瀛。"]'),
('6ef5fef4-1a1b-425d-9282-c24fcc882ed5','我友遠言邁','嚴羽','宋','宋诗','song-poetry','','[]','朔風卷秋樹，白日寒無光。',96,'全唐诗/poet.song.205000.json','["朔風卷秋樹，白日寒無光。", "是時鴻雁來，中野何蒼茫。", "我友遠言邁，使我結中腸。", "如何携手歡，一旦成異鄉。", "行旅有期程，遊子多悲傷。", "置酒欲高歌，淚來霑我裳。", "四座慘相顧，征馬亦徬徨。", "未知會面日，且復盡茲觴。"]'),
('d01837bd-19ca-4e91-9189-149ca0e0fdfb','悠悠我行邁','嚴羽','宋','宋诗','song-poetry','','[]','悠悠我行邁，邈在天一方。',84,'全唐诗/poet.song.205000.json','["悠悠我行邁，邈在天一方。", "道路無終極，時節異炎凉。", "路逢故里親，揮泣問家鄉。", "妻子離別久，不知今存亡。", "中原多白骨，城邑聚豺狼。", "遠去無僮僕，思還絕餱糧。", "寄語家中人，遠行良可傷。"]'),
('d1919f1a-abdd-437f-a332-c06012285e27','朝日臨高臺','嚴羽','宋','宋诗','song-poetry','','[]','朝日臨高臺，睠彼芳樹閒。',72,'全唐诗/poet.song.205000.json','["朝日臨高臺，睠彼芳樹閒。", "上有共棲鳥，和鳴何關關。", "爾亦慕儔侶，我胡獨不然。", "良友在萬里，邈然河與山。", "聚會豈不思，歲月倏已殫。", "未必無他人，要非心所歡。"]'),
('7c410cbe-d2da-4298-a8a6-5cc8d320d1c4','昔遊東海上','嚴羽','宋','宋诗','song-poetry','','[]','昔遊東海上，道遇青童君。',48,'全唐诗/poet.song.205000.json','["昔遊東海上，道遇青童君。", "授我度世訣，中皆鳥篆文。", "讀之了不解，再拜問微言。", "舉首忽無見，茫茫空白雲。"]'),
('5d133784-da3e-4dae-adff-65862bfec8d5','秋風入我戶','嚴羽','宋','宋诗','song-poetry','','[]','秋風入我戶，翩翩動牀帷。',36,'全唐诗/poet.song.205000.json','["秋風入我戶，翩翩動牀帷。", "咄唶中夜起，奈何我心悲。", "四海豈不大，傷哉無己知。"]'),
('d8eb7a66-218d-485e-b568-b59842559796','過逍遥山','嚴羽','宋','宋诗','song-poetry','','[]','來過許仙宅，復窺洪崖井。',48,'全唐诗/poet.song.205000.json','["來過許仙宅，復窺洪崖井。", "地逐靈勝高，興接煙霞永。", "伊余坐昏墊，久欲還林嶺。", "明發囊丹砂，歸歟鍊頹景。"]'),
('57a4ab20-bfcf-43fc-b35c-7e79e921cd56','聞雁二首  其一','嚴羽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','凄離聽不足，咿嗈斷還續。',48,'全唐诗/poet.song.205000.json','["凄離聽不足，咿嗈斷還續。", "江人何似情，賈客舟中宿。", "夜深沙磧寒，月冷洞庭寬。", "寂寞相依影，悲風動毳翰。"]'),
('ab0e10cd-4f31-49f1-bea4-5b1eee76ecc1','聞雁二首  其二','嚴羽','宋','宋诗','song-poetry','','[]','江南底好處，塞北今衰草。',48,'全唐诗/poet.song.205000.json','["江南底好處，塞北今衰草。", "何限旅情遥，月映蘆花老。", "琵琶倚蓬窗，孀婦別蘭房。", "十載江湖淚，一夕盡淋浪。"]'),
('d96cc985-7f3d-4d2f-a829-2ba44c66dd19','古懊惱歌六首  其一','嚴羽','宋','宋诗','song-poetry','','[]','五兩轉須臾，相望奈何許。',24,'全唐诗/poet.song.205000.json','["五兩轉須臾，相望奈何許。", "寄語黄帽郎，船頭慢摇櫓。"]'),
('ae1dd374-70e0-4688-be97-8843ef50baa8','古懊惱歌六首  其二','嚴羽','宋','宋诗','song-poetry','','[]','君子如白日，願得垂末光。',24,'全唐诗/poet.song.205000.json','["君子如白日，願得垂末光。", "妾身如螢火，安能久照郎。"]'),
('01605cfe-c2fe-49bc-869b-5145169e6b87','古懊惱歌六首  其三','嚴羽','宋','宋诗','song-poetry','','[]','郎去無見期，妾死那瞑目。',24,'全唐诗/poet.song.205000.json','["郎去無見期，妾死那瞑目。", "郎歸認妾墳，應有相思木。"]'),
('29fa8b72-f87a-450e-854d-88e96c5923f6','古懊惱歌六首  其四','嚴羽','宋','宋诗','song-poetry','','[]','船在下江口，逆風不得上。',24,'全唐诗/poet.song.205000.json','["船在下江口，逆風不得上。", "結束作男兒，與郎牽百丈。"]'),
('da75bb4f-7852-46d6-a407-5e637d013bb2','古懊惱歌六首  其五','嚴羽','宋','宋诗','song-poetry','','[]','朝亦出門嗁，暮亦出門嗁。',24,'全唐诗/poet.song.205000.json','["朝亦出門嗁，暮亦出門嗁。", "蛛網挂風裏，遥思無定時。"]'),
('61925111-bb3c-4fc9-92f9-1b1dc8736220','古懊惱歌六首  其六','嚴羽','宋','宋诗','song-poetry','','[]','懊惱復懊惱，懊惱無奈何。',24,'全唐诗/poet.song.205000.json','["懊惱復懊惱，懊惱無奈何。", "請郎且少住，聽妾懊惱歌。"]'),
('32646379-f176-4698-8517-4203709350cf','憫時命','嚴羽','宋','宋诗','song-poetry','','[]','憫時命之不當兮，去重華之日遠。',370,'全唐诗/poet.song.205000.json','["憫時命之不當兮，去重華之日遠。", "懷貞慤之操行兮，遭此世之淟涊。", "志浩蕩以耿介兮，思低回而蹇産。", "衆日進而蔽壅兮，何靈修之爲怨。", "固時俗之俇儴兮，背矩矱而不可化。", "獨好修以增姱兮，宜反謂余以多詐。", "惟天地之可正兮，指黄泉以爲期。", "欲予屈心以從俗兮，雖九死其猶不忍爲。", "執太原之獶兮，蹈焦原之峻。", "世沈淖而莫予知兮，吾愈岧嶤而自信。", "昔伯陽之逢紛兮，時亦云其遑遑。", "繄周公不復夢兮，曷疑尼父之惋傷。", "陰與陽其轇轕兮，天與地其回薄。", "八柱將撓兮，四極安託。", "嗟予生之多艱兮，哀衆命之將落。", "願披志而抽憑兮，思自近而不可得。", "獨挹抑而無誰語兮，怊茫洋而焉極。", "涕淫溢而澒溶兮，面高穹而歎息。", "吾將遯俗以潔居兮，從巢父於箕山。", "采三秀而嚥蒼柏兮，聊以終吾之永年。", "哀山谷之多風兮，霰雪冥冥而不見天。", "豺狼縱目以相嗥兮，虎豹羣而食人。", "信自適而無所兮，蹇淹留而戃恍。", "目眈眈而外浮兮，精專專而獨往。"]'),
('d4666272-bcd2-48f3-a57f-a245cc2d8587','雲山操爲吳子才賦','嚴羽','宋','宋诗','song-poetry','','[]','山巃嵸兮白雲，雲冥冥兮高山。',161,'全唐诗/poet.song.205000.json','["山巃嵸兮白雲，雲冥冥兮高山。", "若有人兮居其閒，超逍遥兮盤桓。", "芸櫨兮菌桷，羅橘柚兮爲堂，塗予室兮楓香。", "擥葛藟兮爲帷，虈蕶雜兮佩幃。", "穹岫兮玄崖，瀑流兮相豗，皎積雪兮奔雷。", "攢林杳其蔽日兮，挂飛猱之清哀。", "雲中之君兮騎白鹿，山靈繽兮下空谷，風蕭蕭兮灌木。", "雲山兮幽幽，羌躑躅兮夷猶。", "惆悵兮余懷，非夫君兮誰思。", "投余簪兮太息，從夫君兮歸來。"]'),
('8081e6e0-1d74-43f6-b8c8-c4736684a160','塗山操','嚴羽','宋','宋诗','song-poetry','','[]','天蒼蒼，河水黄。',118,'全唐诗/poet.song.205000.json','["天蒼蒼，河水黄。", "河流決，大野茫。", "伯鯀治水，九年無功。", "四海赤子，化爲魚龍。", "鯀殛死，堯震怒。", "乃命禹，平水土。", "水土平，禹功成，魑魅奔走人安寧。", "平地栽桑麻，山頭種蕎麥。", "赤驥騰櫪，黄牛上軛，諸侯會同三千國。", "嗟爾防風，後至奚爲。", "悠悠塗山，今昔所悲。"]'),
('d32f7e17-6c7f-472a-a8fc-86211faa07f0','行子吟','嚴羽','宋','宋诗','song-poetry','','[]','行子在江海，飄飄無固蹤。',192,'全唐诗/poet.song.205000.json','["行子在江海，飄飄無固蹤。", "有如芒碭野，朔風卷飛蓬。", "朔風無休時，飛蓬日千里。", "散落天地閒，寧復有歸理。", "胡雁西北來，一叫三徘徊。", "何時別沙漠，昨夜宿陽臺。", "同羣一相失，羽翮常低摧。", "人物有殊性，奈何罹此哀。", "昨夜客遊初，結交重豪邁。", "高冠湛盧劍，志若輕四海。", "白首悔前圖，蹉跎天一隅。", "寒冬劍門道，失路空躊躇。", "深林聚豺虎，絕壁號猩鼯。", "雪深車軸折，征馬驚嗁呼。", "何當返故處，餐黍居田廬。", "淚下不能去，腸轉如轆轤。"]'),
('9854de59-ce9b-40c5-9fc4-024d9f9ce208','還山吟留別城南諸公','嚴羽','宋','宋诗','song-poetry','','[]','日暮望寒山，悵然歸思發。',120,'全唐诗/poet.song.205000.json','["日暮望寒山，悵然歸思發。", "如何山中客，屢看城頭月。", "山中月明女蘿秋，石磴潺湲瀉碧流。", "巖猨久別應惆悵，澗鳥相呼亦共愁。", "城南故人與我好，令我忘却歸山道。", "昨夜西窗夢到家，忽驚千嶂芝花老。", "朝來舟子促辭君，回首空江語尚聞。", "別後莫嗟難見面，相思只望嶺頭雲。"]'),
('27fd2863-3ea0-4f01-9090-bc30a83fc9b9','孺子臺吟','嚴羽','宋','宋诗','song-poetry','','[]','去年醉與東湖別，欲上衡湘泛秋月。',160,'全唐诗/poet.song.205000.json','["去年醉與東湖別，欲上衡湘泛秋月。", "君家留我却邅迴，悵望還成阻修闊。", "西山縹緲翠屏開，復憶滕王倒玉杯。", "經過始識洪崖井，調笑重登孺子臺。", "臺前呼酒折荷花，水凈煙明散落霞。", "舉杯失笑君何在，望斷行雲空咄嗟。", "故人別後還愁緒，此都不是余留處。", "興來目送海邊鴻，歸心挂在閩谿樹。", "路逢估客有情人，因得題詩一寄君。", "大鵬正展圖南翼，空有相思隔海雲。"]'),
('73ca56d4-a169-42d3-9702-cc618d78308a','思歸引','嚴羽','宋','宋诗','song-poetry','','[]','海上之草綠芊芊，洞門一閉今幾年。',96,'全唐诗/poet.song.205000.json','["海上之草綠芊芊，洞門一閉今幾年。", "仙驥去時留紫鞭，挂壁見之心惘然。", "欲歸即歸亦由我，不待功成何不可。", "堯舜不能屈由巢，自餘王侯何足交。", "武陵春水綠堪染，就中亦有桑麻郊。", "近聞秦人笑相語，待我東谿種碧桃。"]'),
('c8c911b9-98cd-4371-85fa-b57256a73e59','夢遊廬山謠示同志','嚴羽','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昨夜月落西窗陰，倦推石枕憑素琴。',192,'全唐诗/poet.song.205000.json','["昨夜月落西窗陰，倦推石枕憑素琴。", "身居紅塵不自覺，夢入廬山深復深。", "廬山深處在何許，五老仙人邀我語。", "眉如秀雪顔桃花，酌酒相酣坐箕踞。", "明河九派倒西來，石梁巉絕古道開。", "五公握手向我笑，下見劫火揚塵灰。", "獨騎一鹿窮縈迴，窅然醉蹋青錦苔。", "松風號嘈何清哀，湍飛瀑卷萬壑雷。", "忽然驚起迷所向，四座已失黄崔嵬。", "披衣徬徨還太息，我與世途何所屑。", "亂世茫茫飛蠓蠛，囊中別有金膏訣。", "須君之行當何時，共向丹崖卧松雪。"]'),
('cd362882-8e7d-48ea-b0f0-d50d79e0991a','錢塘潮歌送吳子才赴禮部','嚴羽','宋','宋诗','song-poetry','','[]','海潮之來自古昔，天下詭觀稱錢塘。',240,'全唐诗/poet.song.205000.json','["海潮之來自古昔，天下詭觀稱錢塘。", "東南王氣實在此，勢與造化爲低昂。", "觀其映日始一綫，何處羣鷺紛然翔。", "漸聞鼓聲震原野，疑是三軍囂陣行。", "銀城天際忽過眼，卷蹴厚地何倉皇。", "餘波已去灑月窟，怒氣猶自吹扶桑。", "百川倒流號呼洶，天吳河伯神皆竦。", "海上長人出水驚，巨鼇辟易三山動。", "廣陵之濤安可比，吳客雄誇徒爲爾。", "請君看此憑江樓，載酒無勞棹小舟。", "湖上百花春蕩目，笙簫聒我非清遊。", "洪濤萬里壯可吞，筆底颯颯洪濤奔。", "願持忠憤愬明主，一第於君何足論。", "錢塘日邊雲氣多，君之行兮莫蹉跎。", "教人臨期奈別何，贈君錢塘海潮歌。"]'),
('65d71d49-5718-40ba-baa9-84ea803267b2','送戴式之歸天台歌','嚴羽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吾聞天台華頂連石橋，石橋巉絕橫煙霄。',238,'全唐诗/poet.song.205000.json','["吾聞天台華頂連石橋，石橋巉絕橫煙霄。", "下有滄溟萬折之波濤，上有赤城千丈之霞標。", "峰懸磴斷杳莫測，中有石屏古仙客。", "吟窺混沌愁天公，醉飲扶桑泣龍伯。", "適來何事遊人閒，飄颻八極尋名山。", "三花樹下一相見，笑我蕭颯風沙顔。", "手持玉杯酌我酒，付我新詩五百首。", "共結天邊汗漫遊，重論方外雲霞友。", "海內詩名今數誰，羣賢翕沓爭相推。", "胸襟浩蕩氣蕭爽，豁如洞庭笠澤月。", "寒空萬里雲開時，人生聚散何超忽，愁折瑶華贈君別。", "君騎白鹿歸仙山，我亦扁舟向吳越。", "明日憑高一望君，江花滿眼愁氛氳。", "天長地闊不可見，空有相思寄海雲。"]'),
('637759fd-a982-47b1-9f5c-b9789f72db7f','雷斧歌','嚴羽','宋','宋诗','song-poetry','','[]','穹崖之上，層峰之巔，神光夜半光燭天。',232,'全唐诗/poet.song.205000.json','["穹崖之上，層峰之巔，神光夜半光燭天。", "山僧夢裏忽驚起，有物墜地聲填然。", "峰頭巨石似開劈，鬼物散走如飆旋。", "山僧曉見不敢取，有客識之爲雷斧，持歸摩挲色蒼古。", "匣中往往出雲氣，窗外時時起風雨。", "吾聞陰陽之氣相搏爲雷霆，變化翕欻常杳冥。", "非若革鼉考擊之爲聲，不知此斧何從形。", "乃是比干之心，朱雲之舌。", "一片忠憤氣，蟠鬰天地閒。", "千載長不滅，造化爲鑪巧鎔結。", "嗟哉指佞之草不復生，羣姦睚眥紛縱橫。", "大弓寶玉爭竊取，豈懼鬼責并天刑。", "我欲乘雲朝帝所，大叫天關排九虎。", "乞將此斧借小臣，叩頭問天天更許。"]'),
('6e6526af-4723-418d-a42c-92d260cefd1f','劍歌行','嚴羽','宋','宋诗','song-poetry','','[]','劍歌行，借君劍，爲君舞。',284,'全唐诗/poet.song.205000.json','["劍歌行，借君劍，爲君舞。", "自古英雄重結交，樽酒相逢氣相許。", "愛君倜儻不可羈，與君一見心無疑。", "疏眉大顙長七尺，神彩照耀仍虬髭。", "雄詞落紙走山嶽，霹靂繞壁蛟龍隨。", "如何十載困羈旅，此心獨未時人知。", "去年從軍殺强虜，舉鞭直解揚州圍。", "論功不及驃騎幕，失路羞逐邊城兒。", "歸來寶刀挂空壁，白光夜夜驚虹蜺。", "椎牛釃酒且高會，酣歌擊筑焉能悲。", "百年快意當若此，迂儒拳局徒爾爲。", "我亦摧藏江海客，重氣輕生無所惜。", "關河漂蕩一身存，宇宙茫茫雙鬢白。", "到處猶吟然諾心，平時錯負縱橫策。", "海內交遊四五人，近來得爾情相親。", "情相親，兩相託，生死交情無厚薄。", "別君去，還留連，願剖肝膽致君前。", "人生感激在知己，男兒性命焉足憐。"]'),
('a0e12dd9-cada-4266-952d-dddd15c08e2a','送主簿兄之德化任','嚴羽','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','唐世諸嚴盛西蜀，鄭公勳業開吾族。',240,'全唐诗/poet.song.205000.json','["唐世諸嚴盛西蜀，鄭公勳業開吾族。", "後來避地居南閩，幾代詩名不乏人。", "叔孫伯子俱成集，我兄下筆追唐及。", "少年賜第明光宮，才氣如雲辨揮翕。", "習簿風流四海聞，誰令作吏狎埃氛。", "片帆江上君先發，別袂春前我蹔分。", "借問匡廬在何許，舟人遥指雲中語。", "彭蠡湖邊幾樹秋，琵琶亭下江千古。", "香鑪峰頂散晴煙，瀑布懸疑瀉漏天。", "平生夢寐行歷處，一笑忽覺當樽前。", "盡驅靈異入篇什，物象往往愁笞鞭。", "此中高興寧淹久，盜賊兵戈莽回首。", "鄭公勳業須人傳，康濟他時仗君手。", "我今疏闊更何爲，心事惟將海嶽期。", "匡廬半席君爲主，待我酣來試一題。"]'),
('74b4c80d-76f5-417a-8f73-b7cb2f150bb1','寄贈張南卿兼答文篇之貺時南卿在鄱陽','嚴羽','宋','宋诗','song-poetry','','[]','君不見邯鄲輕薄少年兒，鬭雞走狗長相隨。',230,'全唐诗/poet.song.205000.json','["君不見邯鄲輕薄少年兒，鬭雞走狗長相隨。", "忽然失意向杯酒，拔劍相看死何有。", "君不見關西大姓多俠徒，結客如雲傾五都。", "一朝金盡人事改，昨日交朋竟誰在。", "我笑悠悠世上人，須臾反復非情親。", "拂衣便欲滄海去，但許明月隨吾身。", "張侯爲人心事好，使我一見喜欲倒。", "交友如君未易逢，相逢恨不相知早。", "相知雖早亦何爲，氣豁神傾在一時。", "君知海內劉玄德，我識弘農皇甫規。", "昨來贈我瓊瑶作，把酒高吟意寥廓。", "色動曹劉側耳聽，魂歸萬古開冥漠。", "故人一別兩何如，無限風期記素書。", "千里神交如咫尺，相思誰道隔江湖。"]'),
('56cad903-8574-4e1b-8dd7-a6ae299334e1','惜別行','嚴羽','宋','宋诗','song-poetry','','[]','男兒一片萬古心，滿世寥落無知音。',192,'全唐诗/poet.song.205000.json','["男兒一片萬古心，滿世寥落無知音。", "今朝見君握君手，大笑浩蕩開煩襟。", "携尊下馬清谿側，脫略寒溫忘主客。", "何處閑雲海上來，爲我山邊起秋色。", "自顧沈迷類蜀莊，愛君才術過馮唐。", "座中然諾兩相許，一飲不覺連百觴。", "下悲世事及危亂，上話古昔窮興亡。", "高歌未斷唾壺缺，起視落日神飛揚。", "挽君不留惜君去，恨不移家近君住。", "人生行止皆由天，我輩豈得長相聚。", "風塵澒洞一回首，歲月易失紅顔暮。", "離心一夜誰得知，萬里驚濤浩東注。"]'),
('1a153535-6480-44c6-b254-b9f02f15badf','放歌行','嚴羽','宋','宋诗','song-poetry','','[]','進賢之冠兮，高乎岌危。',109,'全唐诗/poet.song.205000.json','["進賢之冠兮，高乎岌危。", "山玄之佩兮，長乎陸離。", "苟非其道兮，曷如蕙带而荷衣。", "堯舜邈其不逢兮，我之心其孰得而知。", "寧輕世肆志兮，采商山之芝。", "與其突梯滑稽有口如飴，據高位而自若，釣厚祿而無疑。", "則余有蹈東海而死耳，誠非吾之所忍爲。"]'),
('2503adba-6002-4fc9-8b15-bfc9549d6552','相逢行','嚴羽','宋','宋诗','song-poetry','','[]','馮夫子，神仙中人乃如此。',188,'全唐诗/poet.song.205000.json','["馮夫子，神仙中人乃如此。", "幾載長懷玉樹枝，昨來曾見蛟龍字。", "志合神凝杯酒閒，誰知豁盡平生事。", "與君高會日揮金，擊劍談玄復弄琴。", "看君自是青雲器，何事常懸滄海心。", "我今與君真莫逆，世上悠悠誰復識。", "百年飄忽或須臾，萬里青霄一飛翼。", "且將耕釣任吾身，君亦牀頭有周易。", "馮夫子，我欲勸君飲，君當爲我歌。", "眼前萬事莫可理，紛紛黄葉埽更多。", "長風吹天送落日，秋江日夜揚洪波。", "只今留君不盡醉，別後相思知奈何。"]'),
('da719b9b-e32f-4792-b920-eabc06b6f1c4','送吳會卿再往淮南','嚴羽','宋','宋诗','song-poetry','','[]','故人身披紫綺裘，腰佩寶玦騎胡騮。',160,'全唐诗/poet.song.205000.json','["故人身披紫綺裘，腰佩寶玦騎胡騮。", "英風俠氣橫四海，辭我遠向淮南遊。", "淮南桂樹應猶在，八公舉手遥相待。", "明月高懸五兩頭，隨君千里過淮流。", "十年鞍馬邊城道，又向邊城見春草。", "春草萋萋路入秦，長安北望空愁人。", "荆楚奇材多劍客，感慨相逢思報國。", "男兒事業早致身，青鬢須防雪霜迫。", "我向人閒久拂衣，白雲相伴掩巖扉。", "調琴鼓罷清商曲，愁見孤鴻天際飛。"]'),
('7d69a76f-2dcb-43ae-8039-ded733782628','促刺行','嚴羽','宋','宋诗','song-poetry','','[]','促刺復促刺，男兒蹭蹬真可惜。',153,'全唐诗/poet.song.205000.json','["促刺復促刺，男兒蹭蹬真可惜。", "三年走南復走北，歲暮歸來空四壁，鄰翁爲我長太息。", "人生四十未爲老，我已白頭色枯槁。", "海內伶俜獨一身，裘馬摧藏愁欲倒。", "今日飲君數杯酒，座閒頗覺顔色好。", "忽憶當年快意時，與君笑傲長相期。", "大杯倒甕作牛飲，脫巾袒跣唯嫌遲。", "即今多病筋力弱，壯心雖存興寂寞。", "君不見昨夜誰爲烈士歌，聽罷仰空淚零落。"]'),
('0565b2ea-93fe-4990-a3c8-c04cf5637125','古劍行','嚴羽','宋','宋诗','song-poetry','','[]','我有三尺劍，懸瞻光陸離。',70,'全唐诗/poet.song.205000.json','["我有三尺劍，懸瞻光陸離。", "刜鐘不錚，切玉如泥，水斷蛟龍陸剸犀。", "三軍白首纔一揮，惜哉挂壁無所施，使之補履不如錐。", "吾將抱憤愬玉帝，手持此劍上天飛。"]'),
('73eb2ad8-42b5-4162-a1d2-c63d4069a09a','北伐行','嚴羽','宋','宋诗','song-poetry','','[]','王師北伐何倉卒，六郡丁男亳州骨。',64,'全唐诗/poet.song.205000.json','["王師北伐何倉卒，六郡丁男亳州骨。", "空見朝陵奉使回，羣盜翻來舊京闕。", "襄陽兵馬天下雄，尚書兄弟才傑同。", "偏裨入救嗟已晚，萬國此恨何時終。"]'),
('8710f19a-002f-48a1-9326-e1bc0eca9223','四方行','嚴羽','宋','宋诗','song-poetry','','[]','四方羣盜苦未平，况聞中原多甲兵。',64,'全唐诗/poet.song.205000.json','["四方羣盜苦未平，况聞中原多甲兵。", "百年讐恥幸已雪，何意復失東西京。", "嗚呼機事難適至，成敗君看豈天意。", "戰骨連營漫不歸，空流烈士中宵淚。"]'),
('50ad1c4b-156e-4cd7-b93f-73ea38cbc54f','上留田','嚴羽','宋','宋诗','song-poetry','','[]','天地一何長久，上留田。',77,'全唐诗/poet.song.205000.json','["天地一何長久，上留田。", "人老一去無歸，上留田。", "松柏一何纍纍，上留田。", "勸君酒樽金罍，上留田。", "願君大家蠶桑，上留田。", "有絲織作衲襠，上留田。", "無爲多憂煩傷，上留田。"]'),
('4cca02dd-7e6b-42a4-93fe-2ea0cf6988fa','估客樂','嚴羽','宋','宋诗','song-poetry','','[]','荆州人，來販穀。',32,'全唐诗/poet.song.205000.json','["荆州人，來販穀。", "下江易，上江難。", "船頭鼓，波漫漫，長帆輓上五兩竿。"]'),
('fe58ddaa-9c0e-4901-9686-2bb3084e063f','西山','嚴羽','宋','宋诗','song-poetry','','[]','西山青縹緲，深處有丹砂。',24,'全唐诗/poet.song.205000.json','["西山青縹緲，深處有丹砂。", "說道神仙客，邀予戲紫霞。"]'),
('4fb34b2e-6ad6-4066-93f3-7ebeec821b21','送友歸山效韋應物體','嚴羽','宋','宋诗','song-poetry','','[]','送君歸山谷，覺我荷衣塵。',24,'全唐诗/poet.song.205000.json','["送君歸山谷，覺我荷衣塵。", "殷勤郡城別，衰淚欲沾巾。"]'),
('f6e498d9-89dc-4cf4-97de-adac1e5f221f','空齋','嚴羽','宋','宋诗','song-poetry','','[]','寒鐙照疏竹，棲禽時復驚。',24,'全唐诗/poet.song.205000.json','["寒鐙照疏竹，棲禽時復驚。", "默坐空齋夜，寂寞道心生。"]'),
('aeb5c8d1-7cec-4b6f-841f-a27b5deed3b8','歲暮得表叔吳景仙書因寄','嚴羽','宋','宋诗','song-poetry','','[]','遊吳還適越，慷慨莫徒然。',48,'全唐诗/poet.song.205000.json','["遊吳還適越，慷慨莫徒然。", "烽火關河隔，兵戈宇宙連。", "書來山雪外，人在海雲邊。", "借問遼東鶴，歸來定幾年。"]'),
('b7b6774f-03d8-4efd-896b-dc77a2b0291c','登天皇山作','嚴羽','宋','宋诗','song-poetry','','[]','我來陟高頂，俯瞰臨長川。',48,'全唐诗/poet.song.205000.json','["我來陟高頂，俯瞰臨長川。", "陰崖隠落日，疊嶂鳴飛泉。", "獨立一世外，所思千古前。", "回看鳥沒處，茫茫生白煙。"]'),
('6fccd2c5-0556-4015-b57b-c86f60f2e681','遊紫芝巖','嚴羽','宋','宋诗','song-poetry','','[]','羽客逍遥地，花源世未尋。',48,'全唐诗/poet.song.205000.json','["羽客逍遥地，花源世未尋。", "我來窺異迹，高步越飛岑。", "石带藤蘿古，泉鳴澗壑深。", "紫芝未可采，空寄白雲心。"]'),
('7adbfd8a-5363-4885-8645-1d428034a54c','絕句二首  其一','嚴羽','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里長江歲暮天，冰堅可渡不須船。',32,'全唐诗/poet.song.205000.json','["萬里長江歲暮天，冰堅可渡不須船。", "雪堂老子迎君笑，化鶴歸來又百年。"]'),
('8e9a2405-8b98-40f6-a480-cd739b3ee148','絕句二首  其二','嚴羽','宋','宋诗','song-poetry','','[]','梅花樹樹攪離心，寒重駝裘雪片深。',32,'全唐诗/poet.song.205000.json','["梅花樹樹攪離心，寒重駝裘雪片深。", "詩思飛來馿子上，小山叢桂待君吟。"]'),
('b78eb12f-9b85-48b6-b61d-3ab918c6f1de','平寇上史君王潛齋','嚴羽','宋','宋诗','song-poetry','','[]','治平改元，有盜于建。',240,'全唐诗/poet.song.205000.json','["治平改元，有盜于建。", "昔犯我鄙，狼蹂豕踐。", "於時王侯，維民之憂。", "爰整我軍，式遏虔劉。", "侯勵將士，無譁聽我。", "進退勇怯，死生福禍。", "侯出府庫，啗勳賞馘。", "前無堅敵，後無捷策。", "乃有奇士，據鞍請行。", "袒裼入陣，賊莫能嬰。", "亦有賢僚，爭先跋涉。", "屢摧賊鋒，月奏三捷。", "侯曰嘻哉，盜本王臣。", "殪而殲旃，傷天地仁。", "赤子弄兵，如魚游釜。", "投戈歸田，新汝生路。", "孰謂反覆，紿我行人。", "既弛我備，薄奄我軍。", "我軍少却，醜類鴟張。", "環數百里，奔播倉皇。", "侯曰嗟哉，其不可恕。", "馳赤白囊，亟請淮旅。", "淮旅未來，阽危如燬。", "淮旅既來，稚耋失喜。"]'),
('2aa5f567-5a1c-443b-bd65-eeac21685317','平遠樓','嚴仁','宋','宋诗','song-poetry','','[]','湘中病客思歸日，城上高樓獨倚時。',32,'全唐诗/poet.song.205000.json','["湘中病客思歸日，城上高樓獨倚時。", "半樹夕陽鴉集早，一江秋色雁來遲。"]'),
('1da8764c-d66b-40c4-a8d2-4f8891eae8d4','聞雁','嚴仁','宋','宋诗','song-poetry','','[]','西風吹夢楚江秋，雁正來時妾正愁。',32,'全唐诗/poet.song.205000.json','["西風吹夢楚江秋，雁正來時妾正愁。", "怕有帛書天外至，畫眉未了急登樓。"]'),
('3a17b6ac-e7dc-4dc9-beef-6e32ab670e4b','塞下曲','嚴仁','宋','宋诗','song-poetry','','[]','漠漠孤城落照間，黄榆白葦滿關山。',32,'全唐诗/poet.song.205000.json','["漠漠孤城落照間，黄榆白葦滿關山。", "千枝羌笛連雲起，知是胡兒牧馬還。"]'),
('c3f967dd-c89f-4af5-a5e3-ca3e91c7433a','湘南','嚴仁','宋','宋诗','song-poetry','','[]','斑竹蕭蕭水驛孤，落花吹雨赤沙湖。',32,'全唐诗/poet.song.205000.json','["斑竹蕭蕭水驛孤，落花吹雨赤沙湖。", "春風二月湘南路，何處青山無鷓鴣。"]'),
('729b3e9c-de3c-4db8-8431-82539c27a9e0','梅','嚴參','宋','宋诗','song-poetry','','[]','何年流水恨，昨夜小橋春。',24,'全唐诗/poet.song.205000.json','["何年流水恨，昨夜小橋春。", "縱有相逢地，都無可寄人。"]'),
('52b6f8dd-3484-4316-808b-5a90bba13537','看雪','嚴參','宋','宋诗','song-poetry','','[]','天遠正難窮，樓高不堪倚。',24,'全唐诗/poet.song.205000.json','["天遠正難窮，樓高不堪倚。", "醉夢入江南，楊花數千里。"]'),
('b4d8a5fc-7af5-4593-887d-7776eb9ed994','瓶梅','嚴參','宋','宋诗','song-poetry','','[]','衣染龍涎與麝臍，裁雲剪月作冰肌。',32,'全唐诗/poet.song.205000.json','["衣染龍涎與麝臍，裁雲剪月作冰肌。", "小瓶雪水無多子，只篸橫斜一兩枝。"]'),
('b7201ecd-f92f-452b-9a9e-c64c057b8390','落梅','嚴參','宋','宋诗','song-poetry','','[]','園花皆手植，梅萼獨禁寒。',48,'全唐诗/poet.song.205000.json','["園花皆手植，梅萼獨禁寒。", "色與香無價，飛和雪作團。", "數枝橫翠竹，一夜遶朱欄。", "不惜吟邊苦，收將句裏看。"]'),
('d4dc5e7e-a7be-4f44-909a-20f56b66ded6','河梁值雨有懷嚴羽','上官良史','宋','宋诗','song-poetry','','[]','葦岸逢殘雨，河橋對暮流。',48,'全唐诗/poet.song.205000.json','["葦岸逢殘雨，河橋對暮流。", "停鞭一悵望，客思暫夷猶。", "楓葉滿江色，夕陽終古愁。", "遥憐君亦苦，不共故園秋。"]'),
('d2dc2234-11f8-4e2f-8045-4acd24b07222','尋嚴丹丘東潭居二首  其一','上官良史','宋','宋诗','song-poetry','','[]','愛子東溪幽，抱被來同宿。',48,'全唐诗/poet.song.205000.json','["愛子東溪幽，抱被來同宿。", "山家無膏火，然薪代明燭。", "閒窗何所有，古書三五束。", "鳥棲月上時，還見簷前竹。"]'),
('e6cad0f3-e4f9-40bc-af3d-bc026d986929','尋嚴丹丘東潭居二首  其二','上官良史','宋','宋诗','song-poetry','','[]','山齋櫺牖疎，水月連春霧。',48,'全唐诗/poet.song.205000.json','["山齋櫺牖疎，水月連春霧。", "今夕定何夕，清心欣所遇。", "如從天姥遊，似得招提趣。", "幽夢出雲時，匆匆山鳥曙。"]'),
('704c8a1e-c68a-4771-acde-80f85356720c','泊舟有懷','上官良史','宋','宋诗','song-poetry','','[]','渺渺復迢迢，楓林带柞橋。',48,'全唐诗/poet.song.205000.json','["渺渺復迢迢，楓林带柞橋。", "沙寒初上月，浦暗已回潮。", "霜葦多先折，江花或後凋。", "今宵何處雁，相伴宿蘭橈。"]'),
('cf3123db-ee67-4857-aa99-95ca6dbe05eb','句  其一','上官良史','宋','宋诗','song-poetry','','[]','春城不盡頭。',6,'全唐诗/poet.song.205000.json','["春城不盡頭。"]'),
('0408e589-6704-4a22-9a02-b1589524e4e6','句  其二','上官良史','宋','宋诗','song-poetry','','[]','獨樹臨江古。',6,'全唐诗/poet.song.205000.json','["獨樹臨江古。"]'),
('281d7de8-c9a5-4691-8134-c1f88a05e952','句  其三','上官良史','宋','宋诗','song-poetry','','[]','春富野人家。',6,'全唐诗/poet.song.205000.json','["春富野人家。"]'),
('3076821d-582b-45ff-8202-94f22303d8bc','句  其四','上官良史','宋','宋诗','song-poetry','','[]','霜鴻入夜驚還止。',8,'全唐诗/poet.song.205000.json','["霜鴻入夜驚還止。"]'),
('2793baa3-d16d-4f10-9664-4c0c4f77bf4c','句  其五','上官良史','宋','宋诗','song-poetry','','[]','海天臘盡凍初融。',8,'全唐诗/poet.song.205000.json','["海天臘盡凍初融。"]'),
('cfda9d78-39a6-4867-9eb9-4d0e13f06c2c','大滌洞  其一','趙希焄','宋','宋诗','song-poetry','','[]','門敲石鼓叩神靈，洞府巉巖杳靄深。',64,'全唐诗/poet.song.205000.json','["門敲石鼓叩神靈，洞府巉巖杳靄深。", "直欲九淵驚睡玉，須憑一炷爇香沉。", "幾年曾救桑林旱，今日還書魯史霖。", "妙句不妨留大滌，要知棲鳳也來吟。"]'),
('c61168f2-be4c-4ab3-8d02-e29ce140f9e7','大滌洞  其二','趙希焄','宋','宋诗','song-poetry','','[]','誰挽天河響落山，潮聲半夜到江干。',64,'全唐诗/poet.song.205000.json','["誰挽天河響落山，潮聲半夜到江干。", "倒流三峽水何擊，捲起千堆雪正寒。", "想是蛟從其下舞，料應龍在此中蟠。", "如君大手留吟筆，千古坡詩可並觀。"]'),
('ade250cf-b46f-49b4-be5e-ebec9f63da55','寄題中興頌下','衛樵','宋','宋诗','song-poetry','','[]','鼎沸漁陽塞馬鳴，中興鴻業幸天成。',64,'全唐诗/poet.song.205000.json','["鼎沸漁陽塞馬鳴，中興鴻業幸天成。", "且爲當世邦家計，寧問他時父子情。", "李郭功名無可憾，元顔文字有何評。", "若能銘刻燕然石，方許雌黄此頌聲。"]'),
('56996715-f992-47d3-89c0-34585c852f8c','澹岩  其一','衛樵','宋','宋诗','song-poetry','','[]','嵌巖洞谷到曾多，無奈冥搜暗索何。',32,'全唐诗/poet.song.205000.json','["嵌巖洞谷到曾多，無奈冥搜暗索何。", "此處雲穿風月透，短筇渾不待捫蘿。"]'),
('7156ba65-4462-4948-8187-18952b339d87','澹岩  其二','衛樵','宋','宋诗','song-poetry','','[]','慚愧州家一事無，薄遊還愛小蓬壺。',32,'全唐诗/poet.song.205000.json','["慚愧州家一事無，薄遊還愛小蓬壺。", "若憑妙筆丹青寫，應勝從來八景圖。"]'),
('eb53b66a-b87c-4f33-b3e7-cf6efba2c2c9','詩一首','潘時舉','宋','宋诗','song-poetry','','[]','老大倦追隨，得坐且終日。',24,'全唐诗/poet.song.205000.json','["老大倦追隨，得坐且終日。", "所以見春去，亦不甚愛惜。"]'),
('8b68ddb6-924c-4675-a4d6-6fb8f98eb65f','奉題周南仲正字所藏閻立本畫蘇李別','朱鼐','宋','宋诗','song-poetry','','[]','少卿昔在河梁別，執手踟躕不能發。',160,'全唐诗/poet.song.205000.json','["少卿昔在河梁別，執手踟躕不能發。", "萬古初傳五字詩，努力相期在明德。", "子卿海上氈爲食，故人朅來重相覿。", "不覺看羊度歲年，却因射鴈傳消息。", "人間此是長別離，少卿在虜子卿歸。", "歸歟尚握漢臣節，留者永衣胡人衣。", "天長地闊半尺絹，滿眼雲愁風景變。", "一人仰叫頭脫冠，一人橫涕袖著面。", "閻君國相稱畫師，未必想像能爾奇。", "前身恐是胡婦子，曾見兩公分袂時。"]'),
('8ffe3526-dd21-47d3-b756-486bd5eca7a3','送僧歸護國寺','李簡','宋','宋诗','song-poetry','','[]','來赴龍華約，歸承帝澤新。',48,'全唐诗/poet.song.205000.json','["來赴龍華約，歸承帝澤新。", "道高傳幾祖，言下得何人。", "水想靈溪健，花饒法界春。", "自甘鉛鈍者，猶望指迷津。"]'),
('3d2a29cd-9ae7-4a5a-a9b6-911dbdcf398b','羅漢寺  其一','韓舜卿','宋','宋诗','song-poetry','','[]','山陰盛事今寥落，千古風流屬晉陽。',64,'全唐诗/poet.song.205000.json','["山陰盛事今寥落，千古風流屬晉陽。", "况有林泉當列坐，不須絃管送流觴。", "醉揮金椀青春客，自濯塵纓白髮郎。", "一笑相看能幾許，却憐馬首路岐長。"]'),
('26c34d5d-c4fa-4234-9fd0-c3420f7030d5','羅漢寺  其二','韓舜卿','宋','宋诗','song-poetry','','[]','天逈雲收霽色空，喬林還遶寺當中。',64,'全唐诗/poet.song.205000.json','["天逈雲收霽色空，喬林還遶寺當中。", "陰森小徑千重竹，蕭颯虛亭四面風。", "暮靄不興山抹黛，夕陽西下水流紅。", "自慚怯懦承庥庇，安得民稱幾寸葱。"]'),
('c0efbbd1-551f-4212-9566-52d08b44f0ee','詩一首','阮愈','宋','宋诗','song-poetry','','[]','收拾新詩入錦囊，晴天添得兩三章。',32,'全唐诗/poet.song.205000.json','["收拾新詩入錦囊，晴天添得兩三章。", "一冬只在梅花裏，吟筆入春猶自香。"]'),
('906a0903-baa3-44a6-8501-1e92db689ace','訪吳','晏乂','宋','宋诗','song-poetry','','[]','平生一語不肯吐，浩然披髮行西林。',32,'全唐诗/poet.song.205000.json','["平生一語不肯吐，浩然披髮行西林。", "美人十日跨馿出，黄葉堆門雲雪深。"]'),
('5366f318-a6fb-47f8-8523-630f25fc7eea','夢中','晏乂','宋','宋诗','song-poetry','','[]','春樹年年少，寒雲浦浦連。',48,'全唐诗/poet.song.205000.json','["春樹年年少，寒雲浦浦連。", "片帆高浪起，斗酒夕陽偏。", "沙市懷司馬，州城哭老邊。", "太平冠蓋盡，爾敢望諸賢。"]'),
('62f44ab4-1578-4628-84ba-863173649edb','題米元章書蹟拓本','董史','宋','宋诗','song-poetry','','[]','書家寶晉殆猶龍，妙用通神五指中。',64,'全唐诗/poet.song.205000.json','["書家寶晉殆猶龍，妙用通神五指中。", "墨海波瀾無定勢，玄雲夭矯欲隨空。", "格高韻勝存人品，脚闊頭空笑俗工。", "建紹聖人精鑒賞，奪真移在玉屏風。"]'),
('51765942-af87-4702-8b00-f7a3ed2f43be','跋劉敏叔畫楊誠齋先生探梅圖二首  其一','李大來','宋','宋诗','song-poetry','','[]','壽骨勁如霜後雪，詩脾寫出月中梅。',32,'全唐诗/poet.song.205000.json','["壽骨勁如霜後雪，詩脾寫出月中梅。", "如今不愛好官職，得及翁年也樂哉。"]'),
('83b92ab9-69a5-4d89-9c33-379bac096261','跋劉敏叔畫楊誠齋先生探梅圖二首  其二','李大來','宋','宋诗','song-poetry','','[]','梅發江村覓句天，先生策杖到花前。',32,'全唐诗/poet.song.205000.json','["梅發江村覓句天，先生策杖到花前。", "款門有客真能事，爲幻精神若箇邊。"]'),
('a8c1a972-e82e-422f-bd34-72553ead9327','遊隠屏','蔡杭','宋','宋诗','song-poetry','','[]','悚懼未成立，隠憂道學失。',24,'全唐诗/poet.song.205000.json','["悚懼未成立，隠憂道學失。", "修身復補過，庶保餘生責。"]'),
('1fb3a3b9-200c-43e7-86e7-c04f7a894cf4','同友人過大隠屏即事賦別','蔡杭','宋','宋诗','song-poetry','','[]','脫略塵世慮，仙都共夷猶。',132,'全唐诗/poet.song.205000.json','["脫略塵世慮，仙都共夷猶。", "乘凉得風便，快楫竹扁舟。", "神仙現奇怪，古木橫巖陬。", "振衣萬仞高，天風動衣摳。", "巍巍隠屏峰，擎天峙中流。", "良朋論心事，撫景悲新秋。", "浩歎復浩歌，一飲還一酬。", "南陽豈終卧，東山諒同憂。", "斟酌素有定，今焉試爲籌。", "西風起暝色，歸袂不可留。", "去去惜回首，感慨良悠悠。"]'),
('47f39b5c-99f0-41b3-8691-d6810e9d6bbf','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得風字','陳南','宋','宋诗','song-poetry','','[]','自嘆年餘七十翁，道山重上攝高風。',64,'全唐诗/poet.song.205000.json','["自嘆年餘七十翁，道山重上攝高風。", "一封疏奏膽如斗，三請投閑氣直虹。", "憲節可能攄藴抱，男兒到底要英雄。", "江臯父老如相問，爲說吾今計亦東。"]'),
('2393d3d6-e4ff-4393-b808-465a790d1735','哭真西山先生','吳叔告','宋','宋诗','song-poetry','','[]','恍惚精神對大廷，妬賢宰相別孫弘。',32,'全唐诗/poet.song.205000.json','["恍惚精神對大廷，妬賢宰相別孫弘。", "便令身入翹材館，不忍重過下馬陵。"]'),
('091bf71a-3aa4-4a15-9158-18733a14bffc','偈','謝方叔','宋','宋诗','song-poetry','','[]','罷相歸來十七年，燒香禮佛學神仙。',32,'全唐诗/poet.song.205000.json','["罷相歸來十七年，燒香禮佛學神仙。", "今朝雙鶴催歸去，一念無慚對越天。"]'),
('d31d6b0e-ee59-4e65-abd1-1d97a2b80f9f','詠文筆山','高夢月','宋','宋诗','song-poetry','','[]','西山翠欲滴，奇峰露嵂兀。',24,'全唐诗/poet.song.205000.json','["西山翠欲滴，奇峰露嵂兀。", "倚天挺巨手，欲寫風和月。"]'),
('14e6ee5d-1f9e-4ac5-b341-383d89896bc6','壽游侍郎七十九','王九萬','宋','宋诗','song-poetry','','[]','炎凉薄流光，榮悴猾生理。',252,'全唐诗/poet.song.205000.json','["炎凉薄流光，榮悴猾生理。", "芳荃化爲茅，嘉橘變成枳。", "誰知古大椿，霜雪自薿薿。", "立身既千仞，騖陰殆百里。", "宜哉富春秋，萬物聽獨止。", "先生一靈椿，聳壑屹山峙。", "納湖溉其根，後溪擁其址。", "平生學問力，頓在名節裏。", "甘泉詎弗貴，東山不爲起。", "以身蹈高潔，爲世律貪鄙。", "坐令夸奪輩，疾走掩兩耳。", "乃知公進退，均爲國憑恃。", "恭爲陛下聖，雅欲致園綺。", "黄金已九環，丹詔行一紙。", "公心豈輕重，上意實注委。", "嘉平報初度，吉音隨燕喜。", "耆英七十九，彷彿富公是。", "行歸磻溪載，更詠淇奧美。", "方覺歲寒姿，不隨世變靡。", "錦溪入霞觴，城山揖燕几。", "祝公如大椿，明堂棟千祀。"]'),
('cd45bc98-a39e-40dd-a1b4-7b33ff110fc5','遊靈巖','李茂先','宋','宋诗','song-poetry','','[]','雪巖偶得片時留，傾倒清尊興未休。',64,'全唐诗/poet.song.205000.json','["雪巖偶得片時留，傾倒清尊興未休。", "香積尋常分藥水，禪林自昔枕江流。", "羊腸盤轉層崖蔭，山腹空懸古洞幽。", "談笑相逢情更厚，何當携手約重遊。"]'),
('1f20cca8-b36c-4b3b-9721-2eacfa8aeefa','遊靈巖  其一','文紳儀','宋','宋诗','song-poetry','','[]','一入靈巖寺，凭欄望眼遥。',48,'全唐诗/poet.song.205000.json','["一入靈巖寺，凭欄望眼遥。", "山深雲障日，江闊夜生潮。", "古洞遺仙跡，流泉傍石橋。", "醉來搔首咏，得句興偏饒。"]'),
('46d0f47d-4abc-4dc6-8676-84e9cb7c6889','遊靈巖  其二','文紳儀','宋','宋诗','song-poetry','','[]','禪林高聳倚晴空，梯上層巒紫翠重。',64,'全唐诗/poet.song.205000.json','["禪林高聳倚晴空，梯上層巒紫翠重。", "雲氣下成風雨陣，嵐光高接斗牛宮。", "流泉藥水瘳民疾，古洞神仙有路通。", "竊欲捫蘿登絕頂，細將民隠達天聰。"]'),
('1f521f5c-6d32-47a2-b21a-a48e762e20e9','泊舟漁浦望吳山作','林希逸','宋','宋诗','song-poetry','','[]','客子孤舟傍曉沙，隔江人說是京華。',32,'全唐诗/poet.song.205000.json','["客子孤舟傍曉沙，隔江人說是京華。", "緣山一带煙籠樹，中有王侯百萬家。"]'),
('00bf32c6-7469-4205-b62a-0d23a79b7ad6','龍灣秋夜','林希逸','宋','宋诗','song-poetry','','[]','旅泊秋將暮，行吟夜向中。',48,'全唐诗/poet.song.205000.json','["旅泊秋將暮，行吟夜向中。", "獨星明似月，重露冷於風。", "遊歷書何有，飛揚醉自雄。", "時聞邊耗近，憂憤氣填胸。"]'),
('9b4c18ed-6b8b-4a7f-a1d4-6b2661450599','前出塞','林希逸','宋','宋诗','song-poetry','','[]','淮面如江春漲早，獵騎夜歸城未鎖。',32,'全唐诗/poet.song.205000.json','["淮面如江春漲早，獵騎夜歸城未鎖。", "邊頭戍將惜官卑，舉鞭怒指平安火。"]'),
('5e5786f0-3d3c-45aa-a349-53674aacde64','後出塞','林希逸','宋','宋诗','song-poetry','','[]','紫金山前數尺雪，三十六洲明似月。',32,'全唐诗/poet.song.205000.json','["紫金山前數尺雪，三十六洲明似月。", "夜來衝突人不知，但見官軍刀带血。"]'),
('5d0805e3-1528-4548-9af3-beed784c5d57','信陽道中次陳守韻','林希逸','宋','宋诗','song-poetry','','[]','古嶺纔成徑，荒林間有家。',48,'全唐诗/poet.song.205000.json','["古嶺纔成徑，荒林間有家。", "柳眠腰裊娜，桑老骨槎牙。", "野麥三分草，山籬一半花。", "挾書來萬里，飄泊負生涯。"]'),
('e8c8ca69-af64-419d-8aa1-db8f76f5c9fb','安豐作','林希逸','宋','宋诗','song-poetry','','[]','塞北悲笳起，淮南古木疏。',48,'全唐诗/poet.song.205000.json','["塞北悲笳起，淮南古木疏。", "風高疑唳鶴，水落見叉魚。", "俗僅傳丹鼎，人誰問枕書。", "因吟招隠賦，久客自嗟噓。"]'),
('de6911b9-5958-42ed-ad38-555167f4006a','寄書後作','林希逸','宋','宋诗','song-poetry','','[]','幾度題書客未還，歸鴻節節度鄉關。',32,'全唐诗/poet.song.205000.json','["幾度題書客未還，歸鴻節節度鄉關。", "遥知一紙平安字，慈母燈前閣淚看。"]'),
('afe25a14-a44d-457a-89d3-33c18f81f235','寒食  其一','林希逸','宋','宋诗','song-poetry','','[]','異俗逢鑽燧，勞生嘆轉蓬。',48,'全唐诗/poet.song.205000.json','["異俗逢鑽燧，勞生嘆轉蓬。", "茅簷疏柳月，草地落花風。", "故國丘墳在，他鄉祭祀同。", "奔馳真左計，歸夢海雲東。"]'),
('43b4134e-abc1-494d-8dd5-41578fcc7f3d','寒食  其二','林希逸','宋','宋诗','song-poetry','','[]','陣陣花風送雨寒，心隨風雨到鄉關。',32,'全唐诗/poet.song.205000.json','["陣陣花風送雨寒，心隨風雨到鄉關。", "遥知松柏山前路，今日鄰人拜掃還。"]'),
('ef062760-cff7-43e6-8117-e2d62ccc69b6','舟泊姑蘇城外','林希逸','宋','宋诗','song-poetry','','[]','倚郭維孤舟，漠漠見煙渚。',36,'全唐诗/poet.song.205000.json','["倚郭維孤舟，漠漠見煙渚。", "水宿野鳥歸，夜深鄰人語。", "遠客萬斛愁，卧聽姑蘇雨。"]'),
('5b3e8738-63ec-4f13-a88b-50a18545dbe1','宿西興渡作','林希逸','宋','宋诗','song-poetry','','[]','古寺鳴鍾罷，高林宿鳥忙。',48,'全唐诗/poet.song.205000.json','["古寺鳴鍾罷，高林宿鳥忙。", "竹明風弄影，荷凈露生香。", "月到中天小，星過野水長。", "江村人寂寂，敗葉響銀床。"]'),
('6ca183da-b540-47a2-aa26-61c9e6832364','臨浦秋夜','林希逸','宋','宋诗','song-poetry','','[]','野噪寒枝鵲，村歸古寺僧。',48,'全唐诗/poet.song.205000.json','["野噪寒枝鵲，村歸古寺僧。", "傍階聞落葉，隔岸數殘燈。", "月退頻移席，潮高尚倚藤。", "江虛群籟息，人語近漁罾。"]'),
('bd8e07b7-8c85-4e46-98fd-3dca598d2edd','樂軒先師挽歌詞  其一','林希逸','宋','宋诗','song-poetry','','[]','十年燈火若爲情，一日簫笳有底聲。',32,'全唐诗/poet.song.205000.json','["十年燈火若爲情，一日簫笳有底聲。", "惆悵門前舊時路，白頭扶杖夜深行。"]'),
('9770c443-dc56-414a-af28-87f734a4f3ea','樂軒先師挽歌詞  其二','林希逸','宋','宋诗','song-poetry','','[]','網山遺稿樂軒文，已矣今無識子雲。',32,'全唐诗/poet.song.205000.json','["網山遺稿樂軒文，已矣今無識子雲。", "千載何人按圖問，犀斜南谷兩荒墳。"]'),
('6dc88b0d-2503-454e-80ca-cf270c27be52','樂軒先師挽歌詞  其三','林希逸','宋','宋诗','song-poetry','','[]','晦庵南北象山西，道學年來入品題。',32,'全唐诗/poet.song.205000.json','["晦庵南北象山西，道學年來入品題。", "可惜六經真脈絡，紅泉三世兩幽棲。"]'),
('e4431da3-9ec3-4f7b-bbcf-c7dcbd33934c','秋閨怨','林希逸','宋','宋诗','song-poetry','','[]','簾幕低垂夜漏深，秋蟲唧唧相悲吟。',32,'全唐诗/poet.song.205000.json','["簾幕低垂夜漏深，秋蟲唧唧相悲吟。", "回紋織罷空彈淚，未必君心似妾心。"]'),
('04ea9b37-4dd5-4e92-a73c-0ff380f8ebb2','午齋即事','林希逸','宋','宋诗','song-poetry','','[]','晴窗吾伊罷，風薄清晝永。',48,'全唐诗/poet.song.205000.json','["晴窗吾伊罷，風薄清晝永。", "陳編幾廢興，適笑心自領。", "青精飯何味，車笠沸塵境。", "佇立共幽懷，虛簷疏竹影。"]'),
('9ef71635-7861-4498-9526-67a45a0c7f55','用韻答友人論詩','林希逸','宋','宋诗','song-poetry','','[]','藝業難精最是詩，千差萬別信難知。',64,'全唐诗/poet.song.205000.json','["藝業難精最是詩，千差萬別信難知。", "還須倒嶽傾湫手，却有驚天動地時。", "鳥跡論書方古雅，龍媒入畫始權奇。", "夷然便欲趣平淡，此法誰傳我亦疑。"]'),
('0099df16-b4d7-4310-85af-8cb400469352','與陳同舍飲三元樓','林希逸','宋','宋诗','song-poetry','','[]','失身杯酒莫追尤，爛醉生涯儘自由。',64,'全唐诗/poet.song.205000.json','["失身杯酒莫追尤，爛醉生涯儘自由。", "可倚何須鸚鵡賦，相逢且解驌驦裘。", "今無客入揚雄巷，終有人題李白樓。", "却笑三閭太憔悴，獨醒猶作畔牢愁。"]'),
('36d0d951-d560-4a00-a1a5-3ec1f9f2f308','癸巳再入京宿璜溪寄二弟','林希逸','宋','宋诗','song-poetry','','[]','十日離家只四程，白雲何處玉融青。',32,'全唐诗/poet.song.205000.json','["十日離家只四程，白雲何處玉融青。", "溪聲颯颯如風雨，獨對寒燈詠鶺鴒。"]'),
('376a5c3c-c869-4521-814e-2355a8d3d4a4','黄源嶺半見梅作','林希逸','宋','宋诗','song-poetry','','[]','古嶺森森立萬松，一株寒玉笑春風。',32,'全唐诗/poet.song.205000.json','["古嶺森森立萬松，一株寒玉笑春風。", "恰如釣艇桐江客，畫入雲臺劍佩中。"]'),
('cf6f8d40-1d84-40e8-b027-74f05e93a9db','有懷','林希逸','宋','宋诗','song-poetry','','[]','金蓮學士起持衡，玉筍門生僅識名。',32,'全唐诗/poet.song.205000.json','["金蓮學士起持衡，玉筍門生僅識名。", "一瓣心香雙淚眼，半溪殘日暮雲橫。"]'),
('c827c64d-b3fb-47cd-83a2-2a1c1dd8a72e','七夕','林希逸','宋','宋诗','song-poetry','','[]','七香寶駕靈誰乞，雙眼金針俗不存。',32,'全唐诗/poet.song.205000.json','["七香寶駕靈誰乞，雙眼金針俗不存。", "世態如今機巧遍，堪將餘技獻天孫。"]'),
('7b57eddc-1508-4842-9258-1f747e1a49f2','千載','林希逸','宋','宋诗','song-poetry','','[]','千載祇如此，回頭迹便陳。',48,'全唐诗/poet.song.205000.json','["千載祇如此，回頭迹便陳。", "噓天遺故我，問月嘆今人。", "客授長生訣，僧談不壞身。", "未應癡準擬，且樂醉鄉春。"]'),
('e82dd663-bb55-4053-a096-222ffcea3c77','悼四先生','林希逸','宋','宋诗','song-poetry','','[]','真洪蔣魏繼淪終，天肯憂人國欲空。',64,'全唐诗/poet.song.205000.json','["真洪蔣魏繼淪終，天肯憂人國欲空。", "衆口生憎來論學，諸賢死不解和戎。", "良圖已付悲歌外，舊恨祇留奏稿中。", "擬續八哀才思短，剩將雙淚灑松風。"]'),
('b4a4969d-88c2-420d-b983-555dcc527619','讀黄詩','林希逸','宋','宋诗','song-poetry','','[]','我生所敬涪江翁，知翁不獨哦詩工。',176,'全唐诗/poet.song.205000.json','["我生所敬涪江翁，知翁不獨哦詩工。", "逍遥頗學漆園吏，下筆縱橫法略同。", "自言錦機織錦手，興寄每有離騷風。", "內篇外篇手分別，冥搜所到真奇絕。", "頡頏韓柳追莊騷，筆意尤工是晚節。", "兩蘇而下秦晁張，閉門覓句陳履常。", "當時姓名比明月，文莫如蘇詩則黄。", "黔南日月老賓送，白頭去作宜州夢。", "官樓家乘誰得之，那知珠玉無散遺。", "生前忍苦琢詩句，飄泊不憂無死處。", "今人更病語太奇，哀公不遇今猶故。"]'),
('08137e53-2784-4e04-af27-fcb554281bb1','打馬','林希逸','宋','宋诗','song-poetry','','[]','九折羊腸片紙間，機心覿面險於山。',64,'全唐诗/poet.song.205000.json','["九折羊腸片紙間，機心覿面險於山。", "是非喻馬一儒墨，得失爭蝸兩觸蠻。", "危似楚兵臨漢塹，急如齊客度秦關。", "良圖邂逅何分別，莫詫爭雄衣錦還。"]'),
('1b71e03f-494e-40c8-ae52-250f6443a196','晚遊遣興','林希逸','宋','宋诗','song-poetry','','[]','積雨多妨喜晚晴，幽禽足足傍簷鳴。',64,'全唐诗/poet.song.205000.json','["積雨多妨喜晚晴，幽禽足足傍簷鳴。", "迎風遠岸松聲近，背日陰池樹影明。", "親有餘年方頼祿，國無長算幸渝平。", "此生錯料吾猶可，只恐風塵未肯清。"]'),
('bcb3fb90-2f0b-4594-b4d5-33d37dbbfb64','心王','林希逸','宋','宋诗','song-poetry','','[]','易言不動工夫密，書說惟微體段彰。',64,'全唐诗/poet.song.205000.json','["易言不動工夫密，書說惟微體段彰。", "仙謾有方求氣母，禪非無見指心王。", "靈根本要行藏在，槁木寧於應感妨。", "一語何思千古訓，莫言爲陸背程張。"]'),
('42d47550-6062-4268-9566-2cd3d6285412','日用','林希逸','宋','宋诗','song-poetry','','[]','賴得人間念已灰，省身克己問參回。',64,'全唐诗/poet.song.205000.json','["賴得人間念已灰，省身克己問參回。", "事隨緣法安排去，病向根源點檢來。", "布襪青鞋資懶散，筆床茶竈恣徘徊。", "偷忙不住提撕着，猛可投機亦俊哉。"]'),
('da242ecd-80c4-46de-8f42-fef4ff51d2e3','答友人論學','林希逸','宋','宋诗','song-poetry','','[]','逐字箋來學轉難，逢人箇箇說曾顔。',64,'全唐诗/poet.song.205000.json','["逐字箋來學轉難，逢人箇箇說曾顔。", "那知剝落皮毛處，不在流傳口耳間。", "禪要自參求印可，仙須親煉待丹還。", "賣花擔上看桃李，此語吾今憶鶴山。"]'),
('a5424a3e-49dd-49c2-a46f-809946d75313','力學','林希逸','宋','宋诗','song-poetry','','[]','力學求心苦未安，蓬窗頼得小盤桓。',64,'全唐诗/poet.song.205000.json','["力學求心苦未安，蓬窗頼得小盤桓。", "醉知叉手矜持易，過似科頭點檢難。", "靜定工夫忙裏試，和平氣象怒中看。", "亨塗失脚人何限，始信顔回樂一簞。"]'),
('69ddea67-bd08-4ab0-b16f-4436cc72b3e0','玄扃','林希逸','宋','宋诗','song-poetry','','[]','君從何處叩玄扃，耳學紛紛莫浪聽。',64,'全唐诗/poet.song.205000.json','["君從何處叩玄扃，耳學紛紛莫浪聽。", "剗盡念頭方近道，掃空注脚始明經。", "見聞日富祇塵積，涉歷年深似酒醒。", "不必但疑禪背理，請君細讀信心銘。"]'),
('1c8d90cb-fff5-43ac-a3da-dab43165e76d','偶成','林希逸','宋','宋诗','song-poetry','','[]','佛言法界惟心造，仙說還丹要想成。',32,'全唐诗/poet.song.205000.json','["佛言法界惟心造，仙說還丹要想成。", "到得冰壺秋月處，輕輕拈出是功名。"]'),
('839499b9-79d6-4d9c-b53a-966267e28009','讀邸報懷王先生作','林希逸','宋','宋诗','song-poetry','','[]','當日籌邊事偶蹉，追尤未已意云何。',32,'全唐诗/poet.song.205000.json','["當日籌邊事偶蹉，追尤未已意云何。", "縱令君實謀時短，不道伊川好處多。"]'),
('1803b716-f06c-4242-a2ea-5f66302650ad','泊舟箬村有懷老師作','林希逸','宋','宋诗','song-poetry','','[]','昔去京華此艤舟，老師含笑別江頭。',32,'全唐诗/poet.song.205000.json','["昔去京華此艤舟，老師含笑別江頭。", "我今重向江頭立，宿草傷心二十秋。"]'),
('a59b25e9-0c74-481d-b1c2-dd49f930f8fc','寄林寒齋','林希逸','宋','宋诗','song-poetry','','[]','此是淵明向上人，少年早已謝簪紳。',64,'全唐诗/poet.song.205000.json','["此是淵明向上人，少年早已謝簪紳。", "談優雅號周禪客，意散宜稱謝道民。", "書疏苦無多字數，歲時但覺兩情親。", "寒窗欠我煨爐語，久辦青鞋擬乞身。"]'),
('7ef12518-46d9-459c-88ba-1c63c745154b','內宿','林希逸','宋','宋诗','song-poetry','','[]','玉宇凌空聳，金書照夜明。',48,'全唐诗/poet.song.205000.json','["玉宇凌空聳，金書照夜明。", "牆深容竹迸，石古伴梅橫。", "雲接天章路，風傳徼道聲。", "非才叨儤直，愧見壁間名。"]'),
('010a8632-03d0-43b9-b210-5935fd9593fa','又絕句','林希逸','宋','宋诗','song-poetry','','[]','堂虛陡覺暮寒生，長樂疏鍾緩轉更。',32,'全唐诗/poet.song.205000.json','["堂虛陡覺暮寒生，長樂疏鍾緩轉更。", "對燭已無詞可草，擁爐時聽閙皇城。"]'),
('49a8e005-ca7b-4b05-a8ed-b5391cedf77f','次早喜雪','林希逸','宋','宋诗','song-poetry','','[]','竹葉初聞似雨聲，禁林未曉已通明。',64,'全唐诗/poet.song.205000.json','["竹葉初聞似雨聲，禁林未曉已通明。", "朱樓屈曲欄先濕，紫殿參差瓦欲平。", "冰硯筆隨花片起，風簷幔點蕊珠輕。", "堂名不枉人間說，此際真如玉琢成。"]'),
('8621bcb5-92b5-48a4-9f0a-95d172e917d6','入局有懷','林希逸','宋','宋诗','song-poetry','','[]','空餐無補負公家，此志雖存鬢已華。',64,'全唐诗/poet.song.205000.json','["空餐無補負公家，此志雖存鬢已華。", "每向客懷紅躑躅，不貪郎對紫薇花。", "寬心可要流香酒，圓夢何須正焙茶。", "手板便還丞相去，吾儕活計只桑麻。"]'),
('ea11d8b8-9e03-40f2-b5a8-555e0429bc6c','有感','林希逸','宋','宋诗','song-poetry','','[]','少日因貧强覓官，于今悔擲釣魚竿。',64,'全唐诗/poet.song.205000.json','["少日因貧强覓官，于今悔擲釣魚竿。", "宮袍豈似陀尼暖，廐馬何如款段安。", "準易莫教玄尚白，奏篇還要炳於丹。", "得歸須謁嚴陵去，夢已先經七里灘。"]'),
('dbb32403-52a3-4f20-bdeb-a2d80eea6ae0','得郡後二首  其一','林希逸','宋','宋诗','song-poetry','','[]','君王分付爲親還，班路諠傳忤要官。',32,'全唐诗/poet.song.205000.json','["君王分付爲親還，班路諠傳忤要官。", "我但得歸他不問，從來人道乞身難。"]'),
('3f75fd33-dbb0-432d-99bb-67bfdfde47a7','得郡後二首  其二','林希逸','宋','宋诗','song-poetry','','[]','語戇情知忤要人，此心謀國不謀身。',32,'全唐诗/poet.song.205000.json','["語戇情知忤要人，此心謀國不謀身。", "一麾得請天南去，出處應堪白老親。"]');
